#!/usr/bin/env node

const fs = require('fs');

// Read the file
const filePath = 'service-page.tsx';
let content = fs.readFileSync(filePath, 'utf8');

// 1. Fix tooltips - remove addon description from hover tooltip (both instances)
content = content.replace(/\{addon\.tooltipDescription\}\s+<\/div>\s+\{addon\.addonDescription && \(\s+<div className="pt-1 border-t border-gold-dark\/30">\s+\{addon\.addonDescription\}\s+<\/div>\s+\)\}/g, 
  '{addon.tooltipDescription}\n                                            </div>');

// 2. Replace "Features not specified" with service description
content = content.replace(/\{!\tier\.features \|\| tier\.features\.length === 0\) && \(\s+<li className="text-offwhite\/50 italic">Features not specified<\/li>\s+\)\}/g,
  '{(!tier.features || tier.features.length === 0) && (\n                            <li className="text-offwhite/90">{service.description}</li>\n                          )}');

// Write the changes back to the file
fs.writeFileSync(filePath, content);
console.log('Changes applied successfully');

