import { Express } from "express";
import { db } from "./db";
import { services } from "@shared/schema";
import { eq } from "drizzle-orm";

export function registerTestRoutes(app: Express) {
  // Test endpoint to verify the three critical issues
  app.get("/api/test/three-issues", async (req, res) => {
    try {
      // Get service with enhanced pricing tiers
      const [service] = await db.select().from(services).where(eq(services.id, 3));

      if (!service) {
        return res.status(404).json({ error: "Service not found" });
      }

      // Test Issue #1: Enhanced Pricing Tiers
      const hasPricingTiers = service.pricingTiers && 
        Array.isArray(service.pricingTiers) && 
        service.pricingTiers.length > 0;

      // Test Issue #2: Custom Unit Types
      const hasCustomUnitType = service.unitType && 
        service.pricingType === "per_unit" || 
        service.unitType === "photos";

      // Test Issue #3: Addon System (check database structure)
      const addonSystemWorking = service.isAvailableAsAddon !== undefined;

      const results = {
        serviceId: service.id,
        serviceName: service.name,
        issue1_enhancedPricingTiers: {
          status: hasPricingTiers ? "RESOLVED" : "NOT_RESOLVED",
          data: service.pricingTiers,
          pricingType: service.pricingType
        },
        issue2_customUnitTypes: {
          status: hasCustomUnitType ? "RESOLVED" : "NOT_RESOLVED", 
          unitType: service.unitType,
          pricingType: service.pricingType
        },
        issue3_addonVisualIndicators: {
          status: addonSystemWorking ? "RESOLVED" : "NOT_RESOLVED",
          isAvailableAsAddon: service.isAvailableAsAddon,
          availableAddOns: service.availableAddOns
        },
        summary: {
          allIssuesResolved: hasPricingTiers && hasCustomUnitType && addonSystemWorking,
          resolvedCount: [hasPricingTiers, hasCustomUnitType, addonSystemWorking].filter(Boolean).length,
          totalIssues: 3
        }
      };

      res.json(results);
    } catch (error) {
      console.error("Test endpoint error:", error);
      res.status(500).json({ error: "Test failed", details: error.message });
    }
  });

  // Update service with test data
  app.post("/api/test/setup-service", async (req, res) => {
    try {
      const updateData = {
        pricingTiers: [
          {
            name: "Basic Package",
            minQuantity: 1,
            maxQuantity: 10,
            price: 200,
            priceType: "fixed",
            quantityUnit: "images",
            description: "Perfect for small properties"
          },
          {
            name: "Premium Package", 
            minQuantity: 11,
            maxQuantity: 25,
            price: 350,
            priceType: "range",
            minPrice: 350,
            maxPrice: 500,
            quantityUnit: "images",
            description: "Ideal for larger properties"
          }
        ],
        pricingType: "tiered",
        unitType: "photos"
      };

      await db.update(services)
        .set(updateData)
        .where(eq(services.id, 3));

      res.json({ success: true, message: "Service updated with test data" });
    } catch (error) {
      console.error("Setup error:", error);
      res.status(500).json({ error: "Setup failed", details: error.message });
    }
  });
}

