import { Link } from "wouter";
import { Button } from "@/components/ui/button";
import { ChevronDown, Play, ChevronLeft, ChevronRight } from "lucide-react";
import { motion } from "framer-motion";
import { useState, useRef, useEffect, useCallback } from "react";
import useEmblaCarousel from 'embla-carousel-react';
import { EmblaOptionsType } from 'embla-carousel';

// Sample hero options
const HERO_OPTIONS = [
  {
    id: "image-1",
    type: "image",
    title: "Drone over Mountains", 
    url: "https://images.unsplash.com/photo-1508444845599-5c89863b1c44?ixlib=rb-1.2.1&auto=format&fit=crop&w=1920&q=80"
  },
  {
    id: "image-2",
    type: "image",
    title: "Sunset Drone Shot",
    url: "https://images.unsplash.com/photo-1564347288827-3e4293543e07?ixlib=rb-1.2.1&auto=format&fit=crop&w=1920&q=80"
  },
  {
    id: "image-3",
    type: "image",
    title: "Coastal Aerial View",
    url: "https://images.unsplash.com/photo-1568124936547-62c9180d7993?ixlib=rb-1.2.1&auto=format&fit=crop&w=1920&q=80"
  },
  {
    id: "video-1",
    type: "video",
    title: "Aerial Ocean View",
    url: "https://storage.googleapis.com/gtv-videos-bucket/sample/ForBiggerBlazes.mp4"
  },
  {
    id: "video-2",
    type: "video", 
    title: "Nature Footage",
    url: "https://storage.googleapis.com/gtv-videos-bucket/sample/TearsOfSteel.mp4"
  }
];

// Get all available hero options (stock + custom)
function getAllHeroOptions() {
  const saved = localStorage.getItem('customHeroOptions');
  const custom = saved ? JSON.parse(saved) : [];
  return [...HERO_OPTIONS, ...custom];
}

// Configure Embla carousel options
const OPTIONS: EmblaOptionsType = { 
  loop: true 
};

export function HeroSection() {
  const [allHeroOptions, setAllHeroOptions] = useState<any[]>(HERO_OPTIONS);
  const [selectedHeroItems, setSelectedHeroItems] = useState<string[]>([]);
  const [emblaRef, emblaApi] = useEmblaCarousel(OPTIONS);
  const videoRefs = useRef<{ [key: string]: HTMLVideoElement | null }>({});
  const [selectedSlide, setSelectedSlide] = useState(0);

  // Controls visibility state
  const [showControls, setShowControls] = useState(false);

  // Load all hero options (stock + custom) and selected items
  useEffect(() => {
    const allOptions = getAllHeroOptions();
    setAllHeroOptions(allOptions);

    const savedHeroItems = localStorage.getItem('selectedHeroItems');
    if (savedHeroItems) {
      try {
        const parsedItems = JSON.parse(savedHeroItems);
        if (Array.isArray(parsedItems) && parsedItems.length > 0) {
          setSelectedHeroItems(parsedItems);
          return;
        }
      } catch (error) {
        console.error('Error parsing saved hero items:', error);
      }
    }

    // Default to first 3 items if nothing saved
    setSelectedHeroItems(['image-1', 'image-2', 'video-1']);
  }, []);

  // Get the current media type based on the current slide
  const getCurrentMediaType = useCallback(() => {
    if (!emblaApi || selectedHeroItems.length === 0) return 'image';

    const currentIndex = emblaApi.selectedScrollSnap();
    if (currentIndex >= selectedHeroItems.length) return 'image';

    const currentItemId = selectedHeroItems[currentIndex];
    const currentItem = allHeroOptions.find(option => option.id === currentItemId);

    return currentItem?.type || 'image';
  }, [emblaApi, selectedHeroItems]);

  // Handle slide change - manage video playback
  useEffect(() => {
    if (!emblaApi) return;

    // When slide changes, handle video playback and update selected slide
    const onSelect = () => {
      const currentSlide = emblaApi.selectedScrollSnap();
      setSelectedSlide(currentSlide);

      // Play video on current slide and pause others
      selectedHeroItems.forEach((itemId, index) => {
        const item = allHeroOptions.find(option => option.id === itemId);
        if (item?.type === 'video' && videoRefs.current[itemId]) {
          const video = videoRefs.current[itemId];
          if (index === currentSlide) {
            video?.play().catch(err => {
              console.warn('Video play failed:', err);
            });
          } else {
            video?.pause();
          }
        }
      });
    };

    emblaApi.on('select', onSelect);
    // Initial call to set up videos
    onSelect();

    return () => {
      emblaApi.off('select', onSelect);
    };
  }, [emblaApi, selectedHeroItems, getCurrentMediaType]);

  // Update embedApi when selected items change
  useEffect(() => {
    if (emblaApi && selectedHeroItems.length > 0) {
      emblaApi.reInit();

      // Play the first video if needed
      const firstItem = allHeroOptions.find(option => option.id === selectedHeroItems[0]);
      if (firstItem?.type === 'video' && videoRefs.current[firstItem.id]) {
        const video = videoRefs.current[firstItem.id];
        video?.play().catch(err => {
          console.warn('Initial video play failed:', err);
        });
      }
    }
  }, [emblaApi, selectedHeroItems]);



  // Handle navigation buttons
  const scrollPrev = useCallback(() => {
    if (emblaApi) emblaApi.scrollPrev();
  }, [emblaApi]);

  const scrollNext = useCallback(() => {
    if (emblaApi) emblaApi.scrollNext();
  }, [emblaApi]);

  return (
    <section 
      className="relative h-screen overflow-hidden hidden sm:block"
      onMouseEnter={() => setShowControls(true)}
      onMouseLeave={() => setShowControls(false)}
    >
      {/* Carousel */}
      <div className="h-full" ref={emblaRef}>
        <div className="flex h-full">
          {selectedHeroItems.map((itemId) => {
            const mediaItem = allHeroOptions.find(option => option.id === itemId);
            if (!mediaItem) return null;

            return (
              <div 
                key={mediaItem.id} 
                className="flex-none w-full h-full relative"
              >
                {mediaItem.type === 'image' ? (
                  <img
                    src={mediaItem.url}
                    alt=""
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <video
                    ref={(el) => { videoRefs.current[mediaItem.id] = el; }}
                    src={mediaItem.url}
                    className="w-full h-full object-cover"
                    muted
                    loop
                    playsInline
                  />
                )}
                {/* Gradient overlay */}
                <div className="absolute inset-0 bg-gradient-to-t from-black-dark to-transparent opacity-80"></div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Carousel navigation buttons */}
      <div className="absolute inset-x-0 top-1/2 flex justify-between px-4 sm:px-6 lg:px-8 transition-all duration-300">
        <button
          onClick={scrollPrev}
          className="carousel-nav-button bg-transparent border-2 border-gold hover:bg-black/20 hover:border-gold-light transition-all shadow-lg"
        >
          <ChevronLeft size={24} className="text-gold" />
        </button>
        <button
          onClick={scrollNext}
          className="carousel-nav-button bg-transparent border-2 border-gold hover:bg-black/20 hover:border-gold-light transition-all shadow-lg"
        >
          <ChevronRight size={24} className="text-gold" />
        </button>
      </div>

      {/* Carousel indicators/dots */}
      <div className="absolute bottom-6 inset-x-0 flex justify-center gap-3">
        {selectedHeroItems.map((itemId, index) => {
          const mediaItem = allHeroOptions.find(option => option.id === itemId);
          if (!mediaItem) return null;

          const isActive = selectedSlide === index;

          return (
            <button
              key={index}
              onClick={() => {
                if (emblaApi) emblaApi.scrollTo(index);
              }}
              className={`carousel-page-marker border-2 border-gold transition-all ${
                isActive
                  ? "bg-gold-gradient shadow-lg shadow-gold/50"
                  : "bg-transparent hover:bg-gold/20"
              }`}
              aria-label={`Go to slide ${index + 1}`}
            />
          );
        })}
      </div>


    </section>
  );
}

export default HeroSection;

