interface ImageViewerProps {
  fileUrl: string;
}

export default function ImageViewer({ fileUrl }: ImageViewerProps) {
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [zoom, setZoom] = useState(1);
  const [rotation, setRotation] = useState(0);
  const [brightness, setBrightness] = useState(100);
  const [contrast, setContrast] = useState(100);

  // Reference to the container for fullscreen
  const containerRef = useRef<HTMLDivElement>(null);

  // Simulate image loading
  useEffect(() => {
    const img = new Image();
    img.src = fileUrl;

    img.onload = () => {
      setIsLoading(false);
    };

    img.onerror = () => {
      setError("Failed to load image");
      setIsLoading(false);
    };

    return () => {
      img.onload = null;
      img.onerror = null;
    };
  }, [fileUrl]);

  const zoomIn = () => {
    setZoom(prev => Math.min(prev + 0.1, 3));
  };

  const zoomOut = () => {
    setZoom(prev => Math.max(prev - 0.1, 0.5));
  };

  const rotate = () => {
    setRotation(prev => (prev + 90) % 360);
  };

  const toggleFullscreen = () => {
    if (!containerRef.current) return;

    if (document.fullscreenElement) {
      document.exitFullscreen().catch(err => {
        console.error("Error exiting fullscreen:", err);
      });
    } else {
      containerRef.current.requestFullscreen().catch(err => {
        console.error("Error entering fullscreen:", err);
      });
    }
  };

  if (error) {
    return (
      <Alert variant="destructive" className="mt-4">
        <AlertDescription>{error}</AlertDescription>
      </Alert>
    );
  }

  return (
    <div className="flex flex-col" ref={containerRef}>
      <div className="flex justify-between items-center mb-4">
        <div className="text-sm text-offwhite/70">
          Image Viewer
        </div>

        <div className="flex space-x-1">
          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button 
                  variant="outline"
                  size="sm"
                  onClick={zoomIn}
                  className="bg-[#0b111f] hover:bg-[#132642] border-gold-dark/30 text-offwhite"
                >
                  <ZoomIn className="h-4 w-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent className="bg-[#132642] border-gold-dark/30">
                <p>Zoom In</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>

          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button 
                  variant="outline"
                  size="sm"
                  onClick={zoomOut}
                  className="bg-[#0b111f] hover:bg-[#132642] border-gold-dark/30 text-offwhite"
                >
                  <ZoomOut className="h-4 w-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent className="bg-[#132642] border-gold-dark/30">
                <p>Zoom Out</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>

          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button 
                  variant="outline"
                  size="sm"
                  onClick={rotate}
                  className="bg-[#0b111f] hover:bg-[#132642] border-gold-dark/30 text-offwhite"
                >
                  <RotateCw className="h-4 w-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent className="bg-[#132642] border-gold-dark/30">
                <p>Rotate 90°</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>

          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button 
                  variant="outline"
                  size="sm"
                  onClick={toggleFullscreen}
                  className="bg-[#0b111f] hover:bg-[#132642] border-gold-dark/30 text-offwhite"
                >
                  <Maximize className="h-4 w-4" />
                </Button>
              </TooltipTrigger>
              <TooltipContent className="bg-[#132642] border-gold-dark/30">
                <p>Fullscreen</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>

          <TooltipProvider>
            <Tooltip>
              <TooltipTrigger asChild>
                <Button 
                  variant="outline"
                  size="sm"
                  className="bg-[#0b111f] hover:bg-[#132642] border-gold-dark/30 text-offwhite"
                  asChild
                >
                  <a href={fileUrl} download target="_blank" rel="noopener noreferrer">
                    <Download className="h-4 w-4" />
                  </a>
                </Button>
              </TooltipTrigger>
              <TooltipContent className="bg-[#132642] border-gold-dark/30">
                <p>Download Original</p>
              </TooltipContent>
            </Tooltip>
          </TooltipProvider>
        </div>
      </div>

      <div className="rounded-md bg-[#080d17] overflow-hidden">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center h-[400px]">
            <div className="animate-spin w-8 h-8 border-4 border-gold border-t-transparent rounded-full" />
            <p className="mt-4 text-offwhite/70">Loading image...</p>
          </div>
        ) : (
          <div className="relative w-full h-[400px] flex items-center justify-center overflow-hidden">
            <img 
              src={fileUrl} 
              alt="Viewer"
              className="max-w-full max-h-full object-contain"
              style={{
                transform: `scale(${zoom}) rotate(${rotation}deg)`,
                transformOrigin: 'center center',
                filter: `brightness(${brightness}%) contrast(${contrast}%)`,
                transition: 'transform 0.2s ease-out'
              }}
            />
          </div>
        )}
      </div>

      <div className="mt-4 bg-[#080d17] rounded-md p-3 space-y-3">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <div className="space-y-2">
            <div className="flex justify-between">
              <Label htmlFor="brightness" className="text-xs text-offwhite/70">Brightness</Label>
              <span className="text-xs text-offwhite/70">{brightness}%</span>
            </div>
            <Slider 
              id="brightness"
              min={50} 
              max={150} 
              step={1} 
              value={[brightness]} 
              onValueChange={(value) => setBrightness(value[0])} 
              className="my-1.5"
            />
          </div>

          <div className="space-y-2">
            <div className="flex justify-between">
              <Label htmlFor="contrast" className="text-xs text-offwhite/70">Contrast</Label>
              <span className="text-xs text-offwhite/70">{contrast}%</span>
            </div>
            <Slider 
              id="contrast"
              min={50} 
              max={150} 
              step={1} 
              value={[contrast]} 
              onValueChange={(value) => setContrast(value[0])} 
              className="my-1.5"
            />
          </div>
        </div>
      </div>
    </div>
  );
}

client/src/components/ui/gallery-item.ts.content:
import { useState } from 'react';
import { 
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { 
  Play, 
  Download, 
  Maximize2, 
  X,
  ChevronLeft,
  ChevronRight
} from "lucide-react";

import { MediaItem } from "@/types/media";

type GalleryItemProps = {
  item: MediaItem;
  downloadable?: boolean;
  onDownload?: (src: string) => void;
  galleryItems?: MediaItem[];
  currentIndex?: number;
};

export function GalleryItem({ 
  item, 
  downloadable = false, 
  onDownload,
  galleryItems = [],
  currentIndex = 0
}: GalleryItemProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [currentItemIndex, setCurrentItemIndex] = useState(currentIndex);
  const currentItem = galleryItems.length > 0 ? galleryItems[currentItemIndex] : item;

  const handleNext = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (galleryItems.length > 0) {
      setCurrentItemIndex((prevIndex) => 
        prevIndex === galleryItems.length - 1 ? 0 : prevIndex + 1
      );
    }
  };

  const handlePrevious = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (galleryItems.length > 0) {
      setCurrentItemIndex((prevIndex) => 
        prevIndex === 0 ? galleryItems.length - 1 : prevIndex - 1
      );
    }
  };

  const handleDownload = () => {
    if (onDownload) {
      onDownload(currentItem.src);
    } else {
      // Default download behavior
      const actualUrl = getActualUrl(currentItem.src);
      const link = document.createElement('a');
      link.href = actualUrl;

      // Generate a filename based on the title or use a default
      let filename = 'apollo-droneworks-';

      // Add the title to the filename if available
      if (currentItem.title) {
        // Clean up the title to make it suitable for a filename
        filename += currentItem.title.toLowerCase().replace(/[^a-z0-9]/g, '-');
      } else {
        filename += 'image';
      }

      // Add appropriate extension if it's a base64 data URL
      if (actualUrl.startsWith('data:image/')) {
        const imageType = actualUrl.split(';')[0].split('/')[1];
        filename += `.${imageType === 'jpeg' ? 'jpg' : imageType}`;
      } else if (actualUrl.startsWith('data:video/')) {
        const videoType = actualUrl.split(';')[0].split('/')[1];
        filename += `.${videoType}`;
      } else if (currentItem.src.startsWith('local-file://')) {
        // For backward compatibility with old URL format
        const parts = currentItem.src.split('/');
        const oldFilename = parts[parts.length - 1].split('#')[0] || 'download';
        filename = oldFilename;
      } else {
        // For regular URLs, try to extract the filename
        const urlFilename = actualUrl.split('/').pop();
        if (urlFilename) {
          filename = urlFilename;
        } else {
          filename += '.png'; // Default extension
        }
      }

      link.download = filename;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  };

  // Helper to parse URLs and ensure they work correctly
  const getActualUrl = (url: string | undefined): string => {
    // Check for null/undefined URLs and return a placeholder if necessary
    if (!url) {
      console.log('Empty URL encountered in gallery-item');
      return '';
    }

    // Debug the URL being processed (truncated to avoid console spam)
    console.log('Processing URL:', url.substring(0, 30) + '...');

    // For base64 images, no processing needed as they're already valid
    if (url.startsWith('data:image/') || url.startsWith('data:video/')) {
      console.log('Gallery item is using base64 data');
      return url;
    }

    // If it's our old special format (mockUrl#objectUrl), handle it for backward compatibility
    if (url.includes('#')) {
      const parts = url.split('#');
      const result = parts.length > 1 ? parts[1] : url;
      console.log('Processed URL result (old format):', result.substring(0, 30) + '...');
      return result;
    }

    // No special processing needed
    return url;
  };

  const renderPreview = () => {
    // Get the display URL, prioritizing thumbnail if available
    let displayUrl = item.thumbnail ? getActualUrl(item.thumbnail) : getActualUrl(item.src);

    if (item.type === 'video') {
      return (
        <div className="relative group w-full h-full">
          <img 
            src={displayUrl} 
            alt={item.alt || 'Video thumbnail'} 
            className="w-full h-full object-cover rounded-md"
          />
          <div className="absolute inset-0 flex items-center justify-center bg-black/30 opacity-0 group-hover:opacity-100 transition-opacity">
            <div className="rounded-full bg-black/60 p-3">
              <Play className="h-8 w-8 text-white" />
            </div>
          </div>
        </div>
      );
    }

    return (
      <img 
        src={displayUrl} 
        alt={item.alt || 'Gallery image'} 
        className="w-full h-full object-cover rounded-md"
      />
    );
  };

  return (
    <Dialog open={isOpen} onOpenChange={setIsOpen}>
      <DialogTrigger asChild>
        <div className="relative group bg-[#080d17] rounded-md overflow-hidden aspect-video cursor-pointer hover:shadow-md transition-shadow">
          {renderPreview()}
          <div className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity">
            <Button 
              variant="ghost" 
              size="icon" 
              className="h-10 w-10 rounded-full bg-black/60 text-white hover:bg-black/80 hover:text-white"
              onClick={() => setIsOpen(true)}
            >
              <Maximize2 className="h-5 w-5" />
            </Button>
          </div>

          {item.title && (
            <div className="absolute bottom-0 left-0 right-0 bg-black/70 p-2 group-hover:opacity-100 opacity-80">
              <p className="text-white text-sm font-medium truncate">{item.title}</p>
              {item.type === 'video' && (
                <Badge variant="outline" className="bg-red-600/80 text-white border-none text-xs">
                  VIDEO
                </Badge>
              )}
            </div>
          )}
        </div>
      </DialogTrigger>

      <DialogContent className="sm:max-w-3xl md:max-w-4xl lg:max-w-5xl p-0 overflow-hidden bg-[#080d17] border-gold-dark/30">
        <div className="relative h-full">
          <Button 
            variant="ghost" 
            size="icon" 
            className="absolute top-2 right-2 z-50 h-8 w-8 rounded-full bg-black/60 text-white hover:bg-black/80"
            onClick={() => setIsOpen(false)}
          >
            <X className="h-4 w-4" />
          </Button>

          {galleryItems.length > 1 && (
            <>
              <Button 
                variant="ghost" 
                size="icon" 
                className="absolute left-2 top-1/2 -translate-y-1/2 z-50 h-10 w-10 rounded-full bg-black/60 text-white hover:bg-black/80"
                onClick={handlePrevious}
              >
                <ChevronLeft className="h-6 w-6" />
              </Button>

              <Button 
                variant="ghost" 
                size="icon" 
                className="absolute right-2 top-1/2 -translate-y-1/2 z-50 h-10 w-10 rounded-full bg-black/60 text-white hover:bg-black/80"
                onClick={handleNext}
              >
                <ChevronRight className="h-6 w-6" />
              </Button>
            </>
          )}

          <div className="max-h-[80vh] flex items-center justify-center bg-[#080d17] overflow-hidden">
            {currentItem.type === 'video' ? (
              <video 
                src={getActualUrl(currentItem.src)}
                controls
                className="max-h-[80vh] max-w-full"
                autoPlay
              />
            ) : (
              <img 
                src={getActualUrl(currentItem.src)} 
                alt={currentItem.alt || 'Gallery image'} 
                className="max-h-[80vh] max-w-full object-contain" 
              />
            )}
          </div>

          <div className="bg-[#0b111f] p-4">
            <div className="flex justify-between items-start">
              <div>
                {currentItem.title && (
                  <DialogTitle className="text-lg font-bold text-offwhite mb-1">
                    {currentItem.title}
                  </DialogTitle>
                )}
                {currentItem.publicDescription && (
                  <DialogDescription className="text-offwhite/70 text-sm">
                    {currentItem.publicDescription}
                  </DialogDescription>
                )}
              </div>

              {downloadable && (
                <Button 
                  onClick={handleDownload} 
                  variant="default" 
                  className="bg-gold text-black hover:bg-gold-light"
                >
                  <Download className="h-4 w-4 mr-2" />
                  Download
                </Button>
              )}
            </div>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/finance/payroll/pa.content:
import { useState } from "react";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  CardFooter,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { format } from "date-fns";
import { useToast } from "@/hooks/use-toast";
import { Search, Filter, ChevronDown, ChevronsUpDown, AlertCircle, Download, Printer } from "lucide-react";
import { PayrollEntry, PayrollPeriod, Employee } from "@shared/schema";
import { cn } from "@/lib/utils";
import { apiRequest } from "@/lib/queryClient";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { 
  Sheet, 
  SheetContent, 
  SheetDescription, 
  SheetHeader, 
  SheetTitle 
} from "@/components/ui/sheet";

export default function PayrollEntries() {
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedPeriodId, setSelectedPeriodId] = useState<number | null>(null);
  const [viewEntrySheet, setViewEntrySheet] = useState(false);
  const [selectedEntryId, setSelectedEntryId] = useState<number | null>(null);

  const { toast } = useToast();
  const queryClient = useQueryClient();

  // Fetch payroll periods
  const { data: periods } = useQuery<PayrollPeriod[]>({
    queryKey: ["/api/payroll/periods"],
  });

  // Fetch payroll entries for the selected period
  const { data: payrollEntries, isLoading } = useQuery<PayrollEntry[]>({
    queryKey: ["/api/payroll/entries", selectedPeriodId],
    enabled: !!selectedPeriodId,
  });

  // Fetch all employees
  const { data: employees } = useQuery<Employee[]>({
    queryKey: ["/api/payroll/employees"],
  });

  // Fetch single payroll entry when viewing details
  const { data: selectedEntry } = useQuery<PayrollEntry>({
    queryKey: ["/api/payroll/entries", selectedEntryId],
    enabled: !!selectedEntryId,
  });

  // Generate payroll mutation
  const generatePayrollMutation = useMutation({
    mutationFn: async (periodId: number) => {
      await apiRequest("POST", `/api/payroll/periods/${periodId}/generate`);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/payroll/entries"] });
      toast({
        title: "Success",
        description: "Payroll generated successfully",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: "Failed to generate payroll: " + error.message,
        variant: "destructive",
      });
    },
  });

  // Process payroll (mark as completed) mutation
  const processPayrollMutation = useMutation({
    mutationFn: async (periodId: number) => {
      await apiRequest("PATCH", `/api/payroll/periods/${periodId}`, {
        status: "completed",
      });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/payroll/periods"] });
      toast({
        title: "Success",
        description: "Payroll processed successfully",
      });
    },
    onError: (error) => {
      toast({
        title: "Error",
        description: "Failed to process payroll: " + error.message,
        variant: "destructive",
      });
    },
  });

  const selectedPeriod = periods?.find(p => p.id === selectedPeriodId);

  const getEmployeeName = (employeeId: number) => {
    const employee = employees?.find(e => e.id === employeeId);
    return employee ? `${employee.firstName} ${employee.lastName}` : "Unknown Employee";
  };

  const filteredEntries = payrollEntries?.filter((entry) => {
    const searchLower = searchTerm.toLowerCase();
    const employeeName = getEmployeeName(entry.employeeId).toLowerCase();

    return employeeName.includes(searchLower);
  });

  const handleViewEntry = (entryId: number) => {
    setSelectedEntryId(entryId);
    setViewEntrySheet(true);
  };

  const totalGrossPay = filteredEntries?.reduce((sum, entry) => sum + Number(entry.grossPay), 0) || 0;
  const totalTaxes = filteredEntries?.reduce((sum, entry) => sum + Number(entry.taxAmount), 0) || 0;
  const totalNetPay = filteredEntries?.reduce((sum, entry) => sum + Number(entry.netPay), 0) || 0;

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row justify-between gap-4">
        <div className="w-full sm:w-72">
          <Select
            value={selectedPeriodId?.toString() || ""}
            onValueChange={(value) => setSelectedPeriodId(value ? parseInt(value) : null)}
          >
            <SelectTrigger>
              <SelectValue placeholder="Select a payroll period" />
            </SelectTrigger>
            <SelectContent>
              {periods?.map((period) => (
                <SelectItem key={period.id} value={period.id.toString()}>
                  {format(new Date(period.periodStart), "MMM d")} - {format(new Date(period.periodEnd), "MMM d, yyyy")}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>

        {selectedPeriodId && (
          <div className="flex gap-2">
            <Button variant="outline" className="shrink-0">
              <Filter className="h-4 w-4 mr-2" />
              Filter
            </Button>

            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button>
                  Actions
                  <ChevronDown className="ml-2 h-4 w-4" />
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end">
                <DropdownMenuItem
                  onClick={() => generatePayrollMutation.mutate(selectedPeriodId)}
                  disabled={generatePayrollMutation.isPending}
                >
                  Generate Payroll
                </DropdownMenuItem>
                <DropdownMenuItem
                  onClick={() => processPayrollMutation.mutate(selectedPeriodId)}
                  disabled={processPayrollMutation.isPending || selectedPeriod?.status === "completed"}
                >
                  Process Payroll
                </DropdownMenuItem>
                <DropdownMenuItem>
                  Export Pay Stubs
                </DropdownMenuItem>
                <DropdownMenuItem>
                  Print Payroll Report
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>
          </div>
        )}
      </div>

      {selectedPeriodId ? (
        <>
          <Card>
            <CardHeader className="pb-3">
              <div className="flex justify-between items-center">
                <div>
                  <CardTitle>Payroll Details</CardTitle>
                  <CardDescription>
                    {selectedPeriod ? (
                      <>
                        Period: {format(new Date(selectedPeriod.periodStart), "MMM d")} - {format(new Date(selectedPeriod.periodEnd), "MMM d, yyyy")}
                        {" | "}
                        Payment Date: {format(new Date(selectedPeriod.paymentDate), "MMM d, yyyy")}
                        {" | "}
                        Status: <Badge variant={selectedPeriod.status === "completed" ? "default" : "outline"}>{selectedPeriod.status}</Badge>
                      </>
                    ) : (
                      "Loading period details..."
                    )}
                  </CardDescription>
                </div>
              </div>
            </CardHeader>

            <CardContent>
              {isLoading ? (
                <div className="flex justify-center py-8">
                  <div className="animate-spin h-8 w-8 border-4 border-primary border-t-transparent rounded-full"></div>
                </div>
              ) : filteredEntries && filteredEntries.length > 0 ? (
                <>
                  <div className="relative w-full sm:w-72 mb-4">
                    <Search className="absolute left-2 top-2.5 h-4 w-4 text-muted-foreground" />
                    <Input
                      placeholder="Search employees..."
                      className="pl-8"
                      value={searchTerm}
                      onChange={(e) => setSearchTerm(e.target.value)}
                    />
                  </div>

                  <div className="rounded-md border">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Employee</TableHead>
                          <TableHead>Regular Hours</TableHead>
                          <TableHead>Overtime Hours</TableHead>
                          <TableHead>Gross Pay</TableHead>
                          <TableHead>Taxes</TableHead>
                          <TableHead>Net Pay</TableHead>
                          <TableHead className="text-right">Actions</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {filteredEntries.map((entry) => (
                          <TableRow key={entry.id}>
                            <TableCell>{getEmployeeName(entry.employeeId)}</TableCell>
                            <TableCell>{Number(entry.regularHours).toFixed(2)}</TableCell>
                            <TableCell>{Number(entry.overtimeHours).toFixed(2)}</TableCell>
                            <TableCell>${Number(entry.grossPay).toFixed(2)}</TableCell>
                            <TableCell>${Number(entry.taxAmount).toFixed(2)}</TableCell>
                            <TableCell className="font-medium">${Number(entry.netPay).toFixed(2)}</TableCell>
                            <TableCell className="text-right">
                              <Button
                                variant="ghost"
                                size="sm"
                                onClick={() => handleViewEntry(entry.id)}
                              >
                                View Details
                              </Button>
                            </TableCell>
                          </TableRow>
                        ))}
                      </TableBody>
                    </Table>
                  </div>
                </>
              ) : (
                <div className="border rounded-md p-8 flex flex-col items-center justify-center gap-2 text-center">
                  <AlertCircle className="h-8 w-8 text-muted-foreground" />
                  <h3 className="text-lg font-medium">No payroll entries found</h3>
                  <p className="text-sm text-muted-foreground">
                    {searchTerm
                      ? "No employees match your search criteria"
                      : "This payroll period doesn't have any entries yet. Generate the payroll to create entries."}
                  </p>
                  {!searchTerm && (
                    <Button 
                      className="mt-2"
                      onClick={() => generatePayrollMutation.mutate(selectedPeriodId)}
                      disabled={generatePayrollMutation.isPending}
                    >
                      {generatePayrollMutation.isPending ? (
                        <>
                          <div className="mr-2 h-4 w-4 animate-spin rounded-full border-2 border-background border-t-transparent"></div>
                          Generating...
                        </>
                      ) : (
                        "Generate Payroll"
                      )}
                    </Button>
                  )}
                </div>
              )}
            </CardContent>

            {filteredEntries && filteredEntries.length > 0 && (
              <CardFooter className="border-t">
                <div className="w-full">
                  <Collapsible className="w-full">
                    <CollapsibleTrigger asChild>
                      <div className="flex justify-between items-center w-full cursor-pointer py-2">
                        <span className="text-sm font-medium">Payroll Summary</span>
                        <ChevronsUpDown className="h-4 w-4" />
                      </div>
                    </CollapsibleTrigger>
                    <CollapsibleContent>
                      <div className="space-y-2 pt-2">
                        <div className="grid grid-cols-2 text-sm">
                          <span className="text-muted-foreground">Total Employees:</span>
                          <span className="font-medium">{filteredEntries.length}</span>
                        </div>
                        <div className="grid grid-cols-2 text-sm">
                          <span className="text-muted-foreground">Total Gross Pay:</span>
                          <span className="font-medium">${totalGrossPay.toFixed(2)}</span>
                        </div>
                        <div className="grid grid-cols-2 text-sm">
                          <span className="text-muted-foreground">Total Taxes:</span>
                          <span className="font-medium">${totalTaxes.toFixed(2)}</span>
                        </div>
                        <div className="grid grid-cols-2 text-sm">
                          <span className="text-muted-foreground">Total Net Pay:</span>
                          <span className="font-medium">${totalNetPay.toFixed(2)}</span>
                        </div>
                      </div>
                      <div className="flex justify-end gap-2 mt-4">
                        <Button variant="outline" size="sm">
                          <Download className="mr-2 h-4 w-4" />
                          Export
                        </Button>
                        <Button variant="outline" size="sm">
                          <Printer className="mr-2 h-4 w-4" />
                          Print
                        </Button>
                      </div>
                    </CollapsibleContent>
                  </Collapsible>
                </div>
              </CardFooter>
            )}
          </Card>

          <Sheet open={viewEntrySheet} onOpenChange={setViewEntrySheet}>
            <SheetContent>
              <SheetHeader>
                <SheetTitle>Payroll Entry Details</SheetTitle>
                <SheetDescription>
                  Detailed information about this payroll entry
                </SheetDescription>
              </SheetHeader>

              {selectedEntry ? (
                <div className="space-y-6 mt-6">
                  <div>
                    <h3 className="text-sm font-medium text-muted-foreground mb-2">Employee Information</h3>
                    <p className="text-lg font-semibold">{getEmployeeName(selectedEntry.employeeId)}</p>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div>
                      <h3 className="text-sm font-medium text-muted-foreground mb-2">Pay Details</h3>
                      <div className="space-y-2">
                        <div className="flex justify-between">
                          <span className="text-sm">Regular Hours:</span>
                          <span className="font-medium">{Number(selectedEntry.regularHours).toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-sm">Overtime Hours:</span>
                          <span className="font-medium">{Number(selectedEntry.overtimeHours).toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-sm">Bonus:</span>
                          <span className="font-medium">${Number(selectedEntry.bonusAmount).toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-sm">Commission:</span>
                          <span className="font-medium">${Number(selectedEntry.commissionAmount).toFixed(2)}</span>
                        </div>
                      </div>
                    </div>

                    <div>
                      <h3 className="text-sm font-medium text-muted-foreground mb-2">Summary</h3>
                      <div className="space-y-2">
                        <div className="flex justify-between">
                          <span className="text-sm">Gross Pay:</span>
                          <span className="font-medium">${Number(selectedEntry.grossPay).toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-sm">Taxes:</span>
                          <span className="font-medium">${Number(selectedEntry.taxAmount).toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between">
                          <span className="text-sm">Deductions:</span>
                          <span className="font-medium">${Number(selectedEntry.deductionAmount).toFixed(2)}</span>
                        </div>
                        <div className="flex justify-between font-semibold">
                          <span>Net Pay:</span>
                          <span>${Number(selectedEntry.netPay).toFixed(2)}</span>
                        </div>
                      </div>
                    </div>
                  </div>

                  {selectedEntry.deductionAmount > 0 && (
                    <div>
                      <h3 className="text-sm font-medium text-muted-foreground mb-2">Deduction Reason</h3>
                      <p className="text-sm">{selectedEntry.deductionReason || "No reason specified"}</p>
                    </div>
                  )}

                  {selectedEntry.notes && (
                    <div>
                      <h3 className="text-sm font-medium text-muted-foreground mb-2">Notes</h3>
                      <p className="text-sm">{selectedEntry.notes}</p>
                    </div>
                  )}

                  <div className="pt-4 border-t flex justify-end gap-2">
                    <Button variant="outline">
                      <Printer className="mr-2 h-4 w-4" />
                      Print Pay Stub
                    </Button>
                    <Button>
                      <Download className="mr-2 h-4 w-4" />
                      Download PDF
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="flex justify-center py-8">
                  <div className="animate-spin h-8 w-8 border-4 border-primary border-t-transparent rounded-full"></div>
                </div>
              )}
            </SheetContent>
          </Sheet>
        </>
      ) : (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12 text-center">
            <h3 className="text-lg font-medium mb-2">Select a Payroll Period</h3>
            <p className="text-muted-foreground max-w-md mb-6">
              Choose a payroll period from the dropdown above to view and manage payroll entries.
            </p>
            {!periods || periods.length === 0 ? (
              <Button
                variant="outline"
                onClick={() => {
                  // Navigate to periods creation
                }}
              >
                Create Your First Payroll Period
              </Button>
            ) : null}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

