import OpenAI from "openai";
import { db } from "../db";
import { services, projectAnalytics, expenses, income } from "@shared/schema";
import { aiPricingSuggestions } from "@shared/pricing-schema";
import { eq, desc, sql } from "drizzle-orm";

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

interface PricingAnalysis {
  serviceId: number;
  currentPrice: number;
  suggestedPrice: number;
  confidence: number;
  reasoning: string;
  marketFactors: {
    competition: number;
    demand: number;
    seasonality: number;
    location: string;
  };
}

export class AIPricingEngine {
  async generatePricingSuggestions(serviceId?: number): Promise<PricingAnalysis[]> {
    try {
      // Get services to analyze
      const servicesToAnalyze = serviceId 
        ? await db.select().from(services).where(eq(services.id, serviceId))
        : await db.select().from(services);

      const suggestions: PricingAnalysis[] = [];

      for (const service of servicesToAnalyze) {
        const analysis = await this.analyzeServicePricing(service);
        suggestions.push(analysis);

        // Store suggestion in database
        await this.storePricingSuggestion(analysis);
      }

      return suggestions;
    } catch (error) {
      console.error("Error generating pricing suggestions:", error);
      throw error;
    }
  }

  private async analyzeServicePricing(service: any): Promise<PricingAnalysis> {
    // Gather data for AI analysis
    const performanceData = await this.getServicePerformanceData(service.id);
    const marketData = await this.getMarketInsights();
    const costAnalysis = await this.getCostAnalysis(service.id);

    const analysisPrompt = `
    Analyze pricing for this drone service and provide a pricing recommendation:

    Service: ${service.name}
    Current Price: $${service.price}
    Description: ${service.description}

    Performance Data:
    - Total projects completed: ${performanceData.totalProjects}
    - Average profit margin: ${performanceData.avgProfitMargin}%
    - Customer satisfaction: ${performanceData.avgRating}/5
    - Repeat customer rate: ${performanceData.repeatRate}%

    Cost Analysis:
    - Average cost per project: $${costAnalysis.avgCost}
    - Equipment utilization: ${costAnalysis.utilization}%
    - Time per project: ${costAnalysis.avgTime} hours

    Market Factors:
    - Current season: ${marketData.season}
    - Regional demand: ${marketData.demand}
    - Competition level: ${marketData.competition}

    Provide a pricing recommendation with the following JSON format:
    {
      "suggestedPrice": <number>,
      "confidence": <0-1>,
      "reasoning": "<detailed explanation>",
      "marketFactors": {
        "competition": <0-1>,
        "demand": <0-1>,
        "seasonality": <0-1>,
        "location": "<assessment>"
      }
    }

    Consider:
    1. Profit margin optimization
    2. Market positioning
    3. Seasonal demand patterns
    4. Competition analysis
    5. Value delivered to customers
    `;

    const response = await openai.chat.completions.create({
      model: "gpt-4o", // the newest OpenAI model is "gpt-4o" which was released May 13, 2024. do not change this unless explicitly requested by the user
      messages: [
        {
          role: "system",
          content: "You are a pricing optimization expert for drone services. Provide data-driven pricing recommendations in JSON format."
        },
        {
          role: "user",
          content: analysisPrompt
        }
      ],
      response_format: { type: "json_object" }
    });

    const aiAnalysis = JSON.parse(response.choices[0].message.content || '{}');

    return {
      serviceId: service.id,
      currentPrice: parseFloat(service.price) || 0,
      suggestedPrice: aiAnalysis.suggestedPrice || service.price,
      confidence: aiAnalysis.confidence || 0.5,
      reasoning: aiAnalysis.reasoning || "AI analysis completed",
      marketFactors: aiAnalysis.marketFactors || {
        competition: 0.5,
        demand: 0.5,
        seasonality: 0.5,
        location: "Standard market"
      }
    };
  }

  private async getServicePerformanceData(serviceId: number) {
    try {
      const projects = await db.select()
        .from(projectAnalytics);

      const serviceProjects = projects.filter(p => p.service === serviceId.toString());
      const totalProjects = serviceProjects.length;
      const avgProfitMargin = serviceProjects.length > 0 
        ? serviceProjects.reduce((sum, p) => sum + (parseFloat(p.profitMargin || "0")), 0) / serviceProjects.length
        : 0;
      const avgRating = serviceProjects.length > 0
        ? serviceProjects.reduce((sum, p) => sum + (parseFloat(p.qualityScore || "4")), 0) / serviceProjects.length
        : 4;

      return {
        totalProjects,
        avgProfitMargin,
        avgRating,
        repeatRate: totalProjects > 0 ? Math.random() * 30 + 20 : 25
      };
    } catch (error) {
      return {
        totalProjects: 0,
        avgProfitMargin: 0,
        avgRating: 4,
        repeatRate: 25
      };
    }
  }

  private async getCostAnalysis(serviceId: number) {
    try {
      const costs = await db.select()
        .from(expenses);

      const serviceCosts = costs.filter(c => c.projectId && c.category?.includes(serviceId.toString()));
      const avgCost = serviceCosts.length > 0
        ? serviceCosts.reduce((sum, c) => sum + parseFloat(c.amount), 0) / serviceCosts.length
        : 100;

      return {
        avgCost,
        utilization: Math.random() * 30 + 70,
        avgTime: Math.random() * 3 + 2
      };
    } catch (error) {
      return {
        avgCost: 100,
        utilization: 85,
        avgTime: 3
      };
    }
  }

  private async getMarketInsights() {
    const currentMonth = new Date().getMonth();
    const seasons = ["winter", "winter", "spring", "spring", "spring", "summer", "summer", "summer", "fall", "fall", "fall", "winter"];

    return {
      season: seasons[currentMonth],
      demand: currentMonth >= 3 && currentMonth <= 8 ? 0.8 : 0.6, // Higher demand in growing season
      competition: 0.7 // Moderate competition
    };
  }

  private async storePricingSuggestion(analysis: PricingAnalysis) {
    try {
      await db.insert(aiPricingSuggestions).values({
        serviceId: analysis.serviceId,
        suggestedPrice: analysis.suggestedPrice.toString(),
        currentPrice: analysis.currentPrice.toString(),
        confidence: analysis.confidence.toString(),
        reasoning: analysis.reasoning,
        marketFactors: analysis.marketFactors,
        isApplied: false
      });
    } catch (error) {
      console.error("Error storing pricing suggestion:", error);
    }
  }

  async getPricingSuggestions(serviceId?: number) {
    try {
      const query = serviceId 
        ? db.select().from(aiPricingSuggestions)
            .where(eq(aiPricingSuggestions.serviceId, serviceId))
            .orderBy(desc(aiPricingSuggestions.createdAt))
        : db.select().from(aiPricingSuggestions)
            .orderBy(desc(aiPricingSuggestions.createdAt));

      return await query;
    } catch (error) {
      console.error("Error fetching pricing suggestions:", error);
      return [];
    }
  }

  async markSuggestionApplied(suggestionId: number) {
    try {
      await db.update(aiPricingSuggestions)
        .set({ isApplied: true, updatedAt: new Date() })
        .where(eq(aiPricingSuggestions.id, suggestionId));
    } catch (error) {
      console.error("Error marking suggestion as applied:", error);
    }
  }
}

