        }
      ];

      for (const interaction of interactions) {
        await db.insert(customerInteractions).values(interaction);
      }
      console.log("Sample customer interactions added successfully");

      // Seed customer deals
      const deals = [
        {
          customerId: insertedCustomers[0].id,
