  async getClientFileCounts(clientId: number): Promise<{ bookingId: number; images: number; videos: number; documents: number; models3d: number; }[]> {
    const files = await this.getClientFiles(clientId);

    // Group files by bookingId and type
    const bookingCounts = new Map<number, { images: number; videos: number; documents: number; models3d: number; }>();

    for (const file of files) {
      if (!file.bookingId) continue;

      if (!bookingCounts.has(file.bookingId)) {
        bookingCounts.set(file.bookingId, { images: 0, videos: 0, documents: 0, models3d: 0 });
      }

      const counts = bookingCounts.get(file.bookingId)!;

      if (file.fileType === 'image') {
        counts.images++;
      } else if (file.fileType === 'video') {
        counts.videos++;
      } else if (file.fileType === 'document') {
        counts.documents++;
      } else if (file.fileType === '3d_model') {
        counts.models3d++;
      }
    }

    return Array.from(bookingCounts.entries()).map(([bookingId, counts]) => ({
      bookingId,
      ...counts
    }));
  }

