                      <div className="w-8 h-8 rounded-full bg-gold-DEFAULT/20 flex items-center justify-center mr-3">
                        <span className="text-gold-light">✓</span>
                      </div>
                      <p className="text-offwhite">Book new services with just a few clicks</p>
