import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Check, Edit, Trash2 } from "lucide-react";
import { useQuery } from "@tanstack/react-query";

export function ServicesDisplayTest() {
  const { data: services } = useQuery({ queryKey: ["/api/services"] });
  const { data: addons } = useQuery({ queryKey: ["/api/addons"] });
  const { data: serviceAddons } = useQuery({ queryKey: ["/api/service-addons"] });

  const formatPrice = (price: number) => {
    return `$${(price / 100).toFixed(2)}`;
  };

  const getEnabledAddons = (serviceId: number) => {
    if (!serviceAddons || !addons) return [];

    return serviceAddons
      .filter(sa => sa.serviceId === serviceId && sa.isEnabled)
      .map(sa => addons.find(addon => addon.id === sa.addonId))
      .filter(Boolean);
  };

  const renderPricingTiers = (service: any) => {
    if (service.pricingType === "tiered" && service.pricingTiers && service.pricingTiers.length > 0) {
      return (
        <div className="space-y-3">
          <div className="text-lg font-medium text-gold-gradient mb-3">Packages:</div>
          {service.pricingTiers.map((tier: any, index: number) => (
            <div 
              key={index} 
              className="p-4 rounded-lg border-2 transition-all cursor-pointer relative overflow-hidden bg-offwhite/5 hover:bg-offwhite/10 border-gold-gradient"
              style={{
                borderImage: 'linear-gradient(90deg, var(--gold-start), var(--gold-middle), var(--gold-end)) 1'
              }}
            >
              {/* Package Name - Centered */}
              <div className="text-center text-gold-gradient font-medium text-lg mb-2">
                {tier.name}
              </div>

              {/* Quantity and Price - Left/Right Aligned */}
              <div className="flex justify-between items-center mb-2">
                <div className="text-sm text-gold-gradient">
                  {tier.maxQuantity && tier.maxQuantity !== tier.minQuantity 
                    ? `${tier.minQuantity}-${tier.maxQuantity} ${tier.quantityUnit}`
                    : tier.minQuantity === 1 && !tier.maxQuantity
                      ? `${tier.quantityUnit}`
                      : tier.maxQuantity
                        ? `${tier.minQuantity} ${tier.quantityUnit}`
                        : `${tier.minQuantity}+ ${tier.quantityUnit}`
                  }
                </div>
                <div className="text-gold-gradient font-montserrat font-semibold">
                  {tier.priceType === "range" && tier.minPrice && tier.maxPrice 
                    ? `${formatPrice(tier.minPrice * 100)} - ${formatPrice(tier.maxPrice * 100)}`
                    : formatPrice(tier.price * 100)
                  }
                </div>
              </div>

              {/* Description - Centered */}
              {tier.description && (
                <div className="text-center text-xs text-gold-gradient mt-2">
                  {tier.description}
                </div>
              )}
            </div>
          ))}
        </div>
      );
    }
    return null;
  };

  const renderUnitTypeInfo = (service: any) => {
    if (service.pricingType === "per_unit" && service.unitType) {
      return (
        <div className="bg-green-50 p-2 rounded border">
          <div className="text-sm font-medium text-green-600">Custom Unit Pricing:</div>
          <div className="text-green-700">
            {formatPrice(service.price)} per {service.unitType}
          </div>
        </div>
      );
    }
    return null;
  };

  return (
    <div className="space-y-6">
      <div className="bg-yellow-50 border border-yellow-200 p-4 rounded">
        <h2 className="text-lg font-bold text-yellow-800 mb-2">Testing Three Critical Issues:</h2>
        <ul className="text-sm text-yellow-700 space-y-1">
          <li>1. Enhanced pricing tiers with quantity ranges and price ranges</li>
          <li>2. Custom unit types for per-unit pricing (photos, videos, etc.)</li>
          <li>3. Green visual indicators for enabled add-ons</li>
        </ul>
      </div>

      <div className="grid grid-cols-1 gap-6">
        {services?.map((service: any) => {
          const enabledAddons = getEnabledAddons(service.id);

          return (
            <Card key={service.id} className="border-2 border-gray-200 hover:border-blue-300 transition-colors">
              <CardHeader>
                <div className="flex justify-between items-start">
                  <div>
                    <CardTitle className="text-xl text-gold-gradient">{service.name}</CardTitle>
                    <div className="text-gray-600 mt-1">{service.description}</div>
                  </div>
                  <div className="flex gap-2">
                    {service.isAvailableAsAddon && (
                      <Badge variant="secondary" className="bg-purple-100 text-purple-800">
                        Addon Available
                      </Badge>
                    )}
                  </div>
                </div>
              </CardHeader>

              <CardContent className="space-y-4">
                {/* Base Price Display */}
                <div className="text-2xl font-bold text-gold-gradient">
                  Base Price: {formatPrice(service.price)}
                </div>

                {/* Test Issue #1: Enhanced Pricing Tiers */}
                {renderPricingTiers(service)}

                {/* Test Issue #2: Custom Unit Types */}
                {renderUnitTypeInfo(service)}

                {/* Test Issue #3: Addon Visual Indicators */}
                {enabledAddons.length > 0 && (
                  <div className="space-y-2">
                    <div className="text-sm font-medium text-green-600">✅ ISSUE #3 TEST - Active Add-ons:</div>
                    <div className="flex flex-wrap gap-2">
                      {enabledAddons.map((addon: any) => (
                        <Badge 
                          key={addon.id} 
                          variant="default" 
                          className="bg-green-500 hover:bg-green-600 text-white"
                        >
                          <Check className="w-3 h-3 mr-1" />
                          {addon.name}
                        </Badge>
                      ))}
                    </div>
                  </div>
                )}

                {/* Current Pricing Type Display */}
                <div className="bg-gray-50 p-3 rounded">
                  <div className="text-sm font-medium text-gray-700">Current Configuration:</div>
                  <div className="text-xs text-gray-600 mt-1">
                    Pricing Type: <span className="font-semibold">{service.pricingType || "flat"}</span>
                  </div>
                  {service.unitType && (
                    <div className="text-xs text-gray-600">
                      Unit Type: <span className="font-semibold">{service.unitType}</span>
                    </div>
                  )}
                  <div className="text-xs text-gray-600">
                    Service ID: {service.id}
                  </div>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>
    </div>
  );
}

