        <h2 className="text-2xl font-semibold text-offwhite">Manage Services</h2>
      </div>

      {services.length === 0 ? (
        <Card className="bg-[#132642] border-gold-dark/30">
          <CardContent className="pt-6">
            <div className="text-center">
              <p className="text-offwhite/60 mb-4">No services found. Add your first service below!</p>
            </div>
          </CardContent>
        </Card>
      ) : (
        <div className="grid gap-4 mb-8">
          {services.map((service) => (
            <Card key={service.id} className="bg-[#132642] border-gold-dark/30">
              <CardContent className="pt-6">
                <div className="flex justify-between items-start">
                  <div className="flex-1">
                    <h3 className="text-lg font-semibold text-offwhite mb-2">{service.name}</h3>
                    <p className="text-offwhite/70 mb-3">{service.description}</p>
                    <div className="flex flex-wrap gap-2 mb-3">
                      <span className="text-gold-gradient font-semibold">
                        {formatPrice(service.price / 100)}
                        {service.pricingType === "tiered" && service.basePriceQuantity && 
                          ` for ${service.basePriceQuantity} items`
                        }
                      </span>
                      {service.pricingType === "tiered" && service.additionalPricePerUnit && (
                        <span className="text-offwhite/60 text-sm">
                          + {formatPrice(service.additionalPricePerUnit / 100)} per additional item
                        </span>
                      )}
                    </div>
                    {service.classification && (
                      <span className="inline-block px-2 py-1 bg-gold/20 text-gold text-xs rounded">
                        {service.classification}
                      </span>
                    )}
                  </div>
                  <div className="flex gap-2 ml-4">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => editService(service)}
                      className="border-gold-dark/30 text-offwhite hover:bg-[#080d17]"
                    >
                      <Edit className="h-4 w-4" />
                    </Button>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={() => deleteServiceMutation.mutate(service.id)}
                      className="border-red-600/30 text-red-400 hover:bg-red-600/10"
                    >
                      <Trash2 className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      {/* Add New Service Section - Directly on Page */}
      <Card className="bg-[#132642] border-gold-dark/30">
        <CardContent className="p-6">
          <h3 className="text-xl font-semibold text-gold mb-6">
            {currentService ? "Edit Service" : "Add New Service"}
          </h3>

          {/* Show current content when editing */}
          {currentService && (
            <div className="bg-blue-900/20 border border-blue-600/50 rounded-lg p-4 mb-6">
              <h4 className="text-blue-400 font-bold text-lg mb-4">📝 Currently Editing: {currentService.name}</h4>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div>
                  <h5 className="text-blue-300 font-medium mb-2">Current Description:</h5>
                  <p className="text-offwhite/80 text-sm bg-[#080d17] p-3 rounded border">{currentService.description}</p>
                </div>
                <div>
