                        isUploading 
                          ? 'bg-gray-600/20 border-gray-600/30 text-gray-400 cursor-not-allowed' 
                          : 'bg-[#080d17] border-green-dark/30 text-green-400 hover:bg-green-600/10'
                      }`}
                    >
                      {isUploading ? (
                        <>
                          <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                          Uploading...
                        </>
                      ) : (
                        <>
                          <Upload className="h-4 w-4 mr-2" />
                          Choose Image File
                        </>
                      )}
                    </label>
                  </div>
                  <p className="text-xs text-offwhite/60">
                    Select an image from your computer. Max 5MB. Supported: JPG, PNG, GIF, WebP
                  </p>
                </div>

                {/* OR Divider */}
                <div className="flex items-center gap-3">
                  <div className="flex-1 h-px bg-green-600/30"></div>
                  <span className="text-sm text-offwhite/60">OR</span>
                  <div className="flex-1 h-px bg-green-600/30"></div>
                </div>

                {/* Image URL Input */}
                <div className="grid gap-2">
                  <Label htmlFor="imageUrl" className="text-green-400 font-medium">Image URL:</Label>
                  <div className="flex gap-2">
                    <Input
                      id="imageUrl"
                      placeholder="https://example.com/image.jpg"
                      value={serviceForm.imageUrl.startsWith('data:') ? '' : serviceForm.imageUrl}
                      onChange={(e) => setServiceForm({ ...serviceForm, imageUrl: e.target.value })}
                      className="bg-[#080d17] border-green-dark/30 flex-1"
                      disabled={serviceForm.imageUrl.startsWith('data:')}
                    />
                    <Button 
                      type="button" 
                      variant="outline" 
                      onClick={() => {
                        // Simple image URL validation
                        if (serviceForm.imageUrl && !serviceForm.imageUrl.match(/\.(jpg|jpeg|png|gif|webp)$/i)) {
                          toast({
                            title: "Invalid Image URL",
                            description: "Please provide a valid image URL ending in .jpg, .png, .gif, or .webp",
                            variant: "destructive"
                          });
                        }
                      }}
                      className="border-green-dark/30 text-green-400 hover:bg-green-600/10"
                      disabled={serviceForm.imageUrl.startsWith('data:')}
                    >
                      <Image className="h-4 w-4 mr-2" /> Preview
                    </Button>
                  </div>
                  <p className="text-xs text-offwhite/60">
                    {serviceForm.imageUrl.startsWith('data:') 
                      ? 'Image uploaded from computer (clear image to use URL instead)'
                      : 'Paste a direct link to an image file'
                    }
                  </p>
                </div>
              </div>
            </div>

            {/* About This Service */}
            <div className="bg-purple-900/20 border border-purple-600/50 rounded-lg p-4">
              <h4 className="text-purple-400 font-bold text-lg mb-4">📝 ABOUT THIS SERVICE</h4>

              <div className="grid gap-4">
                {/* Current Content Display */}
                {currentService && currentService.aboutServiceContent && (
                  <div className="bg-[#080d17] p-3 rounded border border-purple-600/30">
                    <Label className="text-purple-300 font-medium mb-2 block">Current Content:</Label>
                    <div className="text-sm text-offwhite/80 whitespace-pre-wrap max-h-32 overflow-y-auto">
                      {currentService.aboutServiceContent}
                    </div>
                  </div>
                )}

                <div className="grid gap-2">
                  <Label htmlFor="aboutServiceContent" className="text-purple-400 font-medium">
                    {currentService ? "Update Detailed Description:" : "Detailed Description:"}
                  </Label>
                  <Textarea
                    id="aboutServiceContent"
                    placeholder="Provide a detailed description of this service, its benefits, and what makes it unique..."
                    value={serviceForm.aboutServiceContent}
                    onChange={(e) => setServiceForm({ ...serviceForm, aboutServiceContent: e.target.value })}
                    className="bg-[#080d17] border-purple-dark/30 min-h-[100px]"
                    rows={4}
                  />
                  <p className="text-xs text-offwhite/60">
                    This detailed description will appear on the service page to help clients understand the value
                  </p>
                </div>
              </div>
            </div>

            {/* What's Included */}
            <div className="bg-cyan-900/20 border border-cyan-600/50 rounded-lg p-4">
              <h4 className="text-cyan-400 font-bold text-lg mb-4">📋 WHAT'S INCLUDED</h4>

              <div className="grid gap-4">
                {/* Current Items List */}
                {serviceForm.whatsIncludedContent.length > 0 && (
                  <div className="space-y-2">
                    <Label className="text-cyan-400 font-medium">Included Items:</Label>
                    <ul className="space-y-2">
                      {serviceForm.whatsIncludedContent.map((item, index) => (
                        <li key={index} className="flex items-center justify-between bg-[#080d17] p-3 rounded border border-cyan-600/30">
                          <div className="flex items-center flex-1">
                            <GripVertical className="h-4 w-4 text-cyan-400 mr-2 cursor-grab" />
                            <span className="w-2 h-2 bg-cyan-400 rounded-full mr-3"></span>
                            <span className="text-offwhite flex-1">{item}</span>
                          </div>
                          <div className="flex items-center gap-1">
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => setServiceForm({ 
                                ...serviceForm, 
                                whatsIncludedContent: moveItemUp(serviceForm.whatsIncludedContent, index) 
                              })}
                              disabled={index === 0}
                              className="h-8 w-8 p-0 text-cyan-400 hover:bg-cyan-600/10 disabled:opacity-30"
                            >
                              <ArrowUp className="h-3 w-3" />
                            </Button>
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => setServiceForm({ 
                                ...serviceForm, 
                                whatsIncludedContent: moveItemDown(serviceForm.whatsIncludedContent, index) 
                              })}
                              disabled={index === serviceForm.whatsIncludedContent.length - 1}
                              className="h-8 w-8 p-0 text-cyan-400 hover:bg-cyan-600/10 disabled:opacity-30"
                            >
                              <ArrowDown className="h-3 w-3" />
                            </Button>
                            <Button
                              type="button"
                              variant="outline"
                              size="sm"
                              onClick={() => removeWhatsIncluded(index)}
                              className="h-8 w-8 p-0 border-red-600/30 text-red-400 hover:bg-red-600/10"
                            >
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}

                {/* Add New Item */}
                <div className="grid gap-2">
                  <Label htmlFor="whatsIncludedInput" className="text-cyan-400 font-medium">Add Included Item:</Label>
                  <div className="flex gap-2">
                    <Input
                      id="whatsIncludedInput"
                      placeholder="e.g. 20 high-resolution photos"
                      value={whatsIncludedInput}
                      onChange={(e) => setWhatsIncludedInput(e.target.value)}
                      onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), addWhatsIncluded())}
                      className="bg-[#080d17] border-cyan-dark/30 flex-1"
                    />
                    <Button 
