                              variant="ghost"
                              size="sm"
                              onClick={() => setServiceForm({ 
                                ...serviceForm, 
                                processSteps: moveItemUp(serviceForm.processSteps, index) 
                              })}
                              disabled={index === 0}
                              className="h-8 w-8 p-0 text-indigo-400 hover:bg-indigo-600/10 disabled:opacity-30"
                            >
                              <ArrowUp className="h-3 w-3" />
                            </Button>
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => setServiceForm({ 
