                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => setServiceForm({ 
                                ...serviceForm, 
                                features: moveItemUp(serviceForm.features, index) 
                              })}
                              disabled={index === 0}
                              className="h-8 w-8 p-0 text-blue-400 hover:bg-blue-600/10 disabled:opacity-30"
                            >
                              <ArrowUp className="h-3 w-3" />
                            </Button>
                            <Button
                              type="button"
                              variant="ghost"
                              size="sm"
                              onClick={() => setServiceForm({ 
                                ...serviceForm, 
                                features: moveItemDown(serviceForm.features, index) 
                              })}
                              disabled={index === serviceForm.features.length - 1}
                              className="h-8 w-8 p-0 text-blue-400 hover:bg-blue-600/10 disabled:opacity-30"
                            >
                              <ArrowDown className="h-3 w-3" />
                            </Button>
                            <Button
                              type="button"
                              variant="outline"
                              size="sm"
                              onClick={() => removeFeature(index)}
                              className="h-8 w-8 p-0 border-red-600/30 text-red-400 hover:bg-red-600/10"
                            >
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        </li>
                      ))}
                    </ul>
                  </div>
