                      className="bg-[#080d17] border-orange-dark/30 w-32"
                    />
                    <span className="text-orange-400 font-medium">%</span>
                    <span className="text-xs text-offwhite/60 ml-2">
                      {serviceForm.bundleDiscountPercentage > 0 
