                        : 'No discount when bundled (full price)'
                      }
                    </span>
                  </div>
                  <p className="text-xs text-offwhite/60">
                    When clients bundle this service with others, it will be discounted by this percentage. 
                    The system automatically charges full price for the most expensive service in the bundle.
                  </p>
                </div>

                {/* Individual Bundle Percentage Controls */}
                <div className="bg-gradient-to-r from-purple-900/30 to-pink-900/30 border border-purple-600/50 rounded-lg p-4">
                  <h5 className="text-purple-400 font-bold text-lg mb-4">🎯 INDIVIDUAL BUNDLE PERCENTAGES</h5>
                  <p className="text-sm text-offwhite/80 mb-4">
                    Set custom discount percentages for each service when bundled with this one. This gives you precise control over your pricing strategy.
                  </p>

                  {services.length > 0 ? (
                    <div className="space-y-3">
                      {services
                        .filter(service => currentService ? service.id !== currentService.id : true)
                        .map((service) => (
                          <div key={service.id} className="bg-[#080d17] p-4 rounded border border-purple-600/30">
                            <div className="flex items-center justify-between mb-3">
                              <div className="flex items-center space-x-3">
                                <input
                                  type="checkbox"
                                  id={`bundle-${service.id}`}
                                  checked={serviceForm.availableAddOns.includes(service.id)}
                                  onChange={() => toggleAddOn(service.id)}
                                  className="w-4 h-4 text-purple-400 bg-[#080d17] border-purple-dark/30 rounded focus:ring-purple-400"
                                />
                                <div>
                                  <span className="text-offwhite font-medium">{service.name}</span>
                                  <p className="text-xs text-offwhite/60">{service.description}</p>
                                </div>
                              </div>
                              <span className="text-purple-400 font-medium">{formatPrice(service.price)}</span>
                            </div>

                            {/* Individual Percentage Control */}
                            {serviceForm.availableAddOns.includes(service.id) && (
                              <div className="flex items-center gap-4 ml-7 pt-3 border-t border-purple-600/20">
                                <Label className="text-purple-300 text-sm">Custom discount when bundled:</Label>
                                <div className="flex items-center gap-2">
                                  <Input
                                    type="number"
                                    min="0"
                                    max="100"
                                    placeholder="50"
                                    value={serviceForm.bundleDiscounts?.[service.id] || service.bundleDiscountPercentage || 0}
                                    onChange={(e) => setServiceForm({ 
                                      ...serviceForm, 
                                      bundleDiscounts: {
                                        ...(serviceForm.bundleDiscounts || {}),
                                        [service.id]: parseInt(e.target.value) || 0
                                      }
                                    })}
                                    className="bg-[#0a0f1a] border-purple-dark/30 w-20 text-center"
                                  />
                                  <span className="text-purple-400">%</span>
                                  <span className="text-xs text-offwhite/60">
                                    = {formatPrice((service.price * (serviceForm.bundleDiscounts?.[service.id] || service.bundleDiscountPercentage || 100)) / 100)}
                                  </span>
                                </div>
                              </div>
                            )}
                          </div>
                        ))
                      }
                    </div>
                  ) : (
                    <p className="text-offwhite/60 text-sm">
                      Create other services first to enable individual bundle pricing
                    </p>
                  )}
                </div>

                {/* Available Add-Ons Selection (Legacy - keeping for compatibility) */}
                <div className="grid gap-2">
                  <Label className="text-orange-400 font-medium">
                    Services that can be bundled WITH this service:
                  </Label>

                  {services.length > 0 ? (
                    <div className="space-y-2 max-h-64 overflow-y-auto">
                      {services
                        .filter(service => currentService ? service.id !== currentService.id : true)
                        .map((service) => (
                          <div key={service.id} className="flex items-center space-x-3 bg-[#080d17] p-3 rounded border border-orange-600/30">
                            <input
                              type="checkbox"
                              id={`addon-${service.id}`}
                              checked={serviceForm.availableAddOns.includes(service.id)}
                              onChange={() => toggleAddOn(service.id)}
                              className="w-4 h-4 text-orange-400 bg-[#080d17] border-orange-dark/30 rounded focus:ring-orange-400"
                            />
                            <label htmlFor={`addon-${service.id}`} className="flex-1 cursor-pointer">
                              <div className="flex items-center justify-between">
                                <div>
                                  <span className="text-offwhite font-medium">{service.name}</span>
                                  <p className="text-xs text-offwhite/60 mt-1">{service.description}</p>
                                </div>
                                <div className="text-right">
                                  <span className="text-orange-400 font-medium">
                                    {formatPrice(service.price)}
                                  </span>
                                  {service.bundleDiscountPercentage && service.bundleDiscountPercentage > 0 && (
                                    <p className="text-xs text-orange-300">
                                      {service.bundleDiscountPercentage}% off when bundled
                                    </p>
                                  )}
                                </div>
                              </div>
                            </label>
                          </div>
                        ))
                      }
                    </div>
                  ) : (
                    <p className="text-offwhite/60 text-sm">
                      Create other services first to enable bundling options
                    </p>
                  )}

                  <p className="text-xs text-offwhite/60">
                    Select services that clients can add to their order when purchasing this service. 
                    The system will automatically apply the appropriate discount percentages.
                  </p>
                </div>

                {/* Bundle Preview */}
                {serviceForm.availableAddOns.length > 0 && (
                  <div className="bg-[#080d17] p-4 rounded border border-orange-600/30">
                    <Label className="text-orange-400 font-medium mb-2 block">Bundle Preview:</Label>
                    <div className="space-y-2">
                      <div className="flex justify-between">
                        <span className="text-offwhite">{serviceForm.name || "This Service"} (Primary)</span>
                        <span className="text-orange-400 font-medium">{formatPrice(serviceForm.price * 100)}</span>
                      </div>
                      {serviceForm.availableAddOns.map(addonId => {
                        const addon = services.find(s => s.id === addonId);
                        if (!addon) return null;
                        const discountedPrice = addon.price * (addon.bundleDiscountPercentage || 100) / 100;
                        return (
                          <div key={addonId} className="flex justify-between text-sm">
                            <span className="text-offwhite/80">+ {addon.name}</span>
                            <span className="text-orange-300">
                              {addon.bundleDiscountPercentage && addon.bundleDiscountPercentage > 0 ? (
                                <>
                                  <span className="line-through text-offwhite/40 mr-2">{formatPrice(addon.price)}</span>
                                  {formatPrice(discountedPrice)}
                                </>
                              ) : (
                                formatPrice(addon.price)
                              )}
                            </span>
                          </div>
                        );
                      })}
                    </div>
                  </div>
                )}
              </div>
