            <div className="bg-yellow-900/20 border border-yellow-600/50 rounded-lg p-6">
              <h4 className="text-yellow-400 font-bold text-lg mb-4">💰 PRICING CONFIGURATION</h4>

              <div className="grid gap-6">
                <div className="grid gap-2">
                  <Label htmlFor="price" className="text-white font-medium">Base Price (in dollars)</Label>
                  <Input
                    id="price"
                    type="number"
                    step="0.01"
                    placeholder="e.g. 299.99"
                    value={serviceForm.price}
                    onChange={(e) => setServiceForm({ 
                      ...serviceForm, 
                      price: parseFloat(parseFloat(e.target.value).toFixed(2)) || 0 
                    })}
                    className="bg-[#080d17] border-gold-dark/30"
                    required
                  />
                  <p className="text-xs text-offwhite/60">
                    This will display as: {formatPrice(serviceForm.price || 0)}
                  </p>
                </div>

                <div className="grid gap-2">
                  <Label htmlFor="pricingType" className="text-yellow-400 font-bold">🎯 Pricing Structure Type</Label>
                  <select 
                    value={serviceForm.pricingType}
                    onChange={(e) => setServiceForm({ ...serviceForm, pricingType: e.target.value as "flat" | "tiered" | "per_unit" | "range_based" })}
                    className="bg-[#080d17] border border-yellow-600 rounded-md px-3 py-2 text-white font-medium"
                  >
                    <option value="flat">Flat Rate - Single fixed price</option>
                    <option value="tiered">Tiered Pricing - Base quantity + additional per unit</option>
                    <option value="per_unit">Per Unit - Price calculated per item</option>
                    <option value="range_based">Range-Based - Different prices for different ranges</option>
                  </select>
                </div>

                {/* Unit Type Selection for Per-Unit, Tiered, and Range-Based Pricing */}
                {(serviceForm.pricingType === "per_unit" || serviceForm.pricingType === "tiered" || serviceForm.pricingType === "range_based") && (
                  <div className="grid gap-2">
                    <Label htmlFor="unitType" className="text-yellow-400 font-bold">📐 Unit Type</Label>
                    <select 
                      value={serviceForm.unitType}
                      onChange={(e) => setServiceForm({ ...serviceForm, unitType: e.target.value as "acre" | "square_foot" | "unit" })}
                      className="bg-[#080d17] border border-yellow-600 rounded-md px-3 py-2 text-white font-medium"
                    >
                      <option value="acre">Acre - Land area measurement</option>
                      <option value="square_foot">Square Foot - Building/area measurement</option>
                      <option value="unit">Unit - General count (photos, items, etc.)</option>
                    </select>
                    <p className="text-xs text-offwhite/60">
                      This determines how your pricing is calculated and displayed to clients
                    </p>
                  </div>
                )}

                {/* Range-Based Pricing Configuration */}
                {serviceForm.pricingType === "range_based" && (
                  <div className="grid gap-4 p-4 bg-indigo-900/20 border border-indigo-600/50 rounded-lg">
                    <h5 className="text-indigo-400 font-bold">📊 Range-Based Pricing Configuration</h5>
                    <p className="text-sm text-offwhite/80">
                      Set different prices for different ranges. Perfect for services like roof inspections where price varies by property size.
                    </p>

                    {/* Current Price Ranges */}
                    {serviceForm.priceRanges && serviceForm.priceRanges.length > 0 && (
                      <div className="space-y-3">
                        <Label className="text-indigo-400 font-medium">Current Price Ranges:</Label>
                        {serviceForm.priceRanges.map((range, index) => (
                          <div key={index} className="bg-[#080d17] p-3 rounded border border-indigo-600/30">
                            <div className="flex items-center justify-between">
                              <div>
                                <span className="text-offwhite font-medium">{range.label}</span>
                                <p className="text-sm text-offwhite/60">
                                  {range.maxPrice ? 
                                    `${formatPrice(range.minPrice / 100)} - ${formatPrice(range.maxPrice / 100)}` : 
                                    formatPrice(range.minPrice / 100)
                                  }
                                </p>
                              </div>
                              <Button
                                type="button"
                                variant="outline"
                                size="sm"
                                onClick={() => {
                                  const newRanges = [...(serviceForm.priceRanges || [])];
                                  newRanges.splice(index, 1);
                                  setServiceForm({ ...serviceForm, priceRanges: newRanges });
                                }}
                                className="border-red-600/30 text-red-400 hover:bg-red-600/10"
                              >
                                <Trash2 className="h-4 w-4" />
                              </Button>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Add New Range Interface */}
                    <div className="bg-[#0a0f1a] p-4 rounded border border-indigo-600/20">
                      <Label className="text-indigo-300 font-medium mb-3 block">Add New Price Range:</Label>
                      <div className="grid gap-4">
                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <div className="flex items-center gap-2 mb-2">
                              <input
                                type="checkbox"
                                id="useUpTo"
                                className="w-4 h-4 text-indigo-400 bg-[#080d17] border-indigo-dark/30 rounded focus:ring-indigo-400"
                              />
                              <Label htmlFor="useUpTo" className="text-sm text-offwhite/80 cursor-pointer">
                                Use "Up to" instead of minimum
                              </Label>
                            </div>
                            <Label className="text-sm text-offwhite/80">
                              <span id="minValueLabel">Minimum {serviceForm.unitType?.replace('_', ' ') || 'unit'}</span>
                            </Label>
                            <Input
                              type="number"
                              placeholder="e.g., 10000"
                              className="bg-[#080d17] border-indigo-dark/30"
                              id="rangeMinValue"
                            />
                          </div>
                          <div>
                            <div className="flex items-center gap-2 mb-2">
                              <input
                                type="checkbox"
                                id="useOrMore"
                                className="w-4 h-4 text-indigo-400 bg-[#080d17] border-indigo-dark/30 rounded focus:ring-indigo-400"
                              />
                              <Label htmlFor="useOrMore" className="text-sm text-offwhite/80 cursor-pointer">
                                Use "Or More" instead of maximum
                              </Label>
                            </div>
                            <Label className="text-sm text-offwhite/80">
                              <span id="maxValueLabel">Maximum {serviceForm.unitType?.replace('_', ' ') || 'unit'} (optional)</span>
                            </Label>
                            <Input
                              type="number"
                              placeholder="e.g., 50000 (leave empty for >)"
                              className="bg-[#080d17] border-indigo-dark/30"
                              id="rangeMaxValue"
                            />
                          </div>
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div>
                            <Label className="text-sm text-offwhite/80">Minimum Price ($)</Label>
                            <Input
                              type="number"
                              step="0.01"
                              placeholder="e.g., 400"
                              className="bg-[#080d17] border-indigo-dark/30"
                              id="rangeMinPrice"
                            />
                          </div>
                          <div>
                            <Label className="text-sm text-offwhite/80">Maximum Price ($) (optional)</Label>
                            <Input
                              type="number"
                              step="0.01"
                              placeholder="e.g., 1000 (leave empty for single price)"
                              className="bg-[#080d17] border-indigo-dark/30"
                              id="rangeMaxPrice"
                            />
                          </div>
                        </div>
                        <Button
                          type="button"
                          variant="outline"
                          onClick={() => {
                            const minValueEl = document.getElementById('rangeMinValue') as HTMLInputElement;
                            const maxValueEl = document.getElementById('rangeMaxValue') as HTMLInputElement;
                            const minPriceEl = document.getElementById('rangeMinPrice') as HTMLInputElement;
                            const maxPriceEl = document.getElementById('rangeMaxPrice') as HTMLInputElement;
                            const useUpToEl = document.getElementById('useUpTo') as HTMLInputElement;
                            const useOrMoreEl = document.getElementById('useOrMore') as HTMLInputElement;

                            const minValue = parseFloat(minValueEl?.value || '0');
                            const maxValue = maxValueEl?.value ? parseFloat(maxValueEl.value) : null;
                            const minPrice = parseFloat(minPriceEl?.value || '0');
                            const maxPrice = maxPriceEl?.value ? parseFloat(maxPriceEl.value) : null;
                            const useUpTo = useUpToEl?.checked || false;
                            const useOrMore = useOrMoreEl?.checked || false;

                            // Validation: Need at least one value and one price
                            const hasValidValue = minValue > 0 || (maxValue && maxValue > 0);
                            const hasValidPrice = minPrice > 0 || (maxPrice && maxPrice > 0);

                            if (hasValidValue && hasValidPrice) {
                              const unitLabel = serviceForm.unitType === 'square_foot' ? 'sq/ft' : 
                                              serviceForm.unitType === 'acre' ? 'acre' : 'unit';

                              let label = '';

                              if (useUpTo && minValue > 0 && !maxValue) {
                                // "Up to X" format - only minimum value with "Up to" checkbox
                                label = `Up to ${minValue.toLocaleString()} ${unitLabel}`;
                              } else if (useUpTo && maxValue && maxValue > 0 && minValue === 0) {
                                // "Up to X" format - only maximum value with "Up to" checkbox
                                label = `Up to ${maxValue.toLocaleString()} ${unitLabel}`;
                              } else if (useOrMore && minValue > 0 && !maxValue) {
                                // "X or More" format - only minimum value with "Or More" checkbox
                                label = `${minValue.toLocaleString()} ${unitLabel} or More`;
                              } else if (useOrMore && maxValue && maxValue > 0 && minValue === 0) {
                                // "X or More" format - only maximum value with "Or More" checkbox
                                label = `${maxValue.toLocaleString()} ${unitLabel} or More`;
                              } else if (maxValue && maxValue > minValue && minValue > 0) {
                                // Standard range format
                                label = `${minValue.toLocaleString()} - ${maxValue.toLocaleString()} ${unitLabel}`;
                              } else if (minValue > 0 && !maxValue) {
                                // Default "greater than" format
                                label = `>${minValue.toLocaleString()} ${unitLabel}`;
                              } else if (maxValue && maxValue > 0 && minValue === 0) {
                                // Maximum only format
                                label = `Up to ${maxValue.toLocaleString()} ${unitLabel}`;
                              } else {
                                // Fallback
                                label = `${Math.max(minValue, maxValue || 0).toLocaleString()} ${unitLabel}`;
                              }

                              const newRange: PriceRange = {
                                minValue: minValue || 0,
                                maxValue: maxValue || undefined,
                                minPrice,
                                maxPrice: maxPrice || undefined,
                                label
                              };

                              setServiceForm({
                                ...serviceForm,
                                priceRanges: [...(serviceForm.priceRanges || []), newRange]
                              });

                              // Clear form fields
                              if (minValueEl) minValueEl.value = '';
                              if (maxValueEl) maxValueEl.value = '';
                              if (minPriceEl) minPriceEl.value = '';
                              if (maxPriceEl) maxPriceEl.value = '';
                              if (useUpToEl) useUpToEl.checked = false;
                              if (useOrMoreEl) useOrMoreEl.checked = false;

                              toast({
                                title: "Range Added",
                                description: `Added pricing range: ${label}`,
                              });
                            } else {
                              toast({
                                title: "Invalid Input",
                                description: "Please enter at least one value (minimum or maximum) and at least one price",
                                variant: "destructive"
                              });
                            }
                          }}
                          className="border-indigo-dark/30 text-indigo-400 hover:bg-indigo-600/10"
                        >
                          <PlusCircle className="h-4 w-4 mr-2" /> Add Range
                        </Button>
                      </div>
                    </div>
                  </div>
                )}

                {/* Tiered Pricing Fields */}
                {serviceForm.pricingType === "tiered" && (
                  <div className="grid gap-4 p-4 bg-green-900/20 border border-green-600/50 rounded-lg">
                    <h5 className="text-green-400 font-bold">📊 Tiered Pricing Configuration</h5>
                    <div className="grid grid-cols-2 gap-4">
                      <div className="grid gap-2">
                        <Label htmlFor="basePriceQuantity" className="text-white">Base Quantity Included</Label>
                        <Input
                          id="basePriceQuantity"
                          type="number"
                          min="1"
                          value={serviceForm.basePriceQuantity}
                          onChange={(e) => setServiceForm({ ...serviceForm, basePriceQuantity: parseInt(e.target.value) || 1 })}
                          className="bg-[#080d17] border-gold-dark/30"
                        />
                        <p className="text-xs text-offwhite/60">Items included in base price</p>
                      </div>
                      <div className="grid gap-2">
                        <Label htmlFor="additionalPricePerUnit" className="text-white">Additional Price Per Unit ($)</Label>
                        <Input
                          id="additionalPricePerUnit"
                          type="number"
                          step="0.01"
                          value={serviceForm.additionalPricePerUnit}
                          onChange={(e) => setServiceForm({ ...serviceForm, additionalPricePerUnit: parseFloat(e.target.value) || 0 })}
                          className="bg-[#080d17] border-gold-dark/30"
                        />
                        <p className="text-xs text-offwhite/60">Price for each additional unit</p>
                      </div>
                    </div>
                    <div className="bg-[#080d17] p-3 rounded border border-green-600/30">
                      <p className="text-sm text-green-400 font-medium">
                        Example: {formatPrice(serviceForm.price)} for first {serviceForm.basePriceQuantity} items, 
                        {formatPrice(serviceForm.additionalPricePerUnit)} per additional item
                      </p>
                    </div>
                  </div>
                )}

                <div className="grid gap-2">
                  <Label htmlFor="pricingDescription">Pricing Description (Optional)</Label>
                  <Textarea
                    id="pricingDescription"
                    placeholder="Explain your pricing structure to clients"
                    value={serviceForm.pricingDescription}
                    onChange={(e) => setServiceForm({ ...serviceForm, pricingDescription: e.target.value })}
                    className="bg-[#080d17] border-gold-dark/30"
                    rows={2}
                  />
                </div>
              </div>
            </div>

            <div className="flex gap-4">
              <Button 
                type="submit"
                className="bg-gold text-black hover:bg-gold-light"
                disabled={createServiceMutation.isPending || updateServiceMutation.isPending || !serviceForm.name || !serviceForm.description}
              >
                {(createServiceMutation.isPending || updateServiceMutation.isPending) && (
                  <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                )}
                {currentService ? "Update Service" : "Add Service"}
              </Button>

              {currentService && (
                <Button 
