import { db } from "./db";
import { services, serviceAddons } from "../shared/schema";
import { addons } from "../shared/addons-schema";
import { eq } from "drizzle-orm";

/**
 * This script sets up the service-addon relationships based on the specifications
 */

async function main() {
  try {
    console.log("Setting up service-addon relationships...");

    // Get all services and addons
    const allServices = await db.select().from(services);
    const allAddons = await db.select().from(addons);

    console.log("Available services:", allServices.map(s => `${s.id}: ${s.name}`));
    console.log("Available addons:", allAddons.map(a => `${a.id}: ${a.name}`));

    // Clear existing service-addon relationships
    await db.delete(serviceAddons);

    // Define the relationships based on the specifications
    const relationships = [
      // Visual Media Package (25) - suggested add-ons
      { serviceName: "Visual Media Package", addonName: "Construction Monitoring", enabled: true },
      { serviceName: "Visual Media Package", addonName: "Roof Inspection", enabled: true },

      // Terrain Mapping Package (26) - suggested add-ons  
      { serviceName: "Terrain Mapping Package", addonName: "Construction Monitoring", enabled: true },
      { serviceName: "Terrain Mapping Package", addonName: "Point Cloud & 3D Modeling", enabled: true },

      // Point Cloud & 3D Modeling (27) - suggested add-ons
      { serviceName: "Point Cloud & 3D Modeling", addonName: "Terrain Mapping Package", enabled: true },
      { serviceName: "Point Cloud & 3D Modeling", addonName: "Construction Monitoring", enabled: true },

      // Construction Monitoring (28) - suggested add-ons
      { serviceName: "Construction Monitoring", addonName: "Terrain Mapping Package", enabled: true },
      { serviceName: "Construction Monitoring", addonName: "Visual Media Package", enabled: true },

      // Aerial Photography (29) - suggested add-ons
      { serviceName: "Aerial Photography", addonName: "Aerial Videography", enabled: true },
      { serviceName: "Aerial Photography", addonName: "Visual Media Package", enabled: true },

      // Aerial Videography (30) - suggested add-ons
      { serviceName: "Aerial Videography", addonName: "Aerial Photography", enabled: true },
      { serviceName: "Aerial Videography", addonName: "Visual Media Package", enabled: true },

      // Precision Mapping Package (31) - suggested add-ons
      { serviceName: "Precision Mapping Package", addonName: "Terrain Analysis Package", enabled: true }, // This should be "Terrain Mapping Package"
      { serviceName: "Precision Mapping Package", addonName: "Construction Monitoring", enabled: true },
    ];

    // Create service-addon relationships
    for (const rel of relationships) {
      const service = allServices.find(s => s.name === rel.serviceName);

      // Try to find addon by name, checking both services (as addons) and dedicated addons
      let addon = allAddons.find(a => a.name === rel.addonName);

      // If not found in addons, check if it's a service that can be used as addon
      if (!addon) {
        const addonService = allServices.find(s => s.name === rel.addonName);
        if (addonService) {
          // Create addon entry for this service
          const [newAddon] = await db.insert(addons).values({
            name: addonService.name,
            description: addonService.description || `${addonService.name} add-on service`,
            tooltipDescription: addonService.tooltipDescription || `Add ${addonService.name} to your package`,
            price: Math.round(addonService.price * 0.5), // 50% off as specified
            pricingType: "fixed",
            percentage: 0,
            isActive: true,
            displayOrder: 999
          }).returning();
          addon = newAddon;
        }
      }

      if (service && addon) {
        await db.insert(serviceAddons).values({
          serviceId: service.id,
          addonId: addon.id,
          isEnabled: rel.enabled
        });
        console.log(`✓ Added addon "${addon.name}" to service "${service.name}"`);
      } else {
        console.log(`✗ Could not find service "${rel.serviceName}" or addon "${rel.addonName}"`);
      }
    }

    console.log("Service-addon relationships setup completed successfully!");

  } catch (error) {
    console.error("Error setting up service-addon relationships:", error);
    throw error;
  }
}

// Run setup if executed directly
main().catch(console.error);

export { main };

