// Client Form component
function ClientForm({ mode, client, onSuccess }: { 
  mode: 'create' | 'edit', 
  client: any, 
  onSuccess: () => void 
}) {
  const { toast } = useToast();

  // Debugging client form issues
  useEffect(() => {
    console.log(`ClientForm rendering - mode: ${mode}, client id: ${client?.id}`);
    return () => {
      console.log('ClientForm unmounting');
    };
  }, [mode, client]);

  // Define the form schema
  const formSchema = z.object({
    firstName: z.string().min(1, "First name is required"),
    lastName: z.string().min(1, "Last name is required"),
    email: z.string().email("Invalid email format"),
    phone: z.string().optional(),
    company: z.string().optional(),
    address: z.string().optional(),
    status: z.enum(["lead", "active", "inactive", "closed"]),
    source: z.string().optional(),
    notes: z.string().optional(),
  });

  // Initialize the form
  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: mode === 'edit' && client ? {
      firstName: client.firstName || "",
      lastName: client.lastName || "",
      email: client.email || "",
      phone: client.phone || "",
      company: client.company || "",
      address: client.address || "",
      status: client.status || "lead",
      source: client.source || "",
      notes: client.notes || ""
    } : {
      firstName: "",
      lastName: "",
      email: "",
      phone: "",
      company: "",
      address: "",
      status: "lead",
      source: "",
      notes: ""
    }
  });

  // Create client mutation
  const createClientMutation = useMutation({
    mutationFn: async (data: z.infer<typeof formSchema>) => {
      const res = await apiRequest("POST", "/api/crm/clients", data);
      return await res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/crm/clients"] });
      toast({
        title: "Client Created",
        description: "The client has been successfully created."
      });
      onSuccess();
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: `Failed to create client: ${error.message}`,
        variant: "destructive"
      });
    }
  });

  // Update client mutation
  const updateClientMutation = useMutation({
    mutationFn: async (data: z.infer<typeof formSchema>) => {
      const res = await apiRequest("PUT", `/api/crm/clients/${client.id}`, data);
      return await res.json();
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/crm/clients"] });
      toast({
        title: "Client Updated",
        description: "The client has been successfully updated."
      });
      onSuccess();
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: `Failed to update client: ${error.message}`,
        variant: "destructive"
      });
    }
  });

  // Handle form submission
  const onSubmit = (data: z.infer<typeof formSchema>) => {
    if (mode === 'create') {
      createClientMutation.mutate(data);
    } else {
      updateClientMutation.mutate(data);
    }
  };

  // Create a useEffect to reset form values when client or mode changes
  useEffect(() => {
    console.log('Form reset triggered by client/mode change');
    form.reset(
      mode === 'edit' && client ? {
        firstName: client.firstName || "",
        lastName: client.lastName || "",
        email: client.email || "",
        phone: client.phone || "",
        company: client.company || "",
        address: client.address || "",
        status: client.status || "lead",
        source: client.source || "",
        notes: client.notes || ""
      } : {
        firstName: "",
        lastName: "",
        email: "",
        phone: "",
        company: "",
        address: "",
        status: "lead",
        source: "",
        notes: ""
      }
    );
  }, [mode, client, form]);

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 p-4">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <FormField
            control={form.control}
            name="firstName"
            render={({ field }) => (
              <FormItem>
                <FormLabel className="text-offwhite">First Name</FormLabel>
                <FormControl>
                  <Input placeholder="First name" {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="lastName"
            render={({ field }) => (
              <FormItem>
                <FormLabel className="text-offwhite">Last Name</FormLabel>
                <FormControl>
                  <Input placeholder="Last name" {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="email"
            render={({ field }) => (
              <FormItem>
                <FormLabel className="text-offwhite">Email</FormLabel>
                <FormControl>
                  <Input placeholder="email@example.com" {...field} />
                </FormControl>
                <FormMessage />
              </FormItem>
            )}
          />

          <FormField
            control={form.control}
            name="phone"
            render={({ field }) => (
