// Client Files Upload component
function ClientFilesUpload({ client, onSuccess }: { client: any, onSuccess: () => void }) {
  const { toast } = useToast();
  const [fileType, setFileType] = useState<'photo' | 'video' | 'logo'>('photo');
  const [file, setFile] = useState<File | null>(null);
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = React.useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFile(e.target.files[0]);
    }
  };

  const handleUpload = async () => {
    if (!file || !client) return;

    setIsUploading(true);
    const formData = new FormData();
    formData.append('file', file);
    formData.append('clientId', client.id.toString());
    formData.append('fileType', fileType);

    try {
      const response = await fetch('/api/upload/client-files', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('Upload failed');
      }

      toast({
        title: "File Uploaded",
        description: "The file has been successfully uploaded."
      });

      // Reset the form
      setFile(null);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }

      onSuccess();
    } catch (error: any) {
      toast({
        title: "Upload Failed",
        description: error.message,
        variant: "destructive"
      });
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="space-y-4">
      <div className="grid grid-cols-4 gap-3">
        <Button 
          variant={fileType === 'photo' ? 'gold' : 'outline'} 
          className="w-full"
          onClick={() => setFileType('photo')}
        >
          Photo
        </Button>
        <Button 
          variant={fileType === 'video' ? 'gold' : 'outline'} 
          className="w-full"
          onClick={() => setFileType('video')}
        >
          Video
        </Button>

        <Button 
          variant={fileType === 'logo' ? 'gold' : 'outline'} 
          className="w-full"
          onClick={() => setFileType('logo')}
        >
          Logo
        </Button>
      </div>

      <div className="mt-4">
        <Label htmlFor="file-upload" className="text-offwhite">Upload File</Label>
        <div className="border border-dashed border-gold-dark/50 rounded-md p-6 flex flex-col items-center justify-center cursor-pointer hover:border-gold-light/50 transition-colors">
          <input 
            id="file-upload"
            type="file" 
            className="hidden"
            onChange={handleFileChange}
            ref={fileInputRef}
            accept={
              fileType === 'photo' ? 'image/jpeg,image/png,image/webp,image/gif' : 
              fileType === 'video' ? 'video/mp4,video/webm,video/quicktime' : 
              'image/jpeg,image/png,image/svg+xml'
            }
          />

          <label htmlFor="file-upload" className="flex flex-col items-center justify-center cursor-pointer">
            <Upload className="h-10 w-10 text-gold-light/60 mb-2" />
            <span className="text-offwhite text-sm font-medium">
              {file ? file.name : 'Click to select a file'}
            </span>
            <span className="text-offwhite/60 text-xs mt-1">
              {fileType === 'photo' ? 'JPG, PNG, WebP or GIF' : 
               fileType === 'video' ? 'MP4, WebM or MOV' : 
               'JPG, PNG or SVG for logos'}
            </span>
          </label>
        </div>
      </div>

      <DialogFooter>
        <Button
          variant="gold"
          onClick={handleUpload}
          disabled={!file || isUploading}
          className="w-full sm:w-auto"
        >
          {isUploading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
          Upload {fileType === 'photo' ? 'Photo' : fileType === 'video' ? 'Video' : 'Logo'}
        </Button>
      </DialogFooter>
    </div>
  );
}

// Client Credentials Form component
function ClientCredentialsForm({ client, onSuccess }: { client: any, onSuccess: () => void }) {
  const { toast } = useToast();

  // Define the form schema
  const formSchema = z.object({
    username: z.string().min(3, "Username must be at least 3 characters"),
    password: z.string().min(6, "Password must be at least 6 characters"),
    confirmPassword: z.string()
  }).refine(data => data.password === data.confirmPassword, {
    message: "Passwords do not match",
    path: ["confirmPassword"]
  });

  // Initialize the form
  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      username: client?.email?.split('@')[0] || "",
      password: "",
      confirmPassword: ""
    }
  });

  // Create user credentials mutation
  const createCredentialsMutation = useMutation({
    mutationFn: async (data: z.infer<typeof formSchema>) => {
      const res = await apiRequest("POST", "/api/crm/clients/credentials", {
        clientId: client.id,
        username: data.username,
        password: data.password,
        email: client.email
      });
      return await res.json();
    },
    onSuccess: () => {
      toast({
        title: "Credentials Created",
        description: "Login credentials have been created for this client."
      });
      onSuccess();
    },
    onError: (error: Error) => {
      toast({
        title: "Error",
        description: `Failed to create credentials: ${error.message}`,
        variant: "destructive"
      });
    }
  });

  // Handle form submission
  const onSubmit = (data: z.infer<typeof formSchema>) => {
    createCredentialsMutation.mutate(data);
  };

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
        <FormField
          control={form.control}
          name="username"
          render={({ field }) => (
            <FormItem>
              <FormLabel className="text-offwhite">Username</FormLabel>
              <FormControl>
                <Input placeholder="Username" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="password"
          render={({ field }) => (
            <FormItem>
              <FormLabel className="text-offwhite">Password</FormLabel>
              <FormControl>
                <Input type="password" placeholder="Password" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <FormField
          control={form.control}
          name="confirmPassword"
          render={({ field }) => (
            <FormItem>
              <FormLabel className="text-offwhite">Confirm Password</FormLabel>
              <FormControl>
                <Input type="password" placeholder="Confirm password" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />

        <DialogFooter>
          <Button
            type="submit"
            variant="gold"
            disabled={createCredentialsMutation.isPending}
            className="w-full sm:w-auto"
          >
            {createCredentialsMutation.isPending && (
              <Loader2 className="mr-2 h-4 w-4 animate-spin" />
            )}
            Create Login Credentials
          </Button>
        </DialogFooter>
      </form>
    </Form>
  );
}

