import { useQuery } from "@tanstack/react-query";
import { Testimonial } from "@shared/schema";
import { TestimonialCard } from "@/components/ui/testimonial-card";
import { Loader2 } from "lucide-react";

// Sample testimonials to display if no data is available from the API
const sampleTestimonials: Testimonial[] = [
  {
    id: 1,
    name: "Jennifer Miller",
    company: "Coastal Real Estate",
    content: "Apollo DroneWorks transformed our real estate listings with stunning aerial photography. Properties with their drone shots sell 30% faster than those without.",
    rating: 5,
    isApproved: true,
    createdAt: new Date()
  },
  {
    id: 2,
    name: "Robert Johnson",
    company: "Summit Construction",
    content: "The construction timelapse services provided us with invaluable progress documentation and helped us keep stakeholders informed throughout the project.",
    rating: 5,
    isApproved: true,
    createdAt: new Date()
  },
  {
    id: 3,
    name: "Sarah Parker",
    company: "Visionary Developers",
    content: "The 3D models they created of our development site helped us identify potential issues before they became problems. Exceptional service.",
    rating: 5,
    isApproved: true,
    createdAt: new Date()
  }
];

export function TestimonialsSection() {
  const {
    data: testimonials,
    isLoading,
    error,
  } = useQuery<Testimonial[]>({
    queryKey: ["/api/testimonials"],
  });

  // Use sample testimonials if no data is available
  // Convert createdAt from string to Date if needed
  const processedTestimonials = testimonials?.map(testimonial => ({
    ...testimonial,
    createdAt: testimonial.createdAt instanceof Date ? 
      testimonial.createdAt : 
      new Date(testimonial.createdAt)
  }));

  const displayTestimonials = processedTestimonials && processedTestimonials.length > 0 
    ? processedTestimonials 
    : sampleTestimonials;

  if (isLoading) {
    return (
      <section className="py-20 bg-[#0b111f]">
        <div className="container mx-auto px-4 text-center">
          <h2 className="text-3xl sm:text-4xl font-bold font-montserrat gold-text mb-4">Client Testimonials</h2>
          <p className="text-offwhite max-w-2xl mx-auto mb-10">
            See what our clients say about our drone services
          </p>
          <div className="flex justify-center">
            <Loader2 className="h-12 w-12 animate-spin text-gold" />
          </div>
        </div>
      </section>
    );
  }

  return (
    <section className="py-20 bg-[#0b111f]">
      <div className="container mx-auto px-4">
        <div className="text-center mb-16">
          <h2 className="text-3xl sm:text-4xl font-bold font-montserrat gold-text mb-4">Client Testimonials</h2>
          <p className="text-offwhite max-w-2xl mx-auto">See what our clients say about our drone services</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {displayTestimonials.map((testimonial) => (
            <TestimonialCard key={testimonial.id} testimonial={testimonial} />
          ))}
        </div>
      </div>
    </section>
  );
}

export default TestimonialsSection;

client/src/components/finance/expense-fo.content:
import { useState, useEffect } from "react";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import {
  Form,
  FormControl,
  FormDescription,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { CalendarIcon, Loader2, ReceiptIcon } from "lucide-react";
import { format } from "date-fns";
import { Calendar } from "@/components/ui/calendar";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { cn } from "@/lib/utils";

// Expense interface matching the database model
interface Expense {
  id: number;
  amount: number;
  date: string;
  description: string;
  categoryId: number;
  vendor: string;
  notes: string;
  isDeductible: boolean;
  paymentMethod: string;
  receiptUrl: string;
}

// Expense schema for validation
const expenseSchema = z.object({
  amount: z
    .string()
    .nonempty("Amount is required")
    .refine(
      (val) => !isNaN(parseFloat(val)) && parseFloat(val) > 0,
      "Amount must be a positive number"
    ),
  date: z.date({
    required_error: "Date is required",
    invalid_type_error: "Date format is invalid",
  }),
  description: z.string().default(""),
  categoryId: z.string().nonempty("Category is required"),
  vendor: z.string().default(""),
  notes: z.string().default(""),
  isDeductible: z.boolean().default(false),
  paymentMethod: z.string().default(""),
  receiptUrl: z.string().default(""),
});

// ExpenseFormProps interface
interface ExpenseFormProps {
  onClose: () => void;
  onSuccess?: () => void;
  expenseId?: number | null;
}

export default function ExpenseForm({
  onClose,
  onSuccess,
  expenseId = null,
}: ExpenseFormProps) {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [receiptFile, setReceiptFile] = useState<File | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Form definition
  const form = useForm<z.infer<typeof expenseSchema>>({
    resolver: zodResolver(expenseSchema),
    defaultValues: {
      amount: "",
      date: new Date(),
      description: "",
      categoryId: "",
      vendor: "",
      notes: "",
      isDeductible: false,
      paymentMethod: "",
      receiptUrl: "",
    },
  });

  // Fetch expense categories
  const { data: categories, isLoading: categoriesLoading } = useQuery({
    queryKey: ["/api/expense-categories"],
  });

  // Fetch expense data if editing
  const { data: expense, isLoading: expenseLoading } = useQuery<Expense | undefined>({
    queryKey: [`/api/expenses/${expenseId}`],
    enabled: expenseId !== null,
  });

  // Set form values when editing existing expense
  useEffect(() => {
    if (expense && !expenseLoading) {
      form.reset({
        amount: expense.amount.toString(),
        date: new Date(expense.date),
        description: expense.description || "",
        categoryId: expense.categoryId.toString(),
        vendor: expense.vendor || "",
        notes: expense.notes || "",
        isDeductible: expense.isDeductible || false,
        paymentMethod: expense.paymentMethod || "",
        receiptUrl: expense.receiptUrl || "",
      });
    }
  }, [expense, expenseLoading, form]);

  // Create expense mutation
  const createExpenseMutation = useMutation({
    mutationFn: async (formData: FormData) => {
      const response = await apiRequest("POST", "/api/expenses", formData, {
        'Content-Type': 'multipart/form-data',
      } as any);
      return await response.json();
    },
    onSuccess: () => {
      toast({
        title: "Success",
        description: "Expense added successfully",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/expenses"] });
      if (onSuccess) onSuccess();
      handleClose();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to add expense",
        variant: "destructive",
      });
      setIsSubmitting(false);
    },
  });

  // Update expense mutation
  const updateExpenseMutation = useMutation({
    mutationFn: async (formData: FormData) => {
      const response = await apiRequest("PATCH", `/api/expenses/${expenseId}`, formData, {
        'Content-Type': 'multipart/form-data',
      } as any);
      return await response.json();
    },
    onSuccess: () => {
      toast({
        title: "Success",
        description: "Expense updated successfully",
      });
      queryClient.invalidateQueries({ queryKey: ["/api/expenses"] });
      queryClient.invalidateQueries({ queryKey: [`/api/expenses/${expenseId}`] });
      if (onSuccess) onSuccess();
      handleClose();
    },
    onError: (error: any) => {
      toast({
        title: "Error",
        description: error.message || "Failed to update expense",
        variant: "destructive",
      });
      setIsSubmitting(false);
    },
  });

  // Form submission handler
  const onSubmit = async (values: z.infer<typeof expenseSchema>) => {
    setIsSubmitting(true);

    // Create FormData for file upload
    const formData = new FormData();

    // Add form fields to FormData
    formData.append("amount", values.amount);
    formData.append("date", values.date.toISOString().split("T")[0]);
    formData.append("categoryId", values.categoryId);
    formData.append("isDeductible", values.isDeductible.toString());

    // Add optional fields if they exist
    if (values.description) formData.append("description", values.description);
    if (values.vendor) formData.append("vendor", values.vendor);
    if (values.notes) formData.append("notes", values.notes);
    if (values.paymentMethod) formData.append("paymentMethod", values.paymentMethod);

    // Add receipt file if exists
    if (receiptFile) {
      formData.append("receipt", receiptFile);
    }

    // Determine if creating or updating
    if (expenseId) {
      updateExpenseMutation.mutate(formData);
    } else {
      createExpenseMutation.mutate(formData);
    }
  };

  // Handle form close
  const handleClose = () => {
    form.reset();
    setReceiptFile(null);
    setIsSubmitting(false);
    onClose();
  };

  // Handle file input change
  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (event.target.files && event.target.files[0]) {
      setReceiptFile(event.target.files[0]);
    }
  };

  return (
    <div className="border rounded-lg p-6 bg-white">
      <div className="mb-6">
        <h2 className="text-xl font-semibold mb-2">
          {expenseId ? "Edit Expense" : "Add New Expense"}
        </h2>
        <p className="text-sm text-muted-foreground">
          {expenseId
            ? "Update expense details"
            : "Enter the details of your new expense"}
        </p>
      </div>

        <Form {...form}>
          <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              {/* Amount Field */}
              <FormField
                control={form.control}
                name="amount"
                render={({ field }) => (
                  <FormItem>
                    <FormLabel>Amount*</FormLabel>
                    <FormControl>
                      <div className="relative">
                        <span className="absolute left-3 top-2.5">$</span>
                        <Input
                          placeholder="0.00"
                          type="number"
                          step="0.01"
                          min="0.01"
                          className="pl-8"
                          {...field}
                        />
                      </div>
                    </FormControl>
                    <FormMessage />
                  </FormItem>
                )}
              />

              {/* Date Field */}
              <FormField
                control={form.control}
                name="date"
                render={({ field }) => (
                  <FormItem className="flex flex-col">
                    <FormLabel>Date*</FormLabel>
                    <Popover>
                      <PopoverTrigger asChild>
                        <FormControl>
                          <Button
                            variant="outline"
                            className={cn(
                              "pl-3 text-left font-normal",
                              !field.value && "text-muted-foreground"
                            )}
                          >
                            {field.value ? (
                              format(field.value, "MMM dd, yyyy")
                            ) : (
                              <span>Select date</span>
                            )}
                            <CalendarIcon className="ml-auto h-4 w-4 opacity-50" />
                          </Button>
                        </FormControl>
                      </PopoverTrigger>
                      <PopoverContent className="w-auto p-0" align="start">
                        <Calendar
                          mode="single"
                          selected={field.value}
                          onSelect={field.onChange}
                          disabled={(date) => date > new Date()}
                          initialFocus
                        />
                      </PopoverContent>
                    </Popover>
                    <FormMessage />
                  </FormItem>
                )}
              />
            </div>

            {/* Category Field */}
            <FormField
              control={form.control}
              name="categoryId"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Category*</FormLabel>
                  <Select
                    onValueChange={field.onChange}
                    defaultValue={field.value}
                    value={field.value}
                  >
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Select a category" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      {categoriesLoading ? (
                        <div className="flex items-center justify-center py-2">
                          <Loader2 className="h-4 w-4 animate-spin" />
                          <span className="ml-2">Loading categories...</span>
                        </div>
                      ) : (
                        Array.isArray(categories) && categories.map((category) => (
                          <SelectItem
                            key={category.id}
                            value={category.id.toString()}
                          >
                            {category.name}
                          </SelectItem>
                        ))
                      )}
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Description Field */}
            <FormField
              control={form.control}
              name="description"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Description</FormLabel>
                  <FormControl>
                    <Input 
                      placeholder="Brief description of the expense" 
                      {...field}
                      value={field.value || ""} 
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Vendor Field */}
            <FormField
              control={form.control}
              name="vendor"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Vendor/Merchant</FormLabel>
                  <FormControl>
                    <Input 
                      placeholder="Where was this purchased from?" 
                      {...field} 
                      value={field.value || ""} 
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Payment Method Field */}
            <FormField
              control={form.control}
              name="paymentMethod"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Payment Method</FormLabel>
                  <Select
                    onValueChange={field.onChange}
                    defaultValue={field.value || ""}
                    value={field.value || ""}
                  >
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="How was this paid?" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      <SelectItem value="credit_card">Credit Card</SelectItem>
                      <SelectItem value="debit_card">Debit Card</SelectItem>
                      <SelectItem value="cash">Cash</SelectItem>
                      <SelectItem value="bank_transfer">Bank Transfer</SelectItem>
                      <SelectItem value="check">Check</SelectItem>
                      <SelectItem value="paypal">PayPal</SelectItem>
                      <SelectItem value="other">Other</SelectItem>
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )}
            />

            {/* Tax Deductible Checkbox */}
            <FormField
              control={form.control}
              name="isDeductible"
              render={({ field }) => (
                <FormItem className="flex flex-row items-start space-x-3 space-y-0 rounded-md border p-4">
                  <FormControl>
                    <Checkbox
                      checked={field.value}
                      onCheckedChange={field.onChange}
                    />
                  </FormControl>
                  <div className="space-y-1 leading-none">
                    <FormLabel>Tax Deductible</FormLabel>
                    <FormDescription>
                      Mark if this expense is tax deductible for business purposes
                    </FormDescription>
                  </div>
                </FormItem>
              )}
            />

            {/* Receipt Upload */}
            <div className="rounded-md border p-4">
              <FormLabel className="block mb-2">Receipt Upload</FormLabel>
              <div className="flex items-center space-x-2">
                <Input
                  type="file"
                  accept=".jpg,.jpeg,.png,.pdf"
                  onChange={handleFileChange}
                  className="flex-1"
                />
                {receiptFile && (
                  <p className="text-sm text-muted-foreground truncate">
                    {receiptFile.name}
                  </p>
                )}
              </div>
              {!receiptFile && expense?.receiptUrl && (
                <div className="flex items-center mt-2 text-sm text-blue-600">
                  <ReceiptIcon className="h-4 w-4 mr-1" />
                  <a
                    href={expense.receiptUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                  >
                    View existing receipt
                  </a>
                </div>
              )}
              <FormDescription className="mt-2">
                Upload a photo or scan of your receipt (max 5MB)
              </FormDescription>
            </div>

            {/* Notes Field */}
            <FormField
              control={form.control}
              name="notes"
              render={({ field }) => (
                <FormItem>
                  <FormLabel>Notes</FormLabel>
                  <FormControl>
                    <Textarea
                      placeholder="Additional notes about this expense"
                      className="resize-none"
                      {...field}
                      value={field.value || ""}
                    />
                  </FormControl>
                  <FormMessage />
                </FormItem>
              )}
            />

            <div className="flex justify-end gap-2 mt-6">
              <Button
                type="button"
                variant="outline"
                onClick={handleClose}
                disabled={isSubmitting}
              >
                Cancel
              </Button>
              <Button type="submit" disabled={isSubmitting}>
                {isSubmitting ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    {expenseId ? "Updating..." : "Saving..."}
                  </>
                ) : (
                  <>{expenseId ? "Update" : "Save"}</>
                )}
              </Button>
            </div>
          </form>
        </Form>
    </div>
  );
}

