import type { Express } from "express";
import { z } from "zod";
import { storage } from "../storage";
import {
  insertDepartmentSchema,
  insertEmployeeSchema,
  insertPayrollPeriodSchema,
  insertPayrollEntrySchema,
  insertTimeEntrySchema,
} from "@shared/schema";

// Middleware to check if user is authenticated
const isAuthenticated = (req: any, res: any, next: any) => {
  if (req.isAuthenticated()) {
    return next();
  }
  res.status(401).json({ message: "Unauthorized" });
};

// Middleware to check if user is admin
const isAdmin = (req: any, res: any, next: any) => {
  if (req.isAuthenticated() && req.user.isAdmin) {
    return next();
  }
  res.status(403).json({ message: "Forbidden" });
};

export function registerPayrollRoutes(app: Express) {
  // Department Routes
  app.get("/api/payroll/departments", isAdmin, async (req, res) => {
    try {
      const departments = await storage.getDepartments();
      res.json(departments);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/payroll/departments/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const department = await storage.getDepartment(id);

      if (!department) {
        return res.status(404).json({ message: "Department not found" });
      }

      res.json(department);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post("/api/payroll/departments", isAdmin, async (req, res) => {
    try {
      const validatedData = insertDepartmentSchema.parse(req.body);
      const department = await storage.createDepartment(validatedData);
      res.status(201).json(department);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.patch("/api/payroll/departments/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const validatedData = insertDepartmentSchema.partial().parse(req.body);
      const department = await storage.updateDepartment(id, validatedData);

      if (!department) {
        return res.status(404).json({ message: "Department not found" });
      }

      res.json(department);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.delete("/api/payroll/departments/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const success = await storage.deleteDepartment(id);

      if (!success) {
        return res.status(404).json({ message: "Department not found" });
      }

      res.status(204).send();
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Employee Routes
  app.get("/api/payroll/employees", isAdmin, async (req, res) => {
    try {
      const employees = await storage.getEmployees();
      res.json(employees);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/payroll/employees/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const employee = await storage.getEmployee(id);

      if (!employee) {
        return res.status(404).json({ message: "Employee not found" });
      }

      res.json(employee);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post("/api/payroll/employees", isAdmin, async (req, res) => {
    try {
      const validatedData = insertEmployeeSchema.parse(req.body);
      const employee = await storage.createEmployee(validatedData);
      res.status(201).json(employee);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.patch("/api/payroll/employees/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const validatedData = insertEmployeeSchema.partial().parse(req.body);
      const employee = await storage.updateEmployee(id, validatedData);

      if (!employee) {
        return res.status(404).json({ message: "Employee not found" });
      }

      res.json(employee);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.delete("/api/payroll/employees/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const success = await storage.deleteEmployee(id);

      if (!success) {
        return res.status(404).json({ message: "Employee not found" });
      }

      res.status(204).send();
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Payroll Period Routes
  app.get("/api/payroll/periods", isAdmin, async (req, res) => {
    try {
      const periods = await storage.getPayrollPeriods();
      res.json(periods);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/payroll/periods/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const period = await storage.getPayrollPeriod(id);

      if (!period) {
        return res.status(404).json({ message: "Payroll period not found" });
      }

      res.json(period);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post("/api/payroll/periods", isAdmin, async (req, res) => {
    try {
      const validatedData = insertPayrollPeriodSchema.parse({
        ...req.body,
        status: req.body.status || "draft", // Default status
      });
      const period = await storage.createPayrollPeriod(validatedData);
      res.status(201).json(period);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.post("/api/payroll/periods/:id/process", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const period = await storage.getPayrollPeriod(id);

      if (!period) {
        return res.status(404).json({ message: "Payroll period not found" });
      }

      if (period.status !== "draft") {
        return res.status(400).json({ 
          message: "Only periods in draft status can be processed" 
        });
      }

      // Update period status to processing
      const updatedPeriod = await storage.updatePayrollPeriod(id, {
        status: "processing",
      });

      // Calculate and create payroll entries
      // This would normally be a more complex process involving gathering time entries
      // and calculating pay, taxes, etc.
      const employees = await storage.getEmployees();
      const timeEntries = await storage.getTimeEntriesByPeriod(id);

      // Group time entries by employee
      const entriesByEmployee: {[key: number]: any[]} = {};
      timeEntries.forEach(entry => {
        if (entry.employeeId) {
          if (!entriesByEmployee[entry.employeeId]) {
            entriesByEmployee[entry.employeeId] = [];
          }
          entriesByEmployee[entry.employeeId].push(entry);
        }
      });

      // Create payroll entries for each employee
      for (const employeeId in entriesByEmployee) {
        const employee = employees.find(e => e.id === parseInt(employeeId));
        if (!employee) continue;

        const entries = entriesByEmployee[parseInt(employeeId)];
        const totalHours = entries.reduce((sum, entry) => sum + parseFloat(entry.hoursWorked), 0);

        // Simple payroll calculation for example
        const regularHoursStr = totalHours.toString();
        const payRate = parseFloat(employee.payRate);
        const grossPay = (totalHours * payRate).toFixed(2);
        const taxRate = 0.2; // 20% tax rate for example
        const taxAmount = (parseFloat(grossPay) * taxRate).toFixed(2);
        const netPay = (parseFloat(grossPay) - parseFloat(taxAmount)).toFixed(2);

        await storage.createPayrollEntry({
          payrollPeriodId: id,
          employeeId: parseInt(employeeId),
          regularHours: regularHoursStr,
          overtimeHours: "0",
          grossPay,
          taxAmount,
          netPay,
          payRate: employee.payRate,
        });
      }

      res.json(updatedPeriod);
    } catch (error: any) {
      console.error("Payroll processing error:", error);
      res.status(500).json({ message: error.message });
    }
  });

  app.post("/api/payroll/periods/:id/complete", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const period = await storage.getPayrollPeriod(id);

      if (!period) {
        return res.status(404).json({ message: "Payroll period not found" });
      }

      if (period.status !== "processing") {
        return res.status(400).json({ 
          message: "Only periods in processing status can be completed" 
        });
      }

      // Update period status to completed
      const updatedPeriod = await storage.updatePayrollPeriod(id, {
        status: "completed",
      });

      res.json(updatedPeriod);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.patch("/api/payroll/periods/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const period = await storage.getPayrollPeriod(id);

      if (!period) {
        return res.status(404).json({ message: "Payroll period not found" });
      }

      if (period.status !== "draft" && req.body.status === undefined) {
        return res.status(400).json({ 
          message: "Only periods in draft status can be modified" 
        });
      }

      const validatedData = insertPayrollPeriodSchema.partial().parse(req.body);
      const updatedPeriod = await storage.updatePayrollPeriod(id, validatedData);

      res.json(updatedPeriod);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.delete("/api/payroll/periods/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const period = await storage.getPayrollPeriod(id);

      if (!period) {
        return res.status(404).json({ message: "Payroll period not found" });
      }

      if (period.status !== "draft") {
        return res.status(400).json({ 
          message: "Only periods in draft status can be deleted" 
        });
      }

      const success = await storage.deletePayrollPeriod(id);

      res.status(204).send();
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Get entries for a specific payroll period
  app.get("/api/payroll/periods/:id/entries", isAdmin, async (req, res) => {
    try {
      const periodId = parseInt(req.params.id);
      const entries = await storage.getPayrollEntriesByPeriod(periodId);
      res.json(entries);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Payroll Entry Routes
  app.get("/api/payroll/entries", isAdmin, async (req, res) => {
    try {
      const entries = await storage.getPayrollEntries();
      res.json(entries);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/payroll/entries/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const entry = await storage.getPayrollEntry(id);

      if (!entry) {
        return res.status(404).json({ message: "Payroll entry not found" });
      }

      res.json(entry);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post("/api/payroll/entries", isAdmin, async (req, res) => {
    try {
      const validatedData = insertPayrollEntrySchema.parse(req.body);
      const entry = await storage.createPayrollEntry(validatedData);
      res.status(201).json(entry);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.patch("/api/payroll/entries/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      // First check if period is completed
      const entry = await storage.getPayrollEntry(id);

      if (!entry) {
        return res.status(404).json({ message: "Payroll entry not found" });
      }

      if (entry.payrollPeriodId) {
        const period = await storage.getPayrollPeriod(entry.payrollPeriodId);
        if (period && period.status === "completed") {
          return res.status(400).json({ 
            message: "Cannot modify entries in completed payroll periods" 
          });
        }
      }

      const validatedData = insertPayrollEntrySchema.partial().parse(req.body);
      const updatedEntry = await storage.updatePayrollEntry(id, validatedData);

      res.json(updatedEntry);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.delete("/api/payroll/entries/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      // First check if period is completed
      const entry = await storage.getPayrollEntry(id);

      if (!entry) {
        return res.status(404).json({ message: "Payroll entry not found" });
      }

      if (entry.payrollPeriodId) {
        const period = await storage.getPayrollPeriod(entry.payrollPeriodId);
        if (period && period.status === "completed") {
          return res.status(400).json({ 
            message: "Cannot delete entries in completed payroll periods" 
          });
        }
      }

      const success = await storage.deletePayrollEntry(id);

      res.status(204).send();
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Time Entry Routes
  app.get("/api/payroll/time-entries", isAdmin, async (req, res) => {
    try {
      const timeEntries = await storage.getTimeEntries();
      res.json(timeEntries);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/payroll/employees/:id/time-entries", isAdmin, async (req, res) => {
    try {
      const employeeId = parseInt(req.params.id);
      const timeEntries = await storage.getTimeEntriesByEmployee(employeeId);
      res.json(timeEntries);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/payroll/periods/:id/time-entries", isAdmin, async (req, res) => {
    try {
      const periodId = parseInt(req.params.id);

      if (!periodId || isNaN(periodId)) {
        return res.status(400).json({ message: "Invalid period ID" });
      }

      const period = await storage.getPayrollPeriod(periodId);
      if (!period) {
        return res.status(404).json({ message: "Payroll period not found" });
      }

      const entries = await storage.getTimeEntriesByPeriod(periodId);

      // Format the entries for consistent response
      const formattedEntries = entries.map(entry => ({
        ...entry,
        // Ensure dates are in string format for API response if they're Date objects
        entryDate: entry.entryDate instanceof Date 
          ? entry.entryDate.toISOString().split('T')[0]
          : entry.entryDate,
        approvedAt: entry.approvedAt instanceof Date 
          ? entry.approvedAt.toISOString()
          : entry.approvedAt
      }));

      res.json(formattedEntries);
    } catch (error: any) {
      console.error("Error fetching time entries by period:", error);
      res.status(500).json({ message: error.message });
    }
  });

  app.get("/api/payroll/time-entries/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const timeEntry = await storage.getTimeEntry(id);

      if (!timeEntry) {
        return res.status(404).json({ message: "Time entry not found" });
      }

      res.json(timeEntry);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post("/api/payroll/time-entries", isAdmin, async (req, res) => {
    try {
      // Process entryDate if it's a string
      let timeEntryData = {
        ...req.body,
        billable: req.body.billable !== undefined ? req.body.billable : false,
        approved: req.body.approved !== undefined ? req.body.approved : false,
      };

      const validatedData = insertTimeEntrySchema.parse(timeEntryData);

      // If entry is approved, set approvedBy and approvedAt
      if (validatedData.approved && req.user) {
        validatedData.approvedBy = req.user.id;
        validatedData.approvedAt = new Date();
      }

      const timeEntry = await storage.createTimeEntry(validatedData);
      res.status(201).json(timeEntry);
    } catch (error: any) {
      console.error("Time entry creation error:", error);
      res.status(400).json({ message: error.message });
    }
  });

  app.patch("/api/payroll/time-entries/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const timeEntry = await storage.getTimeEntry(id);

      if (!timeEntry) {
        return res.status(404).json({ message: "Time entry not found" });
      }

      const validatedData = insertTimeEntrySchema.partial().parse(req.body);

      // If changing approved status
      if (validatedData.approved !== undefined && 
          validatedData.approved !== timeEntry.approved) {
        if (validatedData.approved) {
          // If approving, set approvedBy and approvedAt
          validatedData.approvedBy = req.user.id;
          validatedData.approvedAt = new Date();
        } else {
          // If revoking approval, clear approvedBy and approvedAt
          validatedData.approvedBy = null;
          validatedData.approvedAt = null;
        }
      }

      const updatedTimeEntry = await storage.updateTimeEntry(id, validatedData);

      res.json(updatedTimeEntry);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.delete("/api/payroll/time-entries/:id", isAdmin, async (req, res) => {
    try {
      const id = parseInt(req.params.id);
      const timeEntry = await storage.getTimeEntry(id);

      if (!timeEntry) {
        return res.status(404).json({ message: "Time entry not found" });
      }

      const success = await storage.deleteTimeEntry(id);

      res.status(204).send();
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });
}

shared/schema.ts.content:
import { pgTable, text, serial, integer, boolean, timestamp, json, numeric, decimal, jsonb, date, real, varchar, time, unique } from "drizzle-orm/pg-core";
import { relations } from "drizzle-orm";
import { createInsertSchema } from "drizzle-zod";
import { z } from "zod";

export const users = pgTable("users", {
  id: serial("id").primaryKey(),
  username: text("username").notNull().unique(),
  password: text("password").notNull(),
  email: text("email").notNull().unique(),
  firstName: text("first_name"),
  lastName: text("last_name"),
  phone: text("phone"),
  isAdmin: boolean("is_admin").default(false).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const services = pgTable("services", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  description: text("description").notNull(),
  tooltipDescription: text("tooltip_description"), // Short description for tooltips
  price: integer("price").notNull(),
  imageUrl: text("image_url").notNull(),
  videoUrl: text("video_url"), // Optional video for the service
  videoPlayback: text("video_playback").default("hover"), // "autoplay", "hover", "click"
  images: jsonb("images").$type<string[]>().default([]), // Array of image URLs for carousel
  videos: jsonb("videos").$type<string[]>().default([]), // Array of video URLs for carousel
  features: jsonb("features").$type<string[]>().default([]),
  keywords: jsonb("keywords").$type<string[]>().default([]),
  displayOrder: integer("display_order").default(999),
  classification: text("classification").default("Revenue Generation"), // "Revenue Generation" or "Overhead Reduction"
  aboutServiceContent: text("about_service_content"), // Add content for "About This Service" section
  whatsIncludedContent: jsonb("whats_included_content").$type<string[]>().default([]), // Add content for "What's Included" section
  possibilities: jsonb("possibilities").$type<Array<{title: string, description: string}>>().default([]), // Possibilities section with title:description format
  processSteps: jsonb("process_steps").$type<Array<{title: string, description: string}>>().default([]), // Process step details for service page
  // Subscription-related fields
  isSubscription: boolean("is_subscription").default(false),
  weeklySubscriptionEnabled: boolean("weekly_subscription_enabled").default(false),
  weeklyPrice: integer("weekly_price").default(0), // Price for weekly subscription
  weeklyPriceType: text("weekly_price_type").default("fixed"), // "fixed" or "percentage"
  weeklyPercentage: integer("weekly_percentage").default(0), // Percentage of base price
  biWeeklySubscriptionEnabled: boolean("bi_weekly_subscription_enabled").default(false),
  biWeeklyPrice: integer("bi_weekly_price").default(0), // Price for bi-weekly subscription
  biWeeklyPriceType: text("bi_weekly_price_type").default("fixed"), // "fixed" or "percentage"
  biWeeklyPercentage: integer("bi_weekly_percentage").default(0), // Percentage of base price
  monthlySubscriptionEnabled: boolean("monthly_subscription_enabled").default(false),
  monthlyPrice: integer("monthly_price").default(0), // Price for monthly subscription
  monthlyPriceType: text("monthly_price_type").default("fixed"), // "fixed" or "percentage"
  monthlyPercentage: integer("monthly_percentage").default(0), // Percentage of base price
  billingFrequency: text("billing_frequency").default("monthly"), // Comma-separated: "weekly", "monthly", "biweekly", etc.
  frequencyDetails: text("frequency_details"), // E.g., "1 update per week", "2 visits per month", etc.
  // Flexible pricing options
  pricingType: text("pricing_type").default("flat"), // "flat", "tiered", "per_unit", "range_based"
  unitType: text("unit_type").default("unit"), // "acre", "square_foot", "unit" - for per_unit pricing
  basePriceQuantity: integer("base_price_quantity").default(1), // Quantity included in base price
  additionalPricePerUnit: integer("additional_price_per_unit").default(0), // Price per additional unit
  pricingDescription: text("pricing_description"), // Human-readable pricing explanation
  priceRanges: jsonb("price_ranges").$type<Array<{
    minValue: number;
    maxValue?: number;
    minPrice: number;
    maxPrice?: number;
    label: string;
  }>>().default([]), // For range-based pricing
  // Tiered pricing system
  pricingTiers: jsonb("pricing_tiers").$type<Array<{
    name?: string;
    minQuantity?: number;
    maxQuantity?: number;
    exactQuantity?: number; // For specific quantity pricing
    quantityType: "range" | "exact"; // Whether this tier is for a range or exact quantity
    price: number;
    priceType: "fixed" | "range" | "quote";
    minPrice?: number;
    maxPrice?: number;
    quantityUnit?: string;
    description?: string;
  }>>().default([]), // For tiered pricing
  // Bundle pricing system
  bundleDiscountPercentage: integer("bundle_discount_percentage").default(0), // Percentage discount when bundled with other services
  availableAddOns: jsonb("available_add_ons").$type<number[]>().default([]), // Array of service IDs that can be bundled with this service
  // Deprecated fields - will be replaced by serviceAddons table
  isAvailableAsAddon: boolean("is_available_as_addon").default(false), 
  addonPrice: integer("addon_price").default(0),
  // Service-specific bundle configurations for pricing relationships
  bundleConfigurations: jsonb("bundle_configurations").$type<Array<{
    serviceId: number;
    discountPercentage?: number;
    customPrice?: number;
  }>>().default([]), // Array of service-specific bundle pricing rules
  // Public visibility control
  hideFromServicesPage: boolean("hide_from_services_page").default(false), // Hide from public services page (for add-on only services)
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

// New table for service add-ons
export const serviceAddons = pgTable("service_addons", {
  id: serial("id").primaryKey(),
  serviceId: integer("service_id").notNull().references(() => services.id, { onDelete: 'cascade' }),
  addonId: integer("addon_id").references(() => services.id, { onDelete: 'cascade' }), // Reference to the addon service
  isEnabled: boolean("is_enabled").notNull().default(false),
  customPrice: integer("custom_price"), // Custom price override
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

// New table for individual service bundle percentages
export const serviceBundleDiscounts = pgTable("service_bundle_discounts", {
  id: serial("id").primaryKey(),
  primaryServiceId: integer("primary_service_id").notNull().references(() => services.id, { onDelete: 'cascade' }),
  secondaryServiceId: integer("secondary_service_id").notNull().references(() => services.id, { onDelete: 'cascade' }),
  discountPercentage: integer("discount_percentage").notNull().default(0), // Percentage discount for this specific bundle
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

// New table for service subscription tiers
export const subscriptionTiers = pgTable("subscription_tiers", {
  id: serial("id").primaryKey(),
  serviceId: integer("service_id").notNull().references(() => services.id, { onDelete: 'cascade' }),
  name: text("name").notNull(), // e.g., "Basic", "Standard", "Premium"
  description: text("description"), // Detailed description of this tier
  price: integer("price").notNull().default(0), // Price in cents
  frequency: text("frequency").notNull().default("monthly"), // "weekly", "monthly", "quarterly", "annually"
  features: json("features").$type<string[]>().default([]), // Features specific to this tier
  isPopular: boolean("is_popular").default(false), // Highlight as a popular choice
  displayOrder: integer("display_order").default(100), // For ordering tiers on the page
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

// New table for enhanced pricing tiers with quantity and price ranges
export const pricingTiers = pgTable("pricing_tiers", {
  id: serial("id").primaryKey(),
  serviceId: integer("service_id").notNull().references(() => services.id, { onDelete: 'cascade' }),
  name: text("name").notNull(), // e.g., "Small Package", "Medium Package", "Large Package"
  description: text("description"), // Detailed description of this tier
  // Quantity range support
  minQuantity: integer("min_quantity").notNull().default(1), // Minimum quantity for this tier
  maxQuantity: integer("max_quantity"), // Maximum quantity for this tier (null for unlimited)
  quantityUnit: text("quantity_unit").default("items"), // "images", "acres", "square_feet", "items", etc.
  // Price range support
  minPrice: integer("min_price").notNull().default(0), // Minimum price in cents
  maxPrice: integer("max_price"), // Maximum price in cents (null if fixed price)
  priceType: text("price_type").default("fixed"), // "fixed", "range", "quote"
  // Additional pricing details
  priceDescription: text("price_description"), // Human-readable pricing explanation
  features: json("features").$type<string[]>().default([]), // Features specific to this tier
  isPopular: boolean("is_popular").default(false), // Highlight as a popular choice
  displayOrder: integer("display_order").default(100), // For ordering tiers on the page
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const subscriptionTiersRelations = relations(subscriptionTiers, ({ one }) => ({
  service: one(services, {
    fields: [subscriptionTiers.serviceId],
    references: [services.id]
  })
}));

export const pricingTiersRelations = relations(pricingTiers, ({ one }) => ({
  service: one(services, {
    fields: [pricingTiers.serviceId],
    references: [services.id]
  })
}));

export const insertSubscriptionTierSchema = createInsertSchema(subscriptionTiers).pick({
  serviceId: true,
  name: true,
  description: true,
  price: true,
  frequency: true,
  features: true,
  isPopular: true,
  displayOrder: true,
});

export const insertPricingTierSchema = createInsertSchema(pricingTiers).pick({
  serviceId: true,
  name: true,
  description: true,
  minQuantity: true,
  maxQuantity: true,
  quantityUnit: true,
  minPrice: true,
  maxPrice: true,
  priceType: true,
  priceDescription: true,
  features: true,
  isPopular: true,
  displayOrder: true,
});

export type InsertPricingTier = typeof insertPricingTierSchema._output;
export type PricingTier = typeof pricingTiers.$inferSelect;

export const bookings = pgTable("bookings", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull(),
  serviceId: integer("service_id").notNull(), // Primary service ID
  date: timestamp("date").notNull(),
  status: text("status").notNull().default("pending"),
  address: text("address"),
  notes: text("notes"),
  totalPrice: integer("total_price").notNull(),
  paymentStatus: text("payment_status").notNull().default("unpaid"),
  paymentIntentId: text("payment_intent_id"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  projectId: integer("project_id"),
  projectName: text("project_name"),
  selectedServices: json("selected_services").$type<number[]>().default([]), // Store all selected service IDs
});

export const galleries = pgTable("galleries", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull(),
  bookingId: integer("booking_id"),
  name: text("name").notNull(),
  type: text("type").notNull(),
  url: text("url").notNull(),
  isPublic: boolean("is_public").default(false).notNull(),
  category: text("category").default("uncategorized"),
  tags: json("tags").$type<string[]>().default([]),
  description: text("description"),
  publicDescription: text("public_description"),
  thumbnail: text("thumbnail"),
  keywords: json("keywords").$type<string[]>().default([]),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const beforeAfterImages = pgTable("before_after_images", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  description: text("description"),
  beforeImageUrl: text("before_image_url").notNull(),
  afterImageUrl: text("after_image_url").notNull(),
  isPublic: boolean("is_public").default(true).notNull(),
  serviceId: integer("service_id"),
  keywords: json("keywords").$type<string[]>().default([]),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const blogPosts = pgTable("blog_posts", {
  id: serial("id").primaryKey(),
  title: text("title").notNull(),
  content: text("content").notNull(),
  imageUrl: text("image_url").notNull(),
  category: text("category").notNull(),
  excerpt: text("excerpt").notNull(),
  keywords: json("keywords").$type<string[]>().default([]),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const testimonials = pgTable("testimonials", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  company: text("company"),
  content: text("content").notNull(),
  rating: integer("rating").notNull(),
  isApproved: boolean("is_approved").default(false).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

export const contactMessages = pgTable("contact_messages", {
  id: serial("id").primaryKey(),
  name: text("name").notNull(),
  email: text("email").notNull(),
  phone: text("phone"),
  message: text("message").notNull(),
  status: text("status").default("unread").notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
});

// Business config for persistent business costs
export const businessConfig = pgTable("business_config", {
  id: serial("id").primaryKey(),
  name: text("name").notNull().default("default"),
  depreciableAssets: numeric("depreciable_assets").default("10000"),
  targetMissionsPerWeek: numeric("target_missions_per_week").default("3"),
  targetReinvestmentYears: numeric("target_reinvestment_years").default("2"),
  yearlyAdvertisementCost: numeric("yearly_advertisement_cost").default("2000"),
  yearlyInsuranceCost: numeric("yearly_insurance_cost").default("1500"),
  yearlySoftwareSubscriptionsCost: numeric("yearly_software_subscriptions_cost").default("0"),
  taxPercentage: numeric("tax_percentage").default("8.25"),
  customCosts: json("custom_costs").$type<{name: string, yearlyCost: number}[]>().default([]),
  // Per-mission overhead costs
  equipmentDepreciation: numeric("equipment_depreciation"),
  batteryUsage: numeric("battery_usage"),
  insurance: numeric("insurance"),
  transportation: numeric("transportation"),
  // Auto mode settings for analytics-driven cost calculations
  useAutoEquipmentDepreciation: boolean("use_auto_equipment_depreciation").default(false),
  useAutoBatteryUsage: boolean("use_auto_battery_usage").default(false),
  useAutoInsurance: boolean("use_auto_insurance").default(false),
  useAutoTransportation: boolean("use_auto_transportation").default(false),
  useAutoTaxPercentage: boolean("use_auto_tax_percentage").default(false),
  // Auto-calculated values from analytics
  autoEquipmentDepreciation: numeric("auto_equipment_depreciation"),
  autoBatteryUsage: numeric("auto_battery_usage"),
  autoInsurance: numeric("auto_insurance"),
  autoTransportation: numeric("auto_transportation"),
  autoTaxPercentage: numeric("auto_tax_percentage"),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

// Social media connections and auth tokens
export const socialMediaAccounts = pgTable("social_media_accounts", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").references(() => users.id, { onDelete: 'cascade' }).notNull(),
  platform: text("platform").notNull(), // 'facebook', 'instagram', 'twitter'
  accountId: text("account_id").notNull(),
  accountName: text("account_name").notNull(),
  accessToken: text("access_token"),
  refreshToken: text("refresh_token"),
  tokenExpiry: timestamp("token_expiry"),
  connected: boolean("connected").default(true).notNull(),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

// Social media posts
export const socialPosts = pgTable("social_posts", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").references(() => users.id, { onDelete: 'cascade' }).notNull(),
  content: text("content").notNull(),
  mediaUrl: text("media_url"),
  mediaType: text("media_type"), // 'image', 'video', null for text-only
  keywords: json("keywords").$type<string[]>().default([]),
  scheduledFor: timestamp("scheduled_for"),
  published: boolean("published").default(false).notNull(),
  publishedTo: jsonb("published_to").$type<string[]>().default([]),
  createdAt: timestamp("created_at").defaultNow().notNull(),
  updatedAt: timestamp("updated_at").defaultNow().notNull(),
});

export const quotes = pgTable("quotes", {
  id: serial("id").primaryKey(),
  userId: integer("user_id").notNull(),
  clientName: text("client_name").notNull(),
  clientEmail: text("client_email").default(""),
  projectName: text("project_name").notNull(),
  projectDescription: text("project_description").default(""),
  dateCreated: timestamp("date_created").defaultNow().notNull(),
  expiryDate: timestamp("expiry_date").notNull(),
  status: text("status").default("draft").notNull(),
  notes: text("notes").default(""),

  // Complex JSON/JSONB fields
  businessInfo: json("business_info").$type<{
    name: string,
    address: string,
    state: string,
    zip: string,
    phone: string,
    website: string,
    quoteValidity: number
  }>(),
  timeEstimates: json("time_estimates").$type<{activity: string, hours: number, rate: number}[]>(),
  personnel: json("personnel").$type<{role: string, hourlyRate: number, quantity: number}[]>(),
  equipment: json("equipment").$type<{name: string, hourlyRate: number, included: boolean, quantity: number}[]>(),
  expenses: json("expenses").$type<{
    name: string, 
    cost: number, 
    expenseType: string, 
    mileage?: number, 
    costPerMile?: number, 
    travelSpeed?: number,
    quantity?: number,
    unitPrice?: number
  }[]>(),
  thirdPartyProducts: json("third_party_products").$type<{name: string, cost: number, expenseType: string}[]>(),

  // Delivery time
  deliveryTimeHours: numeric("delivery_time_hours").default("48"),

  // Business costs stored separately
  businessCosts: json("business_costs").$type<{
    depreciableAssets: number,
    targetMissionsPerWeek: number,
    targetReinvestmentYears: number,
    yearlyAdvertisementCost: number,
    yearlyInsuranceCost: number
  }>(),

  // Profitability metrics
  profitabilityMetrics: json("profitability_metrics").$type<{
    depreciableAssetsSplit: number,
    advertisementSplit: number,
    insuranceSplit: number
  }>(),

  // Final calculations
  totalAmount: numeric("total_amount").default("0"),

  // Legacy fields that exist in the database but have been migrated to JSONB
