          const travelTimeCost = travelTimeHours * pilotRate;

          // Update the expense with the total cost (mileage cost + travel time cost)
          updatedExpenses[index] = {
            ...updatedExpenses[index],
            cost: calculatedCost + travelTimeCost
          };
