import { db } from "./db";
import { sql } from "drizzle-orm";

// Create the pricing_tiers table with enhanced features
async function createPricingTiersTable() {
  console.log("Creating pricing_tiers table...");

  await db.execute(sql`
    CREATE TABLE IF NOT EXISTS pricing_tiers (
      id SERIAL PRIMARY KEY,
      service_id INTEGER NOT NULL REFERENCES services(id) ON DELETE CASCADE,
      name TEXT NOT NULL,
      description TEXT,
      min_quantity INTEGER NOT NULL DEFAULT 1,
      max_quantity INTEGER,
      quantity_unit TEXT DEFAULT 'items',
      min_price INTEGER NOT NULL DEFAULT 0,
      max_price INTEGER,
      price_type TEXT DEFAULT 'fixed',
      price_description TEXT,
      features JSONB DEFAULT '[]'::jsonb,
      is_popular BOOLEAN DEFAULT FALSE,
      display_order INTEGER DEFAULT 100,
      created_at TIMESTAMP DEFAULT NOW(),
      updated_at TIMESTAMP DEFAULT NOW()
    );
  `);

  console.log("Pricing tiers table created successfully!");
}

// Run the migration
createPricingTiersTable()
  .then(() => {
    console.log("Migration completed successfully");
    process.exit(0);
  })
  .catch((error) => {
    console.error("Migration failed:", error);
    process.exit(1);
  });

