import * as React from "react"
import * as SliderPrimitive from "@radix-ui/react-slider"

import { cn } from "@/lib/utils"

const Slider = React.forwardRef<
  React.ElementRef<typeof SliderPrimitive.Root>,
  React.ComponentPropsWithoutRef<typeof SliderPrimitive.Root>
>(({ className, ...props }, ref) => {
  // Determine if we need to render multiple thumbs based on value or defaultValue
  const isRangeSlider = React.useMemo(() => {
    if (Array.isArray(props.value) && props.value.length > 1) {
      return true;
    }
    if (Array.isArray(props.defaultValue) && props.defaultValue.length > 1) {
      return true;
    }
    return false;
  }, [props.value, props.defaultValue]);

  return (
    <SliderPrimitive.Root
      ref={ref}
      className={cn(
        "relative flex w-full touch-none select-none items-center",
        className
      )}
      {...props}
    >
      <SliderPrimitive.Track className="relative h-2 w-full grow overflow-hidden rounded-full bg-secondary">
        <SliderPrimitive.Range className="absolute h-full bg-gradient-to-r from-[#B5892D] to-[#DBBA6F]" />
      </SliderPrimitive.Track>

      {isRangeSlider ? (
        <>
          <SliderPrimitive.Thumb className="block h-5 w-5 rounded-full border-2 border-[#B5892D] bg-background ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50" />
          <SliderPrimitive.Thumb className="block h-5 w-5 rounded-full border-2 border-[#B5892D] bg-background ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50" />
        </>
      ) : (
        <SliderPrimitive.Thumb className="block h-5 w-5 rounded-full border-2 border-[#B5892D] bg-background ring-offset-background transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50" />
      )}
    </SliderPrimitive.Root>
  );
})
Slider.displayName = SliderPrimitive.Root.displayName

export { Slider }

