                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {galleries.map((gallery) => (
                      <GalleryItem 
                        key={gallery.id}
                        item={{
                          id: gallery.id,
                          src: gallery.url || '',
