  bottom: 0;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--gold-gradient);
  transition: width 0.3s ease;
}

.input-focus-effect:focus-within::after {
  width: 100%;
}

/* Nav item hover underline animation */
.nav-item {
  position: relative;
}

.nav-item::after {
  content: '';
  position: absolute;
  bottom: 0;
  left: 50%;
  width: 0;
  height: 2px;
  background: var(--gold-gradient);
  transition: all 0.3s ease;
  transform: translateX(-50%);
}

.nav-item:hover::after,
.nav-item.active::after {
  width: 80%;
}

/* Toast animations */
.toast-enter {
  animation: toastIn 0.3s cubic-bezier(0.21, 1.02, 0.73, 1);
}

.toast-exit {
  animation: toastOut 0.3s cubic-bezier(0.06, 0.71, 0.55, 1);
}

@keyframes toastIn {
  0% {
    transform: translateY(20px);
    opacity: 0;
  }
  100% {
    transform: translateY(0);
    opacity: 1;
  }
}

@keyframes toastOut {
  0% {
    transform: translateY(0);
    opacity: 1;
  }
  100% {
    transform: translateY(-20px);
    opacity: 0;
  }
}

/* Subtle background animation for sections */
.subtle-bg-animation {
  position: relative;
  overflow: hidden;
}

.subtle-bg-animation::before {
  content: '';
  position: absolute;
  top: 0;
  right: 0;
  bottom: 0;
  left: 0;
  background: radial-gradient(circle at 50% 50%, rgba(199, 174, 106, 0.05), transparent 70%);
  opacity: 0;
  transition: opacity 1s ease;
  pointer-events: none;
  z-index: -1;
}

.subtle-bg-animation:hover::before {
  opacity: 1;
}

/* Background gradient animation for page */
.bg-apollo-gradient {
  background: linear-gradient(135deg, #080d17, #0b111f, #132642, #0b111f, #080d17);
  background-size: 400% 400%;
  animation: gradientBG 30s ease infinite;
}

@keyframes gradientBG {
  0% {
    background-position: 0% 50%;
  }
  50% {
    background-position: 100% 50%;
  }
  100% {
    background-position: 0% 50%;
  }
}

/* Time-based color shifts */
.day-mode {
  --background-intensity: 1;
  --text-brightness: 0.9;
}

.night-mode {
  --background-intensity: 0.8;
  --text-brightness: 1;
}

.transition-mode {
  --background-intensity: 0.9;
  --text-brightness: 0.95;
}

.daytime-color-shift {
  transition: all 1s ease;
}

.daytime-color-shift.day-mode {
  --gold-shift: 1.05;
}

.daytime-color-shift.night-mode {
  --gold-shift: 0.85;
}

.daytime-color-shift.transition-mode {
  --gold-shift: 1;
}

