import jsPDF from 'jspdf';
// Try importing autoTable in a different way - explicitly import and add to jsPDF prototype
import { jsPDF as jsPDFType } from 'jspdf';
import autoTable from 'jspdf-autotable';

// Add autoTable to jsPDF prototype explicitly
(jsPDF.prototype as any).autoTable = autoTable;

// Basic PDF test without tables
export const testPdf = (): void => {
  try {
    console.log('Basic PDF test starting...');

    // Create a new document
    const doc = new jsPDF();
    console.log('jsPDF instance created successfully');

    // Try to set some basic properties
    doc.setFont('helvetica');
    doc.setFontSize(16);
