      { id: "calc-additional-revisions", name: "Additional Revisions Add-on", description: "Verify Additional Revisions add-on pricing", category: "Client Pages", subcategory: "Price Calculator - Add-ons", tested: false, navigationUrl: "/pricing" },
      { id: "calc-extended-coverage", name: "Extended Coverage Add-on", description: "Verify Extended Coverage add-on pricing", category: "Client Pages", subcategory: "Price Calculator - Add-ons", tested: false, navigationUrl: "/pricing" },

