      { id: "calc-photo-video-bundle", name: "Photo + Video Bundle", description: "Test Real Estate Photography + Aerial Videography bundle discount", category: "Client Pages", subcategory: "Price Calculator - Bundles", tested: false, navigationUrl: "/pricing" },
      { id: "calc-inspection-monitoring-bundle", name: "Inspection + Monitoring Bundle", description: "Test Inspection + Construction Monitoring bundle pricing", category: "Client Pages", subcategory: "Price Calculator - Bundles", tested: false, navigationUrl: "/pricing" },
      { id: "calc-full-service-bundle", name: "Full Service Bundle", description: "Test 3+ services bundle with maximum discount", category: "Client Pages", subcategory: "Price Calculator - Bundles", tested: false, navigationUrl: "/pricing" },
      { id: "calc-bundle-with-addons", name: "Bundle + Add-ons Calculation", description: "Verify bundle discount applies before add-on calculations", category: "Client Pages", subcategory: "Price Calculator - Bundles", tested: false, navigationUrl: "/pricing" },

