      { id: "ai-pricing-manual-override", name: "Manual Pricing Override", description: "Admin can manually override AI suggestions", category: "Admin Pages", subcategory: "AI Pricing", tested: false, navigationUrl: "/admin/pricing-optimization" },
      { id: "ai-pricing-market-analysis", name: "Market Factors Analysis", description: "Competition, demand, seasonality analysis", category: "Admin Pages", subcategory: "AI Pricing", tested: false, navigationUrl: "/admin/pricing-optimization" },
      { id: "ai-pricing-confidence-levels", name: "Confidence Level Indicators", description: "High/Medium/Low confidence ratings for suggestions", category: "Admin Pages", subcategory: "AI Pricing", tested: false, navigationUrl: "/admin/pricing-optimization" },
      { id: "ai-pricing-expedited-scheduling", name: "Expedited Service Scheduling", description: "One job limit with weekend blocking capability", category: "Admin Pages", subcategory: "AI Pricing", tested: false, navigationUrl: "/admin/pricing-optimization" },

      // Operational Efficiency Features
      { id: "operational-alerts", name: "Real-time Operational Alerts", description: "Critical issue alerts with severity levels", category: "Admin Pages", subcategory: "Operational Efficiency", tested: false, navigationUrl: "/admin/operational-efficiency" },
      { id: "operational-performance-metrics", name: "Performance Metrics Dashboard", description: "Key performance indicators and trends", category: "Admin Pages", subcategory: "Operational Efficiency", tested: false, navigationUrl: "/admin/operational-efficiency" },
      { id: "operational-workflow-templates", name: "Workflow Template Management", description: "Create and manage reusable workflow templates", category: "Admin Pages", subcategory: "Operational Efficiency", tested: false, navigationUrl: "/admin/operational-efficiency" },
      { id: "operational-automation-rules", name: "Automation Rule Engine", description: "Configure automated workflow triggers", category: "Admin Pages", subcategory: "Operational Efficiency", tested: false, navigationUrl: "/admin/operational-efficiency" },
      { id: "operational-resource-allocation", name: "Resource Allocation Optimizer", description: "Optimize team and equipment allocation", category: "Admin Pages", subcategory: "Operational Efficiency", tested: false, navigationUrl: "/admin/operational-efficiency" },

      // Customer Experience Enhancements
      { id: "customer-satisfaction-surveys", name: "Satisfaction Survey System", description: "Automated post-service satisfaction surveys", category: "Admin Pages", subcategory: "Customer Experience", tested: false, navigationUrl: "/admin/customer-experience" },
      { id: "customer-feedback-analysis", name: "Feedback Analysis Dashboard", description: "Analyze and track customer feedback trends", category: "Admin Pages", subcategory: "Customer Experience", tested: false, navigationUrl: "/admin/customer-experience" },
      { id: "customer-communication-templates", name: "Communication Templates", description: "Pre-built email and SMS templates", category: "Admin Pages", subcategory: "Customer Experience", tested: false, navigationUrl: "/admin/customer-experience" },
      { id: "customer-loyalty-programs", name: "Loyalty Program Management", description: "Configure and manage customer loyalty rewards", category: "Admin Pages", subcategory: "Customer Experience", tested: false, navigationUrl: "/admin/customer-experience" },
      { id: "customer-service-personalization", name: "Service Personalization Engine", description: "Personalized service recommendations", category: "Admin Pages", subcategory: "Customer Experience", tested: false, navigationUrl: "/admin/customer-experience" },

      // Security Tests
      { id: "security-admin-access", name: "Admin Access Control", description: "Only admin users can access admin pages", category: "Security", subcategory: "Access Control", tested: false, navigationUrl: "/admin" },
      { id: "security-data-protection", name: "Data Protection", description: "Sensitive data is properly protected", category: "Security", subcategory: "Data Security", tested: false, navigationUrl: "/admin" },
      { id: "security-form-validation", name: "Form Security Validation", description: "Forms prevent malicious input", category: "Security", subcategory: "Input Security", tested: false, navigationUrl: "/contact" },
    ];

    // Combine static features with dynamic features
    const dynamicFeatures = generateDynamicFeatures();
    const allFeatures = [...staticFeatures, ...dynamicFeatures];

    // Load saved state from localStorage
    const savedFeatures = localStorage.getItem('feature-testing-state');
    if (savedFeatures) {
      const savedState = JSON.parse(savedFeatures);
      const updatedFeatures = allFeatures.map(feature => {
        const saved = savedState.find((s: Feature) => s.id === feature.id);
        return saved ? { ...feature, tested: saved.tested } : feature;
      });
      setFeatures(updatedFeatures);
    } else {
      setFeatures(allFeatures);
    }
  }, [services, addons]);

  // Save state to localStorage whenever features change
  useEffect(() => {
    if (features.length > 0) {
      localStorage.setItem('feature-testing-state', JSON.stringify(features));
    }
  }, [features]);

  const toggleFeature = (featureId: string) => {
    setFeatures(prev => prev.map(feature => 
      feature.id === featureId 
        ? { ...feature, tested: !feature.tested }
        : feature
    ));
  };

  const resetAllFeatures = () => {
    setFeatures(prev => prev.map(feature => ({ ...feature, tested: false })));
    setCollapsedSections({});
  };

  // Check if a category is complete and should be auto-collapsed
  const isCategoryComplete = (categoryName: string) => {
    const categoryFeatures = features.filter(f => f.category === categoryName);
    return categoryFeatures.length > 0 && categoryFeatures.every(f => f.tested);
  };

  // Auto-collapse completed categories
  useEffect(() => {
    if (features.length > 0) {
      const updatedCollapsed = { ...collapsedSections };
      let hasChanges = false;

      Object.values(organizedFeatures).forEach(category => {
        const isComplete = isCategoryComplete(category.name);
        const currentlyCollapsed = collapsedSections[category.name];

        if (isComplete && !currentlyCollapsed) {
          updatedCollapsed[category.name] = true;
          hasChanges = true;
        }
      });

      if (hasChanges) {
        setCollapsedSections(updatedCollapsed);
      }
    }
  }, [features]);

  const toggleSection = (categoryName: string) => {
    setCollapsedSections(prev => ({
      ...prev,
      [categoryName]: !prev[categoryName]
    }));
  };

  // Organize features by category and subcategory
  const organizedFeatures: Record<string, FeatureCategory> = {};

  features.forEach(feature => {
    if (!organizedFeatures[feature.category]) {
      organizedFeatures[feature.category] = {
        name: feature.category,
        subcategories: []
      };
    }

    const category = organizedFeatures[feature.category];
    let subcategory = category.subcategories.find(sub => sub.name === feature.subcategory);

    if (!subcategory) {
      subcategory = {
        name: feature.subcategory || "General",
        features: []
      };
      category.subcategories.push(subcategory);
    }

    subcategory.features.push(feature);
  });

  // Calculate statistics
  const totalFeatures = features.length;
  const testedFeatures = features.filter(f => f.tested).length;
  const completionPercentage = totalFeatures > 0 ? Math.round((testedFeatures / totalFeatures) * 100) : 0;

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-white">Feature Testing Dashboard</h1>
          <p className="text-gray-400 mt-2">Track the testing status of all website features</p>
        </div>
        <Button 
          onClick={resetAllFeatures}
          variant="outline"
          className="flex items-center gap-2"
        >
          <RotateCcw className="h-4 w-4" />
          Reset All
        </Button>
      </div>

      {/* Statistics Overview */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card className="bg-gray-800 border-gray-700">
          <CardContent className="p-6">
            <div className="flex items-center gap-2">
              <CheckCircle className="h-5 w-5 text-green-500" />
              <div>
                <p className="text-2xl font-bold text-white">{testedFeatures}</p>
                <p className="text-gray-400 text-sm">Features Tested</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gray-800 border-gray-700">
          <CardContent className="p-6">
            <div className="flex items-center gap-2">
              <AlertCircle className="h-5 w-5 text-orange-500" />
              <div>
                <p className="text-2xl font-bold text-white">{totalFeatures - testedFeatures}</p>
                <p className="text-gray-400 text-sm">Features Pending</p>
              </div>
            </div>
          </CardContent>
        </Card>

        <Card className="bg-gray-800 border-gray-700">
          <CardContent className="p-6">
            <div className="flex items-center gap-2">
              <div className="h-5 w-5 rounded-full bg-blue-500 flex items-center justify-center">
                <span className="text-xs font-bold text-white">{completionPercentage}%</span>
              </div>
              <div>
                <p className="text-2xl font-bold text-white">{completionPercentage}%</p>
                <p className="text-gray-400 text-sm">Completion Rate</p>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Feature Categories */}
      {Object.values(organizedFeatures).map((category) => {
        const isComplete = isCategoryComplete(category.name);
        const isCollapsed = collapsedSections[category.name];
        const totalFeatures = category.subcategories.reduce((acc, sub) => acc + sub.features.length, 0);
        const completedFeatures = category.subcategories.reduce((acc, sub) => acc + sub.features.filter(f => f.tested).length, 0);

        return (
          <Card key={category.name} className={`bg-gray-800 border-gray-700 ${isComplete ? 'ring-2 ring-green-500/50' : ''}`}>
            <Collapsible open={!isCollapsed} onOpenChange={() => toggleSection(category.name)}>
              <CollapsibleTrigger asChild>
                <CardHeader className="cursor-pointer hover:bg-gray-700/20 transition-colors">
                  <CardTitle className="text-white flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      {isCollapsed ? (
                        <ChevronRight className="h-5 w-5 text-gray-400" />
                      ) : (
                        <ChevronDown className="h-5 w-5 text-gray-400" />
                      )}
                      {category.name}
                      {isComplete && (
                        <CheckCircle className="h-5 w-5 text-green-500" />
                      )}
                    </div>
                    <div className="flex items-center gap-2">
                      <Badge variant={isComplete ? "default" : "secondary"} className={isComplete ? "bg-green-600" : ""}>
                        {completedFeatures}/{totalFeatures} features
                      </Badge>
                      {isComplete && (
                        <Badge variant="outline" className="text-green-400 border-green-400">
                          Complete
                        </Badge>
                      )}
                    </div>
                  </CardTitle>
                </CardHeader>
              </CollapsibleTrigger>
              <CollapsibleContent>
                <CardContent className="space-y-6 pt-0">
                  {category.subcategories.map((subcategory) => (
                    <div key={subcategory.name}>
                      <h3 className="text-lg font-semibold text-white mb-3 flex items-center gap-2">
                        {subcategory.name}
                        <Badge variant="outline">
                          {subcategory.features.filter(f => f.tested).length}/{subcategory.features.length}
                        </Badge>
                        {subcategory.features.every(f => f.tested) && subcategory.features.length > 0 && (
                          <CheckCircle className="h-4 w-4 text-green-500" />
                        )}
                      </h3>

                      <div className="grid grid-cols-1 lg:grid-cols-2 gap-3">
                        {subcategory.features.map((feature) => (
                          <div 
                            key={feature.id}
                            className={`p-4 rounded-lg border transition-all ${
                              feature.tested 
                                ? 'bg-green-900/20 border-green-700' 
                                : 'bg-gray-700/20 border-gray-600'
                            }`}
                          >
                            <div className="flex items-center justify-between">
                              <div className="flex-1">
                                <div className="flex items-center gap-2 mb-1">
                                  <h4 className="font-medium text-white">{feature.name}</h4>
                                  {feature.tested && (
                                    <CheckCircle className="h-4 w-4 text-green-500" />
                                  )}
                                </div>
                                <p className="text-sm text-gray-400">{feature.description}</p>
                              </div>
                              <div className="flex items-center gap-2 ml-4">
                                {feature.navigationUrl && (
                                  <Link to={feature.navigationUrl}>
                                    <Button
                                      size="sm"
                                      variant="outline"
                                      className="h-8 px-2 text-xs flex items-center gap-1"
                                    >
                                      <ExternalLink className="h-3 w-3" />
                                      Go to Page
                                    </Button>
                                  </Link>
                                )}
                                <Switch
                                  checked={feature.tested}
                                  onCheckedChange={() => toggleFeature(feature.id)}
                                />
                              </div>
                            </div>
                          </div>
                        ))}
                      </div>

                      {subcategory !== category.subcategories[category.subcategories.length - 1] && (
                        <Separator className="mt-6 bg-gray-600" />
                      )}
                    </div>
                  ))}
                </CardContent>
              </CollapsibleContent>
            </Collapsible>
          </Card>
        );
      })}
    </div>
  );
}

