// Service Media Carousel Component
function ServiceMediaCarousel({ service }: { service: Service }) {
  const [currentSlide, setCurrentSlide] = useState(0);

  // Create media items array from the new images and videos arrays
  const mediaItems = useMemo(() => {
    const items = [];

    // Add all images from the images array
    if (service.images && service.images.length > 0) {
      service.images.forEach(imageUrl => {
        items.push({ type: 'image', url: imageUrl });
      });
    } else if (service.imageUrl) {
      // Fallback to single imageUrl for backward compatibility
      items.push({ type: 'image', url: service.imageUrl });
    }

    // Add all videos from the videos array
    if (service.videos && service.videos.length > 0) {
      service.videos.forEach(videoUrl => {
        items.push({ type: 'video', url: videoUrl });
      });
    } else if (service.videoUrl) {
      // Fallback to single videoUrl for backward compatibility
      items.push({ type: 'video', url: service.videoUrl });
    }

    return items;
  }, [service.images, service.videos, service.imageUrl, service.videoUrl]);

  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % mediaItems.length);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + mediaItems.length) % mediaItems.length);
  };

  if (mediaItems.length === 0) return null;

  return (
    <div className="relative bg-black-light rounded-lg overflow-hidden border border-white/50">
      <div className="aspect-video w-full overflow-hidden">
        {mediaItems[currentSlide].type === 'video' ? (
          <video
            key={mediaItems[currentSlide].url}
            src={mediaItems[currentSlide].url}
            controls
            className="w-full h-full object-cover"
            poster={service.imageUrl}
            onError={(e) => {
              console.error(`Failed to load video for service: ${service.name}`);
            }}
          >
            Your browser does not support the video tag.
          </video>
        ) : (
          <img
            src={mediaItems[currentSlide].url}
            alt={service.name}
            className="w-full h-full object-cover"
            onError={(e) => {
              console.error(`Failed to load image for service: ${service.name}`);
              const target = e.target as HTMLImageElement;
              target.style.backgroundColor = '#080d17';
              target.style.display = 'none';
            }}
          />
        )}
      </div>

      {/* Carousel Controls - only show if multiple items */}
      {mediaItems.length > 1 && (
        <>
          <div className="absolute inset-x-0 top-1/2 flex justify-between px-4 sm:px-6 lg:px-8 transition-all duration-300">
            <button
              onClick={prevSlide}
              className="carousel-nav-button border-2 border-gold hover:border-gold-light transition-all"
              aria-label="Previous media"
            >
              <ChevronLeft size={24} className="text-gold drop-shadow-lg" />
            </button>
            <button
              onClick={nextSlide}
              className="carousel-nav-button border-2 border-gold hover:border-gold-light transition-all"
              aria-label="Next media"
            >
              <ChevronRight size={24} className="text-gold drop-shadow-lg" />
            </button>
          </div>

          {/* Carousel indicators/dots */}
          <div className="absolute bottom-6 inset-x-0 flex justify-center">
            <div className="carousel-dots-container flex gap-3">
              {mediaItems.map((_, index) => (
                <button
                  key={index}
                  onClick={() => setCurrentSlide(index)}
                  className={`carousel-page-marker border-2 border-gold transition-all ${
                    index === currentSlide
                      ? "bg-gold-gradient shadow-lg shadow-gold/50"
                      : "bg-transparent hover:bg-gold/20"
                  }`}
                  aria-label={`Go to slide ${index + 1}`}
                />
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );
}

export default function ServicePage() {
  // Try both route patterns to handle /service/:id and /services/:id
  const [matchService, serviceParams] = useRoute("/service/:id");
  const [matchServices, servicesParams] = useRoute("/services/:id");

  const params = serviceParams || servicesParams;
  const serviceId = params?.id ? parseInt(params.id) : null;

  console.log("ServicePage - Service params:", serviceParams);
  console.log("ServicePage - Services params:", servicesParams);
  console.log("ServicePage - Final Service ID:", serviceId);

  const [, setLocation] = useLocation();

  // Fetch service details with proper error handling
  const {
    data: service,
    isLoading,
    error
  } = useQuery<Service>({
    queryKey: [`/api/services/${serviceId}`],
    enabled: !!serviceId,
    retry: (failureCount, error: any) => {
      console.error("Service query error:", error);
      // Don't retry if it's a 404 - service doesn't exist
      if (error?.message?.includes('404')) {
        return false;
      }
      return failureCount < 2;
    },
  });

  // Fetch related services
  const {
    data: services,
    isLoading: isLoadingServices,
  } = useQuery<Service[]>({
    queryKey: ["/api/services"],
  });

  // Fetch service add-ons for the current service
  const {
    data: serviceAddons,
    isLoading: isLoadingAddons,
  } = useQuery<any[]>({
    queryKey: [`/api/services/${serviceId}/addons`],
    enabled: !!serviceId,
  });

  // Fetch before/after images
  const {
    data: beforeAfterImages,
    isLoading: isLoadingBeforeAfter,
  } = useQuery<BeforeAfterImage[]>({
    queryKey: ["/api/before-after"],
  });

  // Select which Before/After images to display based on service ID
  let displayBeforeAfterImages: any[] = [];

  if (serviceId === 4) { // Construction Monitoring
    displayBeforeAfterImages = (beforeAfterImages?.filter(img => img.serviceId === 4) || constructionBeforeAfterImages) as any[];
  } else if (serviceId === 6) { // 2D Orthomosaics
    displayBeforeAfterImages = (beforeAfterImages?.filter(img => img.serviceId === 6) || orthomosaicsBeforeAfterImages) as any[];
  }

  const { user } = useAuth();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  // State with immutable objects to ensure React detects changes
  const [selectedBundles, setSelectedBundles] = useState<number[]>([]);
  const [selectedPricingTier, setSelectedPricingTier] = useState<number | null>(null);
  const [selectedAddOns, setSelectedAddOns] = useState<number[]>([]);
  const [selectedSubscription, setSelectedSubscription] = useState<'weekly' | 'biWeekly' | 'monthly' | null>(null);
  const [flightQuantity, setFlightQuantity] = useState<number>(1);

  // Refs for pricing tiers and bundle areas to handle click outside
  const pricingTiersRef = useRef<HTMLDivElement>(null);
  const bundleAreaRef = useRef<HTMLDivElement>(null);

  // Handle click outside pricing tiers to deselect (but not when clicking bundles)
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as Node;
      const isOutsidePricingTiers = pricingTiersRef.current && !pricingTiersRef.current.contains(target);
      const isOutsideBundleArea = bundleAreaRef.current && !bundleAreaRef.current.contains(target);

      // Only deselect pricing tier if click is outside both pricing tiers and bundle area
      if (isOutsidePricingTiers && isOutsideBundleArea) {
        setSelectedPricingTier(null);
      }
    };

    document.addEventListener('mousedown', handleClickOutside);
    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
    };
  }, []);

  // Pricing calculations using array-based state
  const bundlePricing = useMemo(() => {
    if (!service || !services || selectedBundles.length === 0) {
      return { totalDiscount: 0, bundleServices: [] };
    }

    let totalDiscount = 0;
    const bundleServices: any[] = [];

    selectedBundles.forEach(bundleServiceId => {
      const targetService = services.find(s => s.id === bundleServiceId);
      const bundleConfig = service.bundleConfigurations?.find(config => config.serviceId === bundleServiceId);

      if (targetService && bundleConfig) {
        let discount = 0;
        if (bundleConfig.customPrice) {
          discount = targetService.price - bundleConfig.customPrice;
        } else if (bundleConfig.discountPercentage) {
          discount = targetService.price * (bundleConfig.discountPercentage / 100);
        }

        totalDiscount += discount;
        bundleServices.push({
          service: targetService,
          originalPrice: targetService.price,
          bundlePrice: targetService.price - discount,
          discount,
          config: bundleConfig
        });
      }
    });

    return { totalDiscount, bundleServices };
  }, [service, services, selectedBundles.length, selectedBundles.join(',')]);

  const totalPrice = useMemo(() => {
    let basePrice = service?.price || 0;

    // Handle different pricing types
    if (selectedPricingTier !== null && service) {
      if (service.priceRanges && service.priceRanges[selectedPricingTier]) {
        basePrice = service.priceRanges[selectedPricingTier].minPrice;
      } else if (service.pricingTiers && service.pricingTiers[selectedPricingTier]) {
        const tier = service.pricingTiers[selectedPricingTier];
        basePrice = tier.price ? tier.price * 100 : (tier.minPrice ? tier.minPrice * 100 : basePrice);
      }
    }

    // Apply subscription pricing if both tier and subscription are selected
    if (selectedSubscription && selectedPricingTier !== null && service) {
      // Get the subscription price per flight based on frequency
      let pricePerFlight = 0;
      const currentTierPrice = selectedPricingTier !== null && service.pricingTiers && service.pricingTiers[selectedPricingTier] 
        ? (() => {
            const tier = service.pricingTiers[selectedPricingTier];
            return tier.price ? tier.price * 100 : (tier.minPrice ? tier.minPrice * 100 : service.price);
          })()
        : service.price;

      if (selectedSubscription === 'weekly') {
        pricePerFlight = (service as any).weeklyPriceType === "percentage" 
          ? Math.round(currentTierPrice * ((service as any).weeklyPercentage / 100))
          : ((service as any).weeklyPrice || 0) * 100;
      } else if (selectedSubscription === 'biWeekly') {
        pricePerFlight = (service as any).biWeeklyPriceType === "percentage" 
          ? Math.round(currentTierPrice * ((service as any).biWeeklyPercentage / 100))
          : ((service as any).biWeeklyPrice || 0) * 100;
      } else if (selectedSubscription === 'monthly') {
        pricePerFlight = (service as any).monthlyPriceType === "percentage" 
          ? Math.round(currentTierPrice * ((service as any).monthlyPercentage / 100))
          : ((service as any).monthlyPrice || 0) * 100;
      }

      basePrice = pricePerFlight * flightQuantity;
    }

    const bundleServicesTotal = bundlePricing.bundleServices.reduce((sum, bundle) => sum + bundle.bundlePrice, 0);

    // Calculate add-ons total
    const addonsTotal = serviceAddons?.reduce((total, serviceAddon) => {
      if (selectedAddOns.includes(serviceAddon.addon.id)) {
        const addon = serviceAddon.addon;
        if (addon.pricingType === 'percentage') {
          // Calculate percentage of base service price
          return total + Math.round(basePrice * (addon.percentage / 100));
        } else {
          // Fixed price
          return total + addon.price;
        }
      }
      return total;
    }, 0) || 0;

    return basePrice + bundleServicesTotal + addonsTotal;
  }, [service, bundlePricing, selectedPricingTier, selectedSubscription, flightQuantity, serviceAddons, selectedAddOns]);

  // Stable handlers to eliminate race conditions
  const handleBundleToggle = useCallback((serviceId: number) => {
    setSelectedBundles(prev => {
      const newState = prev.includes(serviceId) 
        ? prev.filter(id => id !== serviceId)
        : [...prev, serviceId];
      return newState;
    });
  }, []);

  const handleAddonToggle = useCallback((addonId: number) => {
    setSelectedAddOns(prev => {
      const newState = prev.includes(addonId) 
        ? prev.filter(id => id !== addonId)
        : [...prev, addonId];
      return newState;
    });
  }, []);

  const handlePricingTierSelect = useCallback((index: number) => {
    setSelectedPricingTier(prev => prev === index ? null : index);
  }, []);

  const handleSubscriptionSelect = useCallback((type: 'weekly' | 'biWeekly' | 'monthly') => {
    setSelectedSubscription(prev => prev === type ? null : type);
  }, []);

  // Format price helper
  const formatPrice = (priceInCents: number) => {
    return new Intl.NumberFormat('en-US', { 
      style: 'currency', 
      currency: 'USD', 
      minimumFractionDigits: 0 
    }).format(priceInCents / 100);
  };

  // Get current selected tier price
  const getCurrentPrice = () => {
    if (!service) return 0;

    if (service.pricingTiers && service.pricingTiers.length > 0 && selectedPricingTier !== null) {
      const tier = service.pricingTiers[selectedPricingTier];
      return tier.price ? tier.price * 100 : (tier.minPrice ? tier.minPrice * 100 : service.price);
    }

    return service.price;
  };



  if (isLoading) {
    return (
      <div className="flex flex-col min-h-screen bg-gradient-to-b from-[#080d17] to-[#0b111f]">
        <div className="flex items-center justify-center flex-1">
          <Loader2 className="w-8 h-8 animate-spin text-gold" />
        </div>
      </div>
    );
  }

  if (error) {
    console.error("Service page error:", error);
    return (
      <div className="flex flex-col min-h-screen bg-gradient-to-b from-[#080d17] to-[#0b111f]">
        <div className="flex items-center justify-center flex-1">
          <div className="text-center">
            <h1 className="text-2xl font-bold text-gold mb-4">Service Error</h1>
            <p className="text-offwhite/70 mb-2">Error loading service: {error.message}</p>
            <p className="text-offwhite/50">Service ID: {serviceId}</p>
          </div>
        </div>
      </div>
    );
  }

  // Redirect to services page if service not found after loading completes
  useEffect(() => {
    if (!isLoading && !service && serviceId) {
      console.log(`Service ${serviceId} not found, redirecting to services page`);
      setTimeout(() => {
        setLocation('/services');
      }, 100);
    }
  }, [isLoading, service, serviceId, setLocation]);

  if (!service) {
    if (isLoading) {
      return (
        <div className="flex flex-col min-h-screen bg-gradient-to-b from-[#080d17] to-[#0b111f]">
          <div className="flex items-center justify-center flex-1">
            <Loader2 className="w-8 h-8 animate-spin text-gold" />
          </div>
        </div>
      );
    }

    return (
      <div className="flex flex-col min-h-screen bg-gradient-to-b from-[#080d17] to-[#0b111f]">
        <div className="flex items-center justify-center flex-1">
          <div className="text-center">
            <h1 className="text-2xl font-bold text-gold mb-4">Service Not Found</h1>
            <p className="text-offwhite/70">Redirecting to services page...</p>
          </div>
        </div>
      </div>
    );
  }

  const isQuoteOnlyService = service && (service as any).isQuoteOnly;

  const handleBookNow = () => {
    const searchParams = new URLSearchParams();
    searchParams.set('service', service.id.toString());

    if (selectedPricingTier !== null) {
      searchParams.set('tier', selectedPricingTier.toString());
    }

    if (selectedSubscription) {
      searchParams.set('subscription', selectedSubscription);
      searchParams.set('flights', flightQuantity.toString());
    }

    if (selectedBundles.length > 0) {
      searchParams.set('bundles', selectedBundles.join(','));
    }

    window.location.href = `/booking?${searchParams.toString()}`;
  };

  return (
    <div className="flex flex-col min-h-screen bg-gradient-to-b from-[#080d17] to-[#0b111f] text-offwhite">
      <Helmet>
        <title>{service.name} - Apollo DroneWorks</title>
        <meta name="description" content={service.description} />
      </Helmet>

      <div className="flex-1 pt-4 pb-16">
        <div className="container mx-auto px-4 max-w-7xl">
          {/* DEBUG: Test section at top */}
          <div className="bg-red-500 text-white p-4 mb-4 rounded text-center">
            <h2>🔴 DEBUG: ADD-ONS TEST SECTION 🔴</h2>
            <p>Service ID: {serviceId}</p>
            <p>Add-ons loading: {isLoadingAddons ? 'YES' : 'NO'}</p>
            <p>Add-ons data length: {serviceAddons?.length || 0}</p>
          </div>

          {/* Back Button */}
          <div className="mb-6">
            <Link href="/services" className="inline-flex items-center text-gold hover:text-gold-light transition-colors">
              <ArrowLeft className="w-4 h-4 mr-2" />
              Back to Services
            </Link>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 lg:gap-12">
            {/* Left Column - Service Details */}
            <div className="space-y-8">
              {/* Service Header - Centered */}
              <div className="text-center">
                <h1 className="text-3xl lg:text-4xl font-bold text-gold-gradient mb-4">
                  {service.name}
                </h1>
              </div>

              {/* Service Media Carousel */}
              <ServiceMediaCarousel service={service} />

              {/* Service Description - Below image */}
              <div className="space-y-4">
                <p className="text-offwhite/90 leading-relaxed text-lg">
                  {service.description}
                </p>

                {service.tooltipDescription && (
                  <div className="bg-offwhite/5 border border-gold/20 rounded-lg p-4">
                    <div className="flex items-start gap-3">
                      <Info className="w-5 h-5 text-gold mt-0.5 flex-shrink-0" />
                      <p className="text-offwhite/80 text-sm leading-relaxed">
                        {service.tooltipDescription}
                      </p>
                    </div>
                  </div>
                )}
              </div>

              {/* What's Included Section */}
              {service.whatsIncludedContent && service.whatsIncludedContent.length > 0 && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <h3 className="text-xl font-semibold text-gold-gradient mb-4">What's Included</h3>
                    <ul className="space-y-2">
                      {service.whatsIncludedContent.map((item, index) => (
                        <li key={index} className="flex items-start gap-3">
                          <Check className="w-5 h-5 text-gold mt-0.5 flex-shrink-0" />
                          <span className="text-offwhite/90">{item}</span>
                        </li>
                      ))}
