                      ))}
                    </ul>
                  </CardContent>
                </Card>
              )}

              {/* Service Features */}
              {service.features && service.features.length > 0 && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <h3 className="text-xl font-semibold text-gold-gradient mb-4">Service Features</h3>
                    <ul className="space-y-2">
                      {service.features.map((feature, index) => (
                        <li key={index} className="flex items-start gap-3">
                          <Check className="w-5 h-5 text-gold mt-0.5 flex-shrink-0" />
                          <span className="text-offwhite/90">{feature}</span>
                        </li>
                      ))}
                    </ul>
                  </CardContent>
                </Card>
              )}


            </div>

            {/* Right Column - Pricing and Actions */}
            <div className="space-y-8">
              {/* Pricing Tiers */}
              {service.pricingTiers && service.pricingTiers.length > 0 && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <h3 className="text-xl font-semibold text-gold-gradient mb-4">Choose Your Package</h3>
                    <div ref={pricingTiersRef} className="space-y-3">
                      {service.pricingTiers.map((tier, index) => (
                        <div
                          key={index}
                          onClick={() => handlePricingTierSelect(index)}
                          className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                            selectedPricingTier === index
                              ? 'border-gold bg-gold/10 shadow-lg shadow-gold/20'
                              : 'border-offwhite/20 bg-offwhite/5 hover:border-gold/50'
                          }`}
                        >
                          <div className="flex items-center justify-between">
                            <div className="flex-1">
                              <h4 className="font-semibold text-gold-gradient">{tier.name}</h4>
                              {tier.description && (
                                <p className="text-sm text-offwhite/70 mt-1">{tier.description}</p>
                              )}
                            </div>
                            <div className="text-right ml-4">
                              <span className="text-lg font-bold text-gold-gradient">
                                {tier.price 
                                  ? formatPrice(tier.price * 100)
                                  : tier.minPrice && tier.maxPrice
                                    ? `${formatPrice(tier.minPrice * 100)} - ${formatPrice(tier.maxPrice * 100)}`
                                    : tier.minPrice
                                      ? `From ${formatPrice(tier.minPrice * 100)}`
                                      : 'Quote'
                                }
                              </span>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* DEBUG: Simple test section */}
              <div className="bg-red-500 text-white p-4 m-4 rounded">
                <h3>TEST ADD-ONS SECTION - Can you see this?</h3>
                <p>Service ID: {serviceId}</p>
                <p>Add-ons loading: {isLoadingAddons ? 'YES' : 'NO'}</p>
                <p>Add-ons data: {serviceAddons ? JSON.stringify(serviceAddons) : 'null'}</p>
              </div>

              {/* Add-ons Section - Always show for testing */}
              {true && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <h3 className="text-xl font-semibold text-gold-gradient mb-4">Available Add-ons</h3>
                    <div className="space-y-3">
                      {serviceAddons && serviceAddons.length > 0 ? serviceAddons.map((serviceAddon) => {
                        const addon = serviceAddon.addon;
                        const isSelected = selectedAddOns.includes(addon.id);

                        // Calculate the actual add-on price based on the selected tier
                        const currentTierPrice = getCurrentPrice();
                        const addonPrice = addon.pricingType === 'percentage' 
                          ? Math.round(currentTierPrice * (addon.percentage / 100))
                          : addon.price;

                        return (
                          <div 
                            key={addon.id} 
                            className={`p-3 rounded-lg border-2 cursor-pointer transition-all ${
                              isSelected
                                ? 'border-gold bg-gold/10 shadow-lg shadow-gold/20'
                                : 'border-offwhite/20 bg-offwhite/5 hover:border-gold/50'
                            }`}
                            onClick={() => handleAddonToggle(addon.id)}
                          >
                            <div className="flex items-center justify-between">
                              <div className="flex items-center gap-3">
                                <div className={`w-5 h-5 rounded border-2 flex items-center justify-center ${
                                  isSelected ? 'bg-gold border-gold' : 'border-offwhite/40'
                                }`}>
                                  {isSelected && <Check className="w-3 h-3 text-black" />}
                                </div>
                                <div className="flex-1">
                                  <span className="text-offwhite/90 font-medium">{addon.name}</span>
                                  {addon.description && (
                                    <p className="text-sm text-offwhite/70 mt-1">{addon.description}</p>
                                  )}
                                </div>
                              </div>
                              <div className="text-right ml-4">
                                <span className="text-lg font-bold text-gold-gradient">
                                  +{formatPrice(addonPrice)}
                                </span>
                                {addon.pricingType === 'percentage' && (
                                  <div className="text-xs text-offwhite/60">
                                    {addon.percentage}% of tier
                                  </div>
                                )}
                              </div>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Subscription Options - Only show if tier is selected */}
              {selectedPricingTier !== null && service && (
                (service as any).weeklyEnabled || 
                (service as any).biWeeklyEnabled || 
                (service as any).monthlyEnabled
              ) && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <h3 className="text-xl font-semibold text-gold-gradient mb-4">Subscription Options</h3>
                    <div className="space-y-3">
                      {(service as any).weeklyEnabled && (
                        <div
                          onClick={() => handleSubscriptionSelect('weekly')}
                          className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                            selectedSubscription === 'weekly'
                              ? 'border-gold bg-gold/10 shadow-lg shadow-gold/20'
                              : 'border-offwhite/20 bg-offwhite/5 hover:border-gold/50'
                          }`}
                        >
                          <div className="flex items-center justify-between">
                            <div>
                              <h4 className="font-semibold text-gold-gradient">Weekly</h4>
                              <p className="text-sm text-offwhite/70">Every 7 days</p>
                            </div>
                            <div className="text-right">
                              <span className="text-lg font-bold text-gold-gradient">
                                {(() => {
                                  const currentTierPrice = service.pricingTiers && service.pricingTiers[selectedPricingTier] 
                                    ? (() => {
                                        const tier = service.pricingTiers[selectedPricingTier];
                                        return tier.price ? tier.price * 100 : (tier.minPrice ? tier.minPrice * 100 : service.price);
                                      })()
                                    : service.price;

                                  if ((service as any).weeklyPriceType === "percentage") {
                                    const discountedPrice = Math.round(currentTierPrice * ((service as any).weeklyPercentage / 100));
                                    return formatPrice(discountedPrice);
                                  } else {
                                    return formatPrice(((service as any).weeklyPrice || 0) * 100);
                                  }
                                })()}
                              </span>
                              <div className="text-xs text-offwhite/60">per flight</div>
                            </div>
                          </div>
                        </div>
                      )}

                      {(service as any).biWeeklyEnabled && (
                        <div
                          onClick={() => handleSubscriptionSelect('biWeekly')}
                          className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                            selectedSubscription === 'biWeekly'
                              ? 'border-gold bg-gold/10 shadow-lg shadow-gold/20'
                              : 'border-offwhite/20 bg-offwhite/5 hover:border-gold/50'
                          }`}
                        >
                          <div className="flex items-center justify-between">
                            <div>
                              <h4 className="font-semibold text-gold-gradient">Bi-Weekly</h4>
                              <p className="text-sm text-offwhite/70">Every 14 days</p>
                            </div>
                            <div className="text-right">
                              <span className="text-lg font-bold text-gold-gradient">
                                {(() => {
                                  const currentTierPrice = service.pricingTiers && service.pricingTiers[selectedPricingTier] 
                                    ? (() => {
                                        const tier = service.pricingTiers[selectedPricingTier];
                                        return tier.price ? tier.price * 100 : (tier.minPrice ? tier.minPrice * 100 : service.price);
                                      })()
                                    : service.price;

                                  if ((service as any).biWeeklyPriceType === "percentage") {
                                    const discountedPrice = Math.round(currentTierPrice * ((service as any).biWeeklyPercentage / 100));
                                    return formatPrice(discountedPrice);
                                  } else {
                                    return formatPrice(((service as any).biWeeklyPrice || 0) * 100);
                                  }
                                })()}
                              </span>
                              <div className="text-xs text-offwhite/60">per flight</div>
                            </div>
                          </div>
                        </div>
                      )}

                      {(service as any).monthlyEnabled && (
                        <div
                          onClick={() => handleSubscriptionSelect('monthly')}
                          className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                            selectedSubscription === 'monthly'
                              ? 'border-gold bg-gold/10 shadow-lg shadow-gold/20'
                              : 'border-offwhite/20 bg-offwhite/5 hover:border-gold/50'
                          }`}
                        >
                          <div className="flex items-center justify-between">
                            <div>
                              <h4 className="font-semibold text-gold-gradient">Monthly</h4>
                              <p className="text-sm text-offwhite/70">Every 30 days</p>
                            </div>
                            <div className="text-right">
                              <span className="text-lg font-bold text-gold-gradient">
                                {(() => {
                                  const currentTierPrice = service.pricingTiers && service.pricingTiers[selectedPricingTier] 
                                    ? (() => {
                                        const tier = service.pricingTiers[selectedPricingTier];
                                        return tier.price ? tier.price * 100 : (tier.minPrice ? tier.minPrice * 100 : service.price);
                                      })()
                                    : service.price;

                                  if ((service as any).monthlyPriceType === "percentage") {
                                    const discountedPrice = Math.round(currentTierPrice * ((service as any).monthlyPercentage / 100));
                                    return formatPrice(discountedPrice);
                                  } else {
                                    return formatPrice(((service as any).monthlyPrice || 0) * 100);
                                  }
                                })()}
                              </span>
                              <div className="text-xs text-offwhite/60">per flight</div>
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Flight Quantity Selector - Only show if both tier and subscription are selected */}
              {selectedPricingTier !== null && selectedSubscription && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <div className="flex items-center justify-between mb-4">
                      <label htmlFor="flight-quantity" className="text-lg font-medium text-gold-gradient">
                        Flights:
                      </label>
                      <input
                        id="flight-quantity"
                        type="number"
                        min="1"
                        max="100"
                        value={flightQuantity}
                        onChange={(e) => setFlightQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                        className="w-20 px-3 py-2 text-center bg-transparent border-2 border-gold text-white font-medium rounded-lg focus:outline-none focus:border-gold-light"
                      />
                    </div>
                  </CardContent>
                </Card>
              )}



              {/* Bundle Services */}
              {service.bundleConfigurations && service.bundleConfigurations.length > 0 && services && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <h3 className="text-xl font-semibold text-gold-gradient mb-4">Add Bundle Services</h3>
                    <div ref={bundleAreaRef} className="space-y-3">
                      {service.bundleConfigurations.map((config) => {
                        const bundleService = services.find(s => s.id === config.serviceId);
                        if (!bundleService) return null;

                        const isSelected = selectedBundles.includes(config.serviceId);
                        let bundlePrice = bundleService.price;
                        let discount = 0;

                        if (config.customPrice) {
                          bundlePrice = config.customPrice;
                          discount = bundleService.price - config.customPrice;
                        } else if (config.discountPercentage) {
                          discount = bundleService.price * (config.discountPercentage / 100);
                          bundlePrice = bundleService.price - discount;
                        }

                        return (
                          <div
                            key={config.serviceId}
                            className={`p-4 rounded-lg border-2 cursor-pointer transition-all ${
                              isSelected
                                ? 'border-gold bg-gold/10 shadow-lg shadow-gold/20'
                                : 'border-offwhite/20 bg-offwhite/5 hover:border-gold/50'
                            }`}
                            onClick={() => handleBundleToggle(config.serviceId)}
                          >
                            <div className="flex items-center justify-between">
                              <div className="flex items-center gap-3">
                                <div className={`w-5 h-5 rounded border-2 flex items-center justify-center ${
                                  isSelected ? 'bg-gold border-gold' : 'border-offwhite/40'
                                }`}>
                                  {isSelected && <Check className="w-3 h-3 text-black" />}
                                </div>
                                <div>
                                  <h4 className="font-semibold text-gold-gradient">{bundleService.name}</h4>
                                  {discount > 0 && (
                                    <p className="text-sm text-green-400">
                                      Save {formatPrice(discount)}
                                    </p>
                                  )}
                                </div>
                              </div>
                              <div className="text-right">
                                {discount > 0 && (
                                  <div className="text-sm text-offwhite/60 line-through">
                                    {formatPrice(bundleService.price)}
                                  </div>
                                )}
                                <div className="text-lg font-bold text-gold-gradient">
                                  {formatPrice(bundlePrice)}
                                </div>
                              </div>
                            </div>
                          </div>
                        );
                      })}
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Pricing Summary */}
              {(selectedPricingTier !== null || selectedBundles.length > 0) && (
                <Card className="bg-offwhite/5 border-gold/20">
                  <CardContent className="p-6">
                    <h3 className="text-xl font-semibold text-gold-gradient mb-4">Pricing Summary</h3>

                    {/* Base service pricing */}
                    {selectedPricingTier !== null && (
                      <div className="space-y-3 mb-4">
                        <div className="flex justify-between items-center text-sm">
                          <span>Base service ({service.pricingTiers?.[selectedPricingTier]?.name}):</span>
                          <span className="text-gold-gradient">
                            {(() => {
                              if (selectedSubscription) {
                                // Show per-flight price for subscriptions
                                return `${formatPrice(totalPrice / flightQuantity)} x ${flightQuantity}`;
                              } else {
                                // Show regular tier price for one-time
                                const tier = service.pricingTiers?.[selectedPricingTier];
                                return tier?.price 
                                  ? formatPrice(tier.price * 100)
                                  : tier?.minPrice 
                                    ? formatPrice(tier.minPrice * 100)
                                    : formatPrice(service.price);
                              }
                            })()}
                          </span>
                        </div>
                      </div>
                    )}

                    {/* Subscription pricing breakdown */}
                    {selectedPricingTier !== null && selectedSubscription && (
                      <div className="mb-3 p-3 bg-offwhite/5 rounded-lg">
                        <div className="text-sm text-offwhite/70 mb-2">Subscription Pricing:</div>
                        <div className="flex justify-between items-center text-sm">
                          <span>Price per flight:</span>
                          <span className="text-gold-gradient">
                            {(() => {
                              if (!selectedSubscription || selectedPricingTier === null || !service) return formatPrice(0);

                              const currentTierPrice = service.pricingTiers && service.pricingTiers[selectedPricingTier] 
                                ? (() => {
                                    const tier = service.pricingTiers[selectedPricingTier];
                                    return tier.price ? tier.price * 100 : (tier.minPrice ? tier.minPrice * 100 : service.price);
                                  })()
                                : service.price;

                              let pricePerFlight = 0;
                              if (selectedSubscription === 'weekly') {
                                pricePerFlight = (service as any).weeklyPriceType === "percentage" 
                                  ? Math.round(currentTierPrice * ((service as any).weeklyPercentage / 100))
                                  : ((service as any).weeklyPrice || 0) * 100;
                              } else if (selectedSubscription === 'biWeekly') {
                                pricePerFlight = (service as any).biWeeklyPriceType === "percentage" 
                                  ? Math.round(currentTierPrice * ((service as any).biWeeklyPercentage / 100))
                                  : ((service as any).biWeeklyPrice || 0) * 100;
                              } else if (selectedSubscription === 'monthly') {
                                pricePerFlight = (service as any).monthlyPriceType === "percentage" 
                                  ? Math.round(currentTierPrice * ((service as any).monthlyPercentage / 100))
                                  : ((service as any).monthlyPrice || 0) * 100;
                              }

                              return formatPrice(pricePerFlight);
                            })()}
                          </span>
                        </div>
                        <div className="flex justify-between items-center text-sm">
                          <span>Number of flights:</span>
                          <span className="text-gold-gradient">{flightQuantity}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm">
                          <span>Frequency:</span>
                          <span className="text-gold-gradient capitalize">{selectedSubscription}</span>
                        </div>
                        <div className="flex justify-between items-center text-sm">
                          <span>Estimated End Date:</span>
                          <span className="text-gold-gradient">
                            {(() => {
                              if (!selectedSubscription || !flightQuantity) return 'N/A';

                              const currentDate = new Date();
                              let daysPerFlight = 0;

                              if (selectedSubscription === 'weekly') {
                                daysPerFlight = 7;
                              } else if (selectedSubscription === 'biWeekly') {
                                daysPerFlight = 14;
                              } else if (selectedSubscription === 'monthly') {
                                daysPerFlight = 30;
                              }

                              // First flight within 5 days, then calculate remaining flights
                              const firstFlightDays = 5;
                              const totalDays = firstFlightDays + (flightQuantity - 1) * daysPerFlight;

                              // Calculate range (±3 days for estimation)
                              const earliestEnd = new Date(currentDate.getTime() + (totalDays - 3) * 24 * 60 * 60 * 1000);
                              const latestEnd = new Date(currentDate.getTime() + (totalDays + 3) * 24 * 60 * 60 * 1000);

                              const formatDate = (date: Date) => date.toLocaleDateString('en-US', { 
                                month: 'short', 
                                day: 'numeric'
                              });

                              return `${formatDate(earliestEnd)} - ${formatDate(latestEnd)}`;
                            })()}
                          </span>
                        </div>
                      </div>
                    )}

                    {/* Bundle services breakdown */}
                    {bundlePricing.bundleServices.length > 0 && (
                      <div className="space-y-2 mb-4">
                        {bundlePricing.bundleServices.map((bundle, index) => (
                          <div key={index} className="flex justify-between items-center text-sm">
                            <span>{bundle.service.name}:</span>
                            <span className="text-gold-gradient">
                              {formatPrice(bundle.bundlePrice)}
                              {bundle.discount > 0 && (
                                <span className="text-green-400 ml-2">(-{formatPrice(bundle.discount)})</span>
                              )}
                            </span>
                          </div>
                        ))}
                      </div>
                    )}

                    {/* Add-ons breakdown */}
                    {serviceAddons && selectedAddOns.length > 0 && (
                      <div className="space-y-2 mb-4">
                        {serviceAddons
                          .filter(serviceAddon => selectedAddOns.includes(serviceAddon.addon.id))
                          .map((serviceAddon) => {
                            const addon = serviceAddon.addon;
                            const currentTierPrice = getCurrentPrice();
                            const addonPrice = addon.pricingType === 'percentage' 
                              ? Math.round(currentTierPrice * (addon.percentage / 100))
                              : addon.price;

                            return (
                              <div key={addon.id} className="flex justify-between items-center text-sm">
                                <span>{addon.name}:</span>
                                <span className="text-gold-gradient">
                                  +{formatPrice(addonPrice)}
                                  {addon.pricingType === 'percentage' && (
                                    <span className="text-offwhite/60 ml-2">({addon.percentage}%)</span>
                                  )}
                                </span>
                              </div>
                            );
                          })}
                      </div>
                    )}

                    <div className="flex justify-between items-center">
                      <span className="text-lg font-medium text-gold-gradient">Total:</span>
                      <span className="text-xl font-bold text-gold-gradient">
                        {formatPrice(totalPrice)}
                      </span>
                    </div>
                  </CardContent>
                </Card>
              )}

              {/* Action Buttons */}
              <div className="space-y-4">
                {isQuoteOnlyService ? (
                  <Button className="w-full bg-gold hover:bg-gold-light text-black font-semibold py-3 px-6 rounded-lg transition-colors">
                    Request Quote
                  </Button>
                ) : (
                  <>
                    {selectedPricingTier !== null ? (
                      <Button 
                        onClick={handleBookNow}
                        className="w-full bg-gold hover:bg-gold-light text-black font-semibold py-3 px-6 rounded-lg transition-colors"
                      >
                        Book Now - {formatPrice(totalPrice)}
                      </Button>
                    ) : (
                      <Button 
                        disabled
                        className="w-full bg-offwhite/20 text-offwhite/50 font-semibold py-3 px-6 rounded-lg cursor-not-allowed"
                      >
                        Select a Package to Continue
                      </Button>
                    )}

                    <Button 
                      variant="outline" 
                      className="w-full border-gold text-gold hover:bg-gold hover:text-black transition-colors"
                    >
                      Get Custom Quote
                    </Button>
                  </>
                )}
              </div>
            </div>
          </div>

          {/* Before/After Section */}
          {displayBeforeAfterImages.length > 0 && (
            <div className="mt-16">
              <h2 className="text-3xl font-bold text-gold-gradient text-center mb-12">Before & After</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {displayBeforeAfterImages.map((item, index) => (
                  <Card key={item.id || index} className="bg-offwhite/5 border-gold/20 overflow-hidden">
                    <CardContent className="p-6">
                      <h3 className="text-xl font-semibold text-gold-gradient mb-4">{item.title}</h3>
                      <p className="text-offwhite/80 mb-6">{item.description}</p>

                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div>
                          <h4 className="text-sm font-medium text-offwhite/70 mb-2">Before</h4>
                          <img 
                            src={item.beforeImageUrl} 
                            alt={`${item.title} - Before`}
                            className="w-full h-48 object-cover rounded-lg"
                          />
                        </div>
                        <div>
                          <h4 className="text-sm font-medium text-offwhite/70 mb-2">After</h4>
                          <img 
                            src={item.afterImageUrl} 
                            alt={`${item.title} - After`}
                            className="w-full h-48 object-cover rounded-lg"
                          />
                        </div>
                      </div>
                    </CardContent>
                  </Card>
                ))}
              </div>
            </div>
          )}

          {/* Related Services */}
          {services && services.length > 1 && (
            <div className="mt-16">
              <h2 className="text-3xl font-bold text-gold-gradient text-center mb-12">Related Services</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {services
                  .filter(s => s.id !== service.id)
                  .slice(0, 3)
                  .map((relatedService) => (
                    <Link key={relatedService.id} href={`/services/${relatedService.id}`}>
                      <Card className="bg-offwhite/5 border-gold/20 hover:border-gold/50 transition-colors h-full cursor-pointer">
                        <CardContent className="p-6">
                          <img 
                            src={relatedService.imageUrl} 
                            alt={relatedService.name}
                            className="w-full h-48 object-cover rounded-lg mb-4"
                          />
                          <h3 className="text-xl font-semibold text-gold-gradient mb-2">{relatedService.name}</h3>
                          <p className="text-offwhite/80 mb-4 line-clamp-3">{relatedService.description}</p>
                          <div className="text-lg font-bold text-gold-gradient">
                            {formatPrice(relatedService.price)}
                          </div>
                        </CardContent>
                      </Card>
                    </Link>
                  ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

