// This script will find and fix the tooltip sections to only show tooltipDescription and not addonDescription
// We need to find all instances of the tooltip pattern and replace them

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const filePath = path.join(__dirname, 'service-page.tsx');
let content = fs.readFileSync(filePath, 'utf8');

// Replace pattern for tooltips
const originalPattern = /(\s+<TooltipContent.*?>\s+<div.*?>\s+\{addon\.tooltipDescription\}\s+<\/div>)(\s+\{addon\.addonDescription && \(\s+<div.*?>\s+\{addon\.addonDescription\}\s+<\/div>\s+\)\})/g;
const replacement = '$1';

content = content.replace(originalPattern, replacement);

fs.writeFileSync(filePath, content);
console.log('Tooltip patterns fixed successfully');

