                        </Pie>
                        <Tooltip 
                          formatter={(value) => [`${value} Tasks`, 'Count']}
                          contentStyle={{ backgroundColor: '#0b111f', borderColor: '#b8a15c50', borderRadius: '4px' }}
                          itemStyle={{ color: '#ffffff' }}
                        />
                        <Legend 
                          layout="horizontal" 
                          verticalAlign="bottom" 
                          align="center"
                          wrapperStyle={{ color: '#ffffff' }}
