                    </ResponsiveContainer>
                  </div>
                </CardContent>
              </Card>

              {/* Milestone Progress */}
              <Card className="bg-[#132642] border-gold-dark/30">
                <CardHeader className="pb-2">
                  <CardTitle className="text-md font-medium text-offwhite">Milestone Progress</CardTitle>
