import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";
import { 
  TrendingUp, 
  TrendingDown, 
  Calendar, 
  DollarSign, 
  Brain, 
  CheckCircle, 
  AlertCircle,
  Clock,
  Map,
  Percent,
  Download,
  Search,
  Edit
} from "lucide-react";

interface PricingSuggestion {
  id: number;
  serviceId: number;
  currentPrice: string;
  suggestedPrice: string;
  confidence: string;
  reasoning: string;
  marketFactors: {
    competition: number;
    demand: number;
    seasonality: number;
    location: string;
  };
  isApplied: boolean;
  createdAt: string;
}

interface Service {
  id: number;
  name: string;
  price: string;
  description: string;
}

interface CompetitorPrice {
  competitor: string;
  price: number;
  service: string;
  location: string;
}

interface ServiceCompetitorAnalysis {
  serviceId: number;
  serviceName: string;
  currentPrice: number;
  competitors: CompetitorPrice[];
  avgPrice: number;
  lowPrice: number;
  highPrice: number;
  suggestedPrice: number;
}

export default function PricingOptimization() {
  const { toast } = useToast();
  const queryClient = useQueryClient();
  const [selectedService, setSelectedService] = useState<Service | null>(null);
  const [manualPrice, setManualPrice] = useState("");
  const [isApplyingPrice, setIsApplyingPrice] = useState(false);
  const [competitorAnalysis, setCompetitorAnalysis] = useState<ServiceCompetitorAnalysis[]>([]);
  const [editingPrice, setEditingPrice] = useState<{ serviceId: number; price: string } | null>(null);

  const { data: services = [] } = useQuery<Service[]>({
    queryKey: ["/api/services"]
  });

  const { data: suggestions = [], isLoading: suggestionsLoading } = useQuery<PricingSuggestion[]>({
    queryKey: ["/api/pricing/suggestions"]
  });

  const { data: expeditedSlots = [] } = useQuery({
    queryKey: ["/api/pricing/expedited-slots"]
  });

  const generateSuggestionsMutation = useMutation({
    mutationFn: (serviceId?: number) => 
      apiRequest("/api/pricing/generate-suggestions", "POST", { serviceId }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pricing/suggestions"] });
      toast({
        title: "AI Analysis Complete",
        description: "New pricing suggestions have been generated"
      });
    },
    onError: () => {
      toast({
        title: "Analysis Failed",
        description: "Unable to generate pricing suggestions",
        variant: "destructive"
      });
    }
  });

  const applyPricingMutation = useMutation({
    mutationFn: ({ suggestionId, newPrice }: { suggestionId: number; newPrice: string }) =>
      apiRequest(`/api/pricing/apply-suggestion/${suggestionId}`, "POST", { newPrice }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/services"] });
      queryClient.invalidateQueries({ queryKey: ["/api/pricing/suggestions"] });
      toast({
        title: "Price Updated",
        description: "Service pricing has been updated successfully"
      });
      setManualPrice("");
    },
    onError: () => {
      toast({
        title: "Update Failed",
        description: "Unable to update service pricing",
        variant: "destructive"
      });
    }
  });

  const blockWeekendMutation = useMutation({
    mutationFn: (weekStartDate: string) =>
      apiRequest("/api/pricing/expedited-slots/block", "POST", {
        weekStartDate,
        blockReason: "Weekend blocked for expedited services"
      }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/pricing/expedited-slots"] });
      toast({
        title: "Weekend Blocked",
        description: "Expedited services blocked for selected weekend"
      });
    }
  });

  const importCurrentPricesMutation = useMutation({
    mutationFn: () => apiRequest("/api/pricing/import-current", "POST", {}) as Promise<Service[]>,
    onSuccess: (data: Service[]) => {
      setCompetitorAnalysis(data.map((service) => ({
        serviceId: service.id,
        serviceName: service.name,
        currentPrice: parseFloat(service.price),
        competitors: [],
        avgPrice: 0,
        lowPrice: 0,
        highPrice: 0,
        suggestedPrice: parseFloat(service.price)
      })));
      toast({
        title: "Prices Imported",
        description: `Imported prices for ${data.length} services`
      });
    }
  });

  const fetchCompetitorPricesMutation = useMutation({
    mutationFn: () => apiRequest("/api/pricing/competitor-analysis", "POST", { zipCode: "84780" }) as Promise<ServiceCompetitorAnalysis[]>,
    onSuccess: (data: ServiceCompetitorAnalysis[]) => {
      setCompetitorAnalysis(data);
      toast({
        title: "Competitor Analysis Complete",
        description: `Fetched competitor prices for ${data.length} services`
      });
    },
    onError: () => {
      toast({
        title: "Analysis Failed",
        description: "Unable to fetch competitor prices",
        variant: "destructive"
      });
    }
  });

  const updateServicePriceMutation = useMutation({
    mutationFn: ({ serviceId, newPrice }: { serviceId: number; newPrice: string }) =>
      apiRequest(`/api/services/${serviceId}`, "PATCH", { price: newPrice }),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/services"] });
      setEditingPrice(null);
      toast({
        title: "Price Updated",
        description: "Service price updated successfully"
      });
    }
  });

  const getConfidenceColor = (confidence: number) => {
    if (confidence >= 0.8) return "bg-green-100 text-green-800";
    if (confidence >= 0.6) return "bg-yellow-100 text-yellow-800";
    return "bg-red-100 text-red-800";
  };

  const formatCurrency = (amount: string) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD'
    }).format(parseFloat(amount));
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold">Pricing Optimization</h1>
          <p className="text-muted-foreground">AI-powered pricing insights and expedited scheduling</p>
        </div>
        <Button 
          onClick={() => generateSuggestionsMutation.mutate()}
          disabled={generateSuggestionsMutation.isPending}
        >
          <Brain className="w-4 h-4 mr-2" />
          Generate AI Suggestions
        </Button>
      </div>

      <Tabs defaultValue="suggestions" className="space-y-6">
        <TabsList>
          <TabsTrigger value="suggestions">AI Pricing Suggestions</TabsTrigger>
          <TabsTrigger value="competitor">Competitor Analysis</TabsTrigger>
          <TabsTrigger value="expedited">Expedited Scheduling</TabsTrigger>
          <TabsTrigger value="zones">Geographic Pricing</TabsTrigger>
          <TabsTrigger value="bulk">Bulk Discounts</TabsTrigger>
        </TabsList>

        <TabsContent value="suggestions" className="space-y-6">

          <div className="grid gap-6">
            {suggestionsLoading ? (
              <div className="text-center py-8">
                <div className="animate-spin w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full mx-auto"></div>
                <p className="mt-2 text-muted-foreground">Loading AI suggestions...</p>
              </div>
            ) : suggestions.length === 0 ? (
              <Card>
                <CardContent className="text-center py-8">
                  <Brain className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                  <h3 className="text-lg font-semibold mb-2">No Suggestions Available</h3>
                  <p className="text-muted-foreground mb-4">
                    Generate AI-powered pricing suggestions to optimize your service rates
                  </p>
                  <Button onClick={() => generateSuggestionsMutation.mutate()}>
                    Generate Suggestions
                  </Button>
                </CardContent>
              </Card>
            ) : (
              suggestions.map(suggestion => {
                const service = services.find(s => s.id === suggestion.serviceId);
                const currentPrice = parseFloat(suggestion.currentPrice);
                const suggestedPrice = parseFloat(suggestion.suggestedPrice);
                const priceChange = ((suggestedPrice - currentPrice) / currentPrice) * 100;
                const confidence = parseFloat(suggestion.confidence);

                return (
                  <Card key={suggestion.id} className="relative">
                    {suggestion.isApplied && (
                      <div className="absolute top-4 right-4">
                        <Badge variant="secondary" className="bg-green-100 text-green-800">
                          <CheckCircle className="w-3 h-3 mr-1" />
                          Applied
                        </Badge>
                      </div>
                    )}

                    <CardHeader>
                      <div className="flex justify-between items-start">
                        <div>
                          <CardTitle className="flex items-center gap-2">
                            {service?.name || `Service ${suggestion.serviceId}`}
                            <Badge className={getConfidenceColor(confidence)}>
                              {Math.round(confidence * 100)}% confidence
                            </Badge>
                          </CardTitle>
                          <CardDescription>
                            AI analysis completed {new Date(suggestion.createdAt).toLocaleDateString()}
                          </CardDescription>
                        </div>
                      </div>
                    </CardHeader>

                    <CardContent className="space-y-4">
                      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                        <div className="text-center p-4 bg-gray-50 rounded-lg">
                          <DollarSign className="w-6 h-6 text-gray-600 mx-auto mb-2" />
                          <div className="text-sm text-muted-foreground">Current Price</div>
                          <div className="text-xl font-semibold">{formatCurrency(suggestion.currentPrice)}</div>
                        </div>

                        <div className="text-center p-4 bg-blue-50 rounded-lg">
                          <Brain className="w-6 h-6 text-blue-600 mx-auto mb-2" />
                          <div className="text-sm text-muted-foreground">AI Suggested</div>
                          <div className="text-xl font-semibold text-blue-600">
                            {formatCurrency(suggestion.suggestedPrice)}
                          </div>
                        </div>

                        <div className="text-center p-4 bg-green-50 rounded-lg">
                          {priceChange > 0 ? (
                            <TrendingUp className="w-6 h-6 text-green-600 mx-auto mb-2" />
                          ) : (
                            <TrendingDown className="w-6 h-6 text-red-600 mx-auto mb-2" />
                          )}
                          <div className="text-sm text-muted-foreground">Change</div>
                          <div className={`text-xl font-semibold ${priceChange > 0 ? 'text-green-600' : 'text-red-600'}`}>
                            {priceChange > 0 ? '+' : ''}{priceChange.toFixed(1)}%
                          </div>
                        </div>
                      </div>

                      <div className="space-y-3">
                        <div>
                          <h4 className="font-semibold mb-2">AI Reasoning</h4>
                          <p className="text-sm text-muted-foreground">{suggestion.reasoning}</p>
                        </div>

                        <div>
                          <h4 className="font-semibold mb-2">Market Factors</h4>
                          <div className="grid grid-cols-2 md:grid-cols-4 gap-2 text-sm">
                            <div className="flex items-center gap-1">
                              <Percent className="w-3 h-3" />
                              Competition: {Math.round(suggestion.marketFactors.competition * 100)}%
                            </div>
                            <div className="flex items-center gap-1">
                              <TrendingUp className="w-3 h-3" />
                              Demand: {Math.round(suggestion.marketFactors.demand * 100)}%
                            </div>
                            <div className="flex items-center gap-1">
                              <Calendar className="w-3 h-3" />
                              Seasonality: {Math.round(suggestion.marketFactors.seasonality * 100)}%
                            </div>
                            <div className="flex items-center gap-1">
                              <Map className="w-3 h-3" />
                              {suggestion.marketFactors.location}
                            </div>
                          </div>
                        </div>
                      </div>

                      {!suggestion.isApplied && (
                        <div className="border-t pt-4">
                          <div className="flex gap-4 items-end">
                            <div className="flex-1">
                              <Label htmlFor={`price-${suggestion.id}`}>
                                Set Custom Price (or use AI suggestion)
                              </Label>
                              <Input
                                id={`price-${suggestion.id}`}
                                type="number"
                                step="0.01"
                                placeholder={suggestion.suggestedPrice}
                                value={manualPrice}
                                onChange={(e) => setManualPrice(e.target.value)}
                              />
                            </div>
                            <Button
                              onClick={() => applyPricingMutation.mutate({
                                suggestionId: suggestion.id,
                                newPrice: manualPrice || suggestion.suggestedPrice
                              })}
                              disabled={applyPricingMutation.isPending}
                            >
                              Apply Pricing
                            </Button>
                            <Button
                              variant="outline"
                              onClick={() => applyPricingMutation.mutate({
                                suggestionId: suggestion.id,
                                newPrice: suggestion.suggestedPrice
                              })}
                              disabled={applyPricingMutation.isPending}
                            >
                              Use AI Price
                            </Button>
                          </div>
                        </div>
                      )}
                    </CardContent>
                  </Card>
                );
              })
            )}
          </div>
        </TabsContent>

        <TabsContent value="competitor" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Search className="w-5 h-5" />
                Competitor Price Analysis
              </CardTitle>
              <CardDescription>
                Import your current prices and analyze competitor pricing within 45 miles of 84780
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="flex gap-4 mb-6">
                <Button 
                  onClick={() => importCurrentPricesMutation.mutate()}
                  disabled={importCurrentPricesMutation.isPending}
                  data-testid="button-import-prices"
                >
                  <Download className="w-4 h-4 mr-2" />
                  Import Current Prices
                </Button>
                <Button 
                  onClick={() => fetchCompetitorPricesMutation.mutate()}
                  disabled={fetchCompetitorPricesMutation.isPending || competitorAnalysis.length === 0}
                  data-testid="button-fetch-competitors"
                >
                  <Search className="w-4 h-4 mr-2" />
                  Fetch Competitor Prices
                </Button>
              </div>

              {fetchCompetitorPricesMutation.isPending && (
                <div className="text-center py-8">
                  <div className="animate-spin w-8 h-8 border-4 border-blue-500 border-t-transparent rounded-full mx-auto"></div>
                  <p className="mt-2 text-muted-foreground">Analyzing competitor prices...</p>
                </div>
              )}

              {competitorAnalysis.length > 0 && (
                <div className="border rounded-lg overflow-hidden">
                  <Table>
                    <TableHeader>
                      <TableRow>
                        <TableHead>Service</TableHead>
                        <TableHead>Your Price</TableHead>
                        <TableHead>Low Price</TableHead>
                        <TableHead>Average Price</TableHead>
                        <TableHead>High Price</TableHead>
                        <TableHead>Suggested Price</TableHead>
                        <TableHead>Actions</TableHead>
                      </TableRow>
                    </TableHeader>
                    <TableBody>
                      {competitorAnalysis.map((analysis) => (
                        <TableRow key={analysis.serviceId}>
                          <TableCell className="font-medium">{analysis.serviceName}</TableCell>
                          <TableCell>
                            {editingPrice?.serviceId === analysis.serviceId ? (
                              <Input
                                type="number"
                                step="0.01"
                                value={editingPrice.price}
                                onChange={(e) => setEditingPrice({ ...editingPrice, price: e.target.value })}
                                className="w-24"
                                data-testid={`input-price-${analysis.serviceId}`}
                              />
                            ) : (
                              formatCurrency(analysis.currentPrice.toString())
                            )}
                          </TableCell>
                          <TableCell className="text-green-600 font-semibold">
                            {analysis.lowPrice > 0 ? formatCurrency(analysis.lowPrice.toString()) : '-'}
                          </TableCell>
                          <TableCell className="font-semibold">
                            {analysis.avgPrice > 0 ? formatCurrency(analysis.avgPrice.toString()) : '-'}
                          </TableCell>
                          <TableCell className="text-red-600 font-semibold">
                            {analysis.highPrice > 0 ? formatCurrency(analysis.highPrice.toString()) : '-'}
                          </TableCell>
                          <TableCell className="text-blue-600 font-semibold">
                            {analysis.suggestedPrice > 0 ? formatCurrency(analysis.suggestedPrice.toString()) : '-'}
                          </TableCell>
                          <TableCell>
                            {editingPrice?.serviceId === analysis.serviceId ? (
                              <div className="flex gap-2">
                                <Button
                                  size="sm"
                                  onClick={() => updateServicePriceMutation.mutate({
                                    serviceId: analysis.serviceId,
                                    newPrice: editingPrice.price
                                  })}
                                  data-testid={`button-save-${analysis.serviceId}`}
                                >
                                  Save
                                </Button>
                                <Button
                                  size="sm"
                                  variant="outline"
                                  onClick={() => setEditingPrice(null)}
                                  data-testid={`button-cancel-${analysis.serviceId}`}
                                >
                                  Cancel
                                </Button>
                              </div>
                            ) : (
                              <Button
                                size="sm"
                                variant="outline"
                                onClick={() => setEditingPrice({
                                  serviceId: analysis.serviceId,
                                  price: analysis.currentPrice.toString()
                                })}
                                data-testid={`button-edit-${analysis.serviceId}`}
                              >
                                <Edit className="w-4 h-4 mr-1" />
                                Edit
                              </Button>
                            )}
                          </TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>

                  {competitorAnalysis.some(a => a.competitors.length > 0) && (
                    <div className="p-4 bg-gray-50 border-t">
                      <h4 className="font-semibold mb-3">Competitor Details</h4>
                      <div className="grid gap-4">
                        {competitorAnalysis.filter(a => a.competitors.length > 0).map((analysis) => (
                          <div key={`details-${analysis.serviceId}`} className="space-y-2">
                            <h5 className="font-medium text-sm">{analysis.serviceName}</h5>
                            <div className="grid grid-cols-4 gap-2 text-sm">
                              {analysis.competitors.map((comp, idx) => (
                                <div key={idx} className="p-2 bg-white rounded border">
                                  <div className="font-medium">{comp.competitor}</div>
                                  <div className="text-xs text-muted-foreground">{comp.location}</div>
                                  <div className="font-semibold text-blue-600">{formatCurrency(comp.price.toString())}</div>
                                </div>
                              ))}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              )}

              {competitorAnalysis.length === 0 && !fetchCompetitorPricesMutation.isPending && (
                <div className="text-center py-8 text-muted-foreground">
                  <Search className="w-12 h-12 mx-auto mb-4 opacity-50" />
                  <p>Click "Import Current Prices" to get started</p>
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="expedited" className="space-y-6">
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <Clock className="w-5 h-5" />
                Expedited Service Scheduling
              </CardTitle>
              <CardDescription>
                Manage expedited job scheduling with weekend blocking capability. 
                Only one expedited job can be scheduled at a time.
              </CardDescription>
            </CardHeader>
            <CardContent>
              <div className="space-y-4">
                <div className="flex gap-4 items-center">
                  <Label>Block Weekend Starting:</Label>
                  <Input
                    type="date"
                    onChange={(e) => {
                      if (e.target.value) {
                        const date = new Date(e.target.value);
                        // Ensure it's a Saturday (weekend start)
                        const saturday = new Date(date);
                        saturday.setDate(date.getDate() - date.getDay() + 6);
                        blockWeekendMutation.mutate(saturday.toISOString().split('T')[0]);
                      }
                    }}
                  />
                  <Button variant="outline" disabled={blockWeekendMutation.isPending}>
                    Block Weekend
                  </Button>
                </div>

                <div className="grid gap-2">
                  <h4 className="font-semibold">Current Expedited Slots</h4>
                  {expeditedSlots.length === 0 ? (
                    <p className="text-muted-foreground">No expedited slots scheduled</p>
                  ) : (
                    expeditedSlots.map((slot: any) => (
                      <div key={slot.id} className="flex justify-between items-center p-3 border rounded">
                        <div>
                          <span className="font-medium">
                            Week of {new Date(slot.weekStartDate).toLocaleDateString()}
                          </span>
                          {slot.isBlocked && (
                            <Badge variant="destructive" className="ml-2">Blocked</Badge>
                          )}
                          {slot.isBooked && (
                            <Badge variant="secondary" className="ml-2">Booked</Badge>
                          )}
                        </div>
                        {slot.blockReason && (
                          <span className="text-sm text-muted-foreground">{slot.blockReason}</span>
                        )}
                      </div>
                    ))
                  )}
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="zones">
          <Card>
            <CardHeader>
              <CardTitle>Geographic Pricing Zones</CardTitle>
              <CardDescription>Configure location-based pricing adjustments</CardDescription>
            </CardHeader>
            <CardContent>
              <p className="text-muted-foreground">Geographic pricing configuration coming soon...</p>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="bulk">
          <Card>
            <CardHeader>
              <CardTitle>Bulk Discount Management</CardTitle>
              <CardDescription>Set up volume-based pricing discounts</CardDescription>
            </CardHeader>
            <CardContent>
              <p className="text-muted-foreground">Bulk discount configuration coming soon...</p>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}
